/* techniques q11 (188 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["techniques"]={"updatedAt":"2026-07-14","count":188,"techniques":[{"id":"kiem-tran-chin-thanh-phi-kiem","name":"Kiếm trận chín thanh phi kiếm","cn":null,"loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":null,"soHuu":["Lý Thiến Mai"],"blurb":"Trận pháp do Lý Thiến Mai bố trí bằng chín thanh phi kiếm đâm bốn phía, tự động chém giết mãnh thú bảo vệ sơn cốc.","detail":"Lý Thiến Mai dùng chín thanh phi kiếm đâm về bốn phía hợp thành kiếm trận bảo vệ sơn cốc nơi tượng đá Vương Lâm đặt, khi nàng phải rời đi lấy hồn huyết từ Yêu Tông. Trận pháp này chính là trận đã giúp nàng chém giết vô số mãnh thú trên chiến trường trước đó. Khi bà lão bạch y (sư tỷ Lý Thiến Mai) tới sơn cốc, bà dùng ngọc giản phát ra khí tức nhu hòa hóa giải kiếm trận này mới vào được bên trong.","nguon":["@c1214"]},{"id":"ngan-van-dao-kiem-khi","name":"Ngàn vạn đạo kiếm khí","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Vương Lâm"],"blurb":"Thần thông kiếm khí cực mạnh, từ ngón trỏ bộc phát hàng ngàn vạn đạo kiếm khí hóa thành bão kiếm. Uy lực khiến ngay cả Thủy Đạo Tử cũng phải e dè.","detail":"Vương Lâm thi triển lần thứ hai tại Vô Cực Tông: từ ngón trỏ bộc phát mười vạn, trăm vạn, năm trăm vạn rồi ngàn vạn đạo kiếm khí hóa thành cơn bão kiếm. Đánh hắc y lão giả (Thiên Nhân Đệ Nhất Suy) phun máu, tông chủ Vô Cực Tử bị đẩy lui không thể tới gần nửa bước.","congNang":["Bộc phát kiếm khí từ ngón trỏ, số lượng tăng dần tới ngàn vạn đạo, hóa bão kiếm quét sạch đối thủ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1217","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1217","loai":"thi triển","importance":"normal","giaiDoan":"Lần thi triển thứ hai","text":"Vương Lâm thi triển lần thứ hai tại Vô Cực Tông, đánh hắc y lão giả phun máu và đẩy lui tông chủ Vô Cực Tử. Uy lực được xác nhận khiến Thủy Đạo Tử cũng phải e dè.","anchor":"Ngàn vạn đạo kiếm khí này đến ngay cả Thủy Đạo Tử cũng phải e dè uy lực tuyệt luân của nó"}]},"nguon":["@c1217"]},{"id":"khong-che-loi-dinh","name":"Khống chế lôi đình","cn":"","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Vương Lâm"],"blurb":"Thần thông liên quan Cổ Thần lực, chỉ cần một chữ «Lôi» đã giành quyền khống chế lôi đình trong thiên địa, khiến lôi cầu đối phương quay ngược tấn công chủ cũ.","detail":"Vương Lâm dùng một chữ «Lôi» giành quyền khống chế mười chín lôi cầu của hắc y lão giả Vô Cực Tông, khiến chúng quay ngược tấn công chủ nhân cũ. Dường như hắn mới chính là chủ nhân chính thức của lôi đình trong thiên địa.","congNang":["Giành quyền khống chế lôi đình người khác chỉ bằng một chữ «Lôi», lôi cầu quay ngược tấn công chủ cũ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1217","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1217","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm dùng một chữ «Lôi» giành quyền khống chế mười chín lôi cầu của hắc y lão giả, khiến lôi đình quay ngược tấn công chủ cũ.","anchor":"Dường như Vương Lâm mới chính là chủ nhân chính thức của chúng, là chủ nhân"}]},"nguon":["@c1217"]},{"id":"hai-luong-khi-tuc-den-trang-nai-con","name":"Hai luồng khí tức đen trắng hình nai con","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Vương Lâm"],"blurb":"Từ ngón trỏ Vương Lâm biến ảo thành hai con nai con đen trắng, xuất hiện phối hợp cùng ngàn vạn đạo kiếm khí tấn công.","detail":"Hai luồng khí tức đen trắng từ ngón trỏ biến ảo thành hình dạng hai con nai con, xuất hiện cùng lúc với ngàn vạn đạo kiếm khí khi Vương Lâm giao chiến tại Vô Cực Tông.","congNang":["Tấn công phối hợp cùng kiếm khí, biến ảo thành hai nai con đen trắng"],"nguon":["@c1217"]},{"id":"de-nhat-dao-thuat-dao-canh","name":"Đệ nhất đạo thuật (Đạo cảnh)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo thuật Vương Lâm cảm ngộ được trong Đạo cảnh, chưa mở phong ấn cũng đủ bảo hộ toàn thân chiến đấu ngang tu sĩ Thiên Nhân Đệ Nhất Suy.","detail":"Vương Lâm dùng đạo thuật này bảo vệ toàn thân, kết hợp nửa bước Toái Niết mà chưa cần mở phong ấn cũng đủ đối đầu Thiên Nhân Đệ Nhất Suy.","congNang":["Bảo hộ toàn thân, nâng chiến lực ngang Thiên Nhân Đệ Nhất Suy khi chưa mở phong ấn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1219","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1219","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm tự đánh giá","text":"Vương Lâm nhận định dùng đệ nhất đạo thuật cảm ngộ trong Đạo cảnh bảo vệ toàn thân, chưa mở phong ấn cũng đủ chiến Thiên Nhân Đệ Nhất Suy.","anchor":"chỉ lấy đệ nhất đạo thuật cảm ngộ được trong Đạo cảnh để bảo vệ toàn thân, cũng đủ để chiến tranh tu sĩ Thiên Nhân Đệ Nhất Suy"}]},"nguon":["@c1219"]},{"id":"van-dao-te-bao","name":"Vạn Đạo Tề Bạo","cn":"万道齐爆","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Lão già (chiến trường Yêu Tông)"],"blurb":"Thần thông tự sáng tạo của lão già chiến trường Yêu Tông, hấp thụ thiên địa nguyên lực hóa thành hơn vạn kim đan bao quanh thân rồi cho nổ tung đồng loạt.","detail":"Hấp thụ thiên địa nguyên lực biến ảo thành hơn vạn viên kim đan bao quanh thân thể, sau đó cho nổ tung đồng loạt tạo sức mạnh hủy diệt. Là thần thông tự nghĩ ra, được lão già sử dụng chống Cửu U Long.","congNang":["Hóa thiên địa nguyên lực thành vạn kim đan rồi cho nổ hàng loạt tạo sức công kích hủy diệt"],"nguoiTu":[{"ten":"Lão già (chiến trường Yêu Tông)","tuChuong":"@c1220","tangDatToi":"","trangThai":"dang-tu"}],"nguonGoc":"Tự sáng tạo","tabs":{"tienTrinh":[{"chuong":"@c1220","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Lão già thi triển chống Cửu U Long tại chiến trường Yêu Tông, hấp thụ thiên địa nguyên lực hóa vạn kim đan cho nổ tung nhưng không hạ được đầu lâu nghìn trượng.","anchor":"hấp thụ thiên địa nguyên lực hóa thành kim đan"}]},"nguon":["@c1220"]},{"id":"yeu-tong-dai-tran","name":"Yêu Tông đại trận","cn":"妖宗大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Yêu Tông","soHuu":["Yêu Tông"],"blurb":"Trận pháp phòng thủ trên chiến trường Yêu Tông, cần mấy nghìn tu sĩ hiến tế sức sống để kích hoạt, đóng khe chiến trường ép chết mãnh thú bị kẹt.","detail":"Khi kích hoạt, khe chiến trường đóng lại tạm thời, ép chết mãnh thú kẹt giữa. Chỉ duy trì thời gian ngắn rồi khe lại mở. Cần mấy nghìn tu sĩ đồng loạt hiến tế sức sống.","congNang":["Đóng khe chiến trường phong bế tạm thời, ép chết mãnh thú bị kẹt"],"nguonGoc":"Yêu Tông","tabs":{"tienTrinh":[{"chuong":"@c1220","loai":"thi triển","importance":"normal","giaiDoan":"Kích hoạt chống Cửu U Long","text":"Mấy nghìn tu sĩ đồng loạt hiến tế sức sống kích hoạt đại trận theo lệnh lão già, khe chiến trường đóng lại ép chết mãnh thú, Cửu U Long thu đầu tránh.","anchor":"Lấy sức sống để hiến tế, gọi ra Yêu Tông đại trận"}]},"nguon":["@c1220"]},{"id":"dai-tran-sau-tu-chan-tinh","name":"Đại trận sáu tu chân tinh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Yêu Tông","soHuu":["Tông chủ đời đầu Yêu Tông"],"blurb":"Trận pháp do tông chủ đời đầu Yêu Tông bày ra, lấy sáu tu chân tinh xếp hình tròn làm nền, đủ sức phá tan đất trời, là phòng tuyến cuối cùng ngăn mãnh thú từ khe chiến trường.","detail":"Sáu tu chân tinh xếp hình tròn tạo thành đại trận, mỗi ngôi sao có một sơn môn với trưởng lão trấn giữ. Trận pháp này ngăn mãnh thú tấn công từ khe chiến trường, uy lực đủ phá tan đất trời.","congNang":["Phòng tuyến ngăn mãnh thú từ khe chiến trường tấn công"],"nguonGoc":"Do tông chủ đời đầu Yêu Tông tự tay bày ra","tabs":{"tienTrinh":[{"chuong":"@c1221","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ cấu trúc","text":"Lần đầu mô tả chi tiết: sáu tu chân tinh xếp hình tròn thành đại trận do tông chủ đời đầu bày ra, là phòng tuyến cuối ngăn mãnh thú.","anchor":"một đại trận lấy sáu tu chân tinh này tạo thành"}]},"nguon":["@c1221"]},{"id":"phong-an-khe-chien-truong","name":"Phong ấn khe chiến trường","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Tông chủ đời đầu Yêu Tông"],"blurb":"Thần thông phong ấn do tông chủ Yêu Tông năm xưa thi triển, thu nhỏ khe chiến trường và hạn chế mãnh thú mạnh xông ra, nhưng không hoàn toàn vì có kẻ bên trong ngăn cản.","detail":"Tông chủ Yêu Tông phong ấn khe chiến trường, thu nhỏ khe rất nhiều và dưới tác dụng phong ấn, mãnh thú mạnh bị hạn chế không thể xông ra. Tuy nhiên có ai đó ở bên trong khe thi triển thần thông không thể tưởng tượng, ngăn cản phong ấn hoàn toàn.","congNang":["Thu nhỏ khe chiến trường","Hạn chế mãnh thú mạnh xông ra"],"tabs":{"tienTrinh":[{"chuong":"@c1221","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ lịch sử","text":"Tông chủ Yêu Tông năm xưa phong ấn khe chiến trường, thu nhỏ khe rất nhiều nhưng có kẻ bên trong ngăn cản khiến phong ấn không hoàn toàn.","anchor":"thu nhỏ cái khe lại rất nhiều, hơn nữa dưới tác dụng của phong ấn"}]},"nguon":["@c1221"]},{"id":"thuat-hoa-than-huyet-kiem","name":"Thuật hóa thân thành huyết kiếm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật hóa thân thành huyết kiếm là bí thuật Vương Lâm thu huyết kiếm vào cơ thể, toàn thân phát xích quang hóa thành thanh huyết kiếm khổng lồ, bản thân chính là kiếm. Song chỉ tay phải trở thành mũi kiếm, phóng ngàn vạn kiếm khí với uy lực cực đại.","detail":"Vương Lâm dung nhập huyết kiếm (máu Cổ Thần từ mi tâm) vào thân thể, toàn thân biến thành thanh huyết kiếm khổng lồ, đạt trạng thái nhân kiếm hợp nhất hoàn toàn. Trong trạng thái này, song chỉ tay phải trở thành mũi kiếm, có thể phóng ngàn vạn kiếm khí hóa cuồng phong. Thuật này được Vương Lâm thi triển để phá hủy Dịch Linh Ấn hoàn chỉnh năm ký hiệu của tu sĩ Thiên Nhân Đệ Nhị Suy.","congNang":["Nhân kiếm hợp nhất, thu huyết kiếm vào cơ thể, toàn thân phát xích quang hóa thành thanh huyết kiếm khổng lồ @c1222","Song chỉ tay phải biến thành mũi kiếm, phóng ngàn vạn kiếm khí hóa cuồng phong @c1222","Phá hủy Dịch Linh Ấn hoàn chỉnh năm ký hiệu của tu sĩ Thiên Nhân Đệ Nhị Suy @c1222"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1222","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1222","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thu huyết kiếm vào thân, toàn thân hóa huyết kiếm, song chỉ tay phải phá hủy Dịch Linh Ấn năm ký hiệu của trưởng lão Yêu Tông, điểm trán đánh bại đối thủ.","anchor":"hắn, chính là huyết kiếm!"}]},"nguon":["@c1222"],"uyLuc":"Phóng ngàn vạn kiếm khí hóa cuồng phong, uy lực cực đại đủ phá hủy Dịch Linh Ấn hoàn chỉnh năm ký hiệu của tu sĩ cảnh giới Thiên Nhân Đệ Nhị Suy.","dacDiem":"Bản thân tu sĩ chính là kiếm, toàn thân phát xích quang, dung hợp hoàn toàn với huyết kiếm mang máu Cổ Thần từ mi tâm."},{"id":"ba-buoc-dich-chuyen-tinh-khong","name":"Ba bước dịch chuyển tinh không","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Trưởng lão Yêu Tông"],"blurb":"Trưởng lão Yêu Tông bước ba bước xuyên tinh không, mỗi bước dịch chuyển khoảng cách cực lớn, tốc độ không thấy thân ảnh.","detail":"Thân pháp dịch chuyển tức thời qua tinh không, mỗi bước vượt khoảng cách cực lớn. Trưởng lão Yêu Tông dùng để từ tu chân tinh xuất hiện trước mặt Vương Lâm trong nháy mắt.","nguon":["@c1222"]},{"id":"tue-nguyet-nghich-chuyen","name":"Tuế Nguyệt Nghịch Chuyển","cn":"岁月逆转","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Tuế Nguyệt Nghịch Chuyển là thần thông đảo ngược thời gian cục bộ tại một địa điểm, cho phép người thi triển nhìn thấy ảo ảnh quá khứ đã xảy ra nơi đó. Vương Lâm từng thi triển thuật này tại biên giới khe nứt Tử Giới để truy tìm dấu vết Lý Thiến Mai.","detail":"Nguồn gốc của Tuế Nguyệt Nghịch Chuyển không rõ ràng. Khi thi triển, người dùng điểm lên mi tâm, chấn động nguyên thần, từ đó kích hoạt hiệu ứng đảo ngược tuế nguyệt tại khu vực xung quanh. Thần thông không đưa người thi triển quay về quá khứ mà tái hiện hình ảnh của quá khứ dưới dạng ảo ảnh tại địa điểm đó. Vương Lâm đã sử dụng thuật này tại biên giới khe nứt Tử Giới, nhờ vậy nhìn thấy được ảo ảnh một nữ tử áo lam bị thương đang bay đi trong hư vô, qua đó xác nhận dấu vết Lý Thiến Mai. @c1223","thuocTinh":"Thời gian","nguonGoc":"Không rõ","yeuCau":"Chấn động nguyên thần","uyLuc":"Đảo ngược thời gian cục bộ tại một địa điểm, tái hiện hình ảnh quá khứ dưới dạng ảo ảnh, đủ rõ ràng để nhận diện nhân vật và trạng thái của họ @c1223","dacDiem":"Cần điểm mi tâm chấn động nguyên thần để kích hoạt; hiệu ứng giới hạn trong phạm vi cục bộ, không đưa người thi triển quay về quá khứ mà chỉ tái hiện ảo ảnh tại chỗ","congNang":["Đảo ngược thời gian cục bộ tại một địa điểm, tái hiện ảo ảnh quá khứ đã xảy ra nơi đó, cho phép người thi triển quan sát sự kiện đã qua @c1223"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1223","tangDatToi":"Không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1223","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển tại biên giới khe nứt Tử Giới, điểm mi tâm chấn động nguyên thần đảo ngược thời gian, nhìn thấy ảo ảnh quá khứ nữ tử áo lam bị thương đang bay đi.","anchor":"Tuế nguyệt. nghịch chuyển."}]},"capNhatToi":"@c1223","nguon":["@c1223"]},{"id":"than-thong-lu-phu-tu","name":"Thần thông Lỗ Phu Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm học được từ Lỗ Phu Tử, ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần đánh ra chưởng ấn hóa ánh sáng chói mắt tràn ngập vạn dặm.","detail":"Vương Lâm dùng tay trái thi triển, ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần đánh ra chưởng ấn hóa ánh sáng chói mắt tràn ngập vạn dặm, uy lực cực lớn. Nữ tử bọ cạp chín đuôi cấp mười ba buộc phải phun máu tạo huyết linh bao vây toàn thân để chống đỡ.","congNang":["Chưởng ấn ngưng tụ thiên địa nguyên lực + sức mạnh Cổ Thần, hóa ánh sáng chói mắt hủy diệt phạm vi vạn dặm"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1227","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1227","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong trận chiến bọ cạp cấp mười ba","text":"Vương Lâm dùng tay trái thi triển thần thông học từ Lỗ Phu Tử, ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần đánh ra chưởng ấn chói mắt tràn ngập vạn dặm, buộc nữ tử bọ cạp phải phun máu phòng thủ.","anchor":"thi triển ra thần thông học được từ Lỗ Phu Tử"}]},"nguon":["@c1227"]},{"id":"co-than-bien-hoa-phong-dai","name":"Cổ Thần biến hóa (phóng đại thân thể)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Kích hoạt tinh điểm Cổ Thần tại mi tâm, phóng đại thân thể lên gần ngàn trượng, hiện hình Cổ Thần với da thô ráp, uy áp kinh thiên, khí tức tang thương.","detail":"Vương Lâm điểm mi tâm kích hoạt tinh điểm Cổ Thần, thân thể phóng đại từ mười trượng lên gần ngàn trượng, hiện hình Cổ Thần với da thô ráp, uy áp kinh thiên động địa, mang khí tức tang thương. Nữ tử bọ cạp nhận ra tinh điểm Cổ Thần và kinh hãi kêu lên.","congNang":["Phóng đại thân thể Cổ Thần lên gần ngàn trượng, mang uy áp kinh thiên và sức mạnh vật lý khổng lồ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1227","tangDatToi":"lục tinh","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1227","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển sau khi khôi phục lục tinh","text":"Vương Lâm kích hoạt tinh điểm Cổ Thần, phóng đại thân thể gần ngàn trượng, hiện hình Cổ Thần với da thô ráp và uy áp kinh thiên. Nữ tử bọ cạp nhận ra và kinh hãi kêu lên.","anchor":"tinh điểm Cổ Thần ầm ầm biến ảo hiện ra, điên cuồng xoay tròn"}]},"nguon":["@c1227"]},{"id":"vo-luong-kiep","name":"Vô lượng kiếp","cn":"无量劫","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"Tất sát chi kiếp (đáng sợ nhất trong thiên kiếp)","hePhai":"","soHuu":[],"blurb":"Vô lượng kiếp là loại thiên kiếp đáng sợ nhất, giáng xuống khi có người đạt tầm ngang hàng với thiên địa. Bên trong chứa biến hóa khó lường, vượt trên mọi loại thiên kiếp thông thường như hồ lôi kiếp, thần kiếp hay uy kiếp.","detail":"Vô lượng kiếp được Thái thượng trưởng lão Yêu Tông nhận định là tất sát chi kiếp, dành riêng cho kẻ có thực lực bằng với thiên địa. Tông chủ Yêu Tông từng cảm thán rằng chúng sinh khó độ vô lượng kiếp. Khi giáng xuống, tầng mây tím cuồn cuộn bao phủ cả tinh vực cấp chín, uy áp kinh thiên khiến hàng trăm tu sĩ phun máu. Trong tầng mây mở ra lỗ hổng thông tới thế giới khác, lộ ra tòa lầu các bạch ngọc có pho tượng ngồi khoanh chân và hai thanh thạch kiếm. Biến hóa bên trong vô lượng kiếp khó lường, không đơn thuần là sấm sét hay lôi kiếp thông thường.","thuocTinh":"Thiên kiếp cực hạn","nguonGoc":"Giáng xuống khi có người đạt tầm bằng với thiên địa","dacDiem":"Biến hóa khó lường, vượt trên hồ lôi kiếp, thần kiếp và uy kiếp; khi giáng xuống mở lỗ hổng thông thế giới khác thay vì chỉ giáng lôi điện đơn thuần.","congNang":["Tất sát chi kiếp dành cho người ngang hàng thiên địa @c1229","Tầng mây tím bao phủ cả tinh vực cấp chín, uy áp kinh thiên khiến hàng trăm tu sĩ phun máu @c1229","Mở lỗ hổng thông tới thế giới khác, lộ ra tòa lầu các bạch ngọc có pho tượng và hai thanh thạch kiếm @c1229"],"tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"major","giaiDoan":"Giáng xuống Vân Hải tinh vực cấp chín","text":"Tầng mây tím cuồn cuộn bao phủ cả tinh vực, uy áp kinh thiên khiến hàng trăm tu sĩ phun máu. Trong tầng mây mở lỗ hổng thông thế giới khác, lộ tòa lầu các bạch ngọc với pho tượng và hai thanh thạch kiếm. Thái thượng trưởng lão Yêu Tông nhận ra đây là vô lượng kiếp.","anchor":"Chỉ có vô lượng kiếp thì mới là đáng sợ nhất, bên trong có biến hóa khó lường"}]},"capNhatToi":"@c1229","nguon":["@c1229"],"uyLuc":"Uy áp kinh thiên bao phủ cả tinh vực cấp chín, khiến hàng trăm tu sĩ phun máu, vượt trên mọi loại thiên kiếp thông thường."},{"id":"loi-luc-dieu-khien","name":"Lôi lực điều khiển","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lôi lực điều khiển là thuật do Vương Lâm thi triển nhằm tranh đoạt quyền kiểm soát sấm sét thiên kiếp, biến lôi đình thành vũ khí phản kích. Tại chương @c1230, Vương Lâm một tay đỡ tia sét ngàn trượng, truyền ý chí vào lôi đình và ra lệnh cho toàn bộ sấm sét oanh kích ngược lên tầng mây.","detail":"Vương Lâm dùng tay trái vuốt lôi đình, truyền ý chí của mình vào bên trong, tranh đoạt quyền điều khiển sấm sét với thiên kiếp. Sau đó bắt quyết, ra lệnh cho toàn bộ lôi đình nghe theo hiệu lệnh, ngưng tụ lôi đình ngàn trượng chứa ý chí của bản thân oanh kích thẳng vào tầng mây, tiếng nổ kinh thiên truyền khắp tinh vực cấp chín. Đây là biểu hiện khả năng can thiệp trực tiếp vào quy luật thiên kiếp, chiếm đoạt lôi lực thiên địa để sử dụng như vũ khí của chính mình.","congNang":["Tranh đoạt quyền kiểm soát sấm sét thiên kiếp, chiếm lấy lôi đình từ tay thiên kiếp @c1230","Truyền ý chí bản thân vào lôi đình, khiến sấm sét phục tùng hiệu lệnh @c1230","Ngưng tụ lôi đình ngàn trượng chứa ý chí, phản kích oanh thẳng vào tầng mây thiên kiếp @c1230"],"tabs":{"tienTrinh":[{"chuong":"@c1230","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng chống thiên kiếp","text":"Vương Lâm một tay đỡ tia sét ngàn trượng, tranh đoạt quyền điều khiển lôi lực thiên địa, phản kích lôi đình oanh thẳng vào tầng mây. Ý chí ẩn trong lôi đình còn xâm nhập mật thất Thần Tông kích hoạt Thất Thải Đinh.","anchor":"Ta chính là lôi, nắm quyền điều khiển lôi lực trong thiên địa"}]},"nguon":["@c1230"],"uyLuc":"Ngưng tụ lôi đình ngàn trượng oanh kích vào tầng mây thiên kiếp, tiếng nổ kinh thiên truyền khắp tinh vực cấp chín @c1230","dacDiem":"Không phải chiêu thức chủ động phóng sét mà là thuật tranh đoạt — cưỡng chiếm quyền kiểm soát lôi lực vốn thuộc về thiên kiếp, biến thiên phạt thành vũ khí phản công ngược trở lại."},{"id":"kiem-khi-hu-anh-huou","name":"Kiếm khí hư ảnh hươu","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm chỉ tay phóng hư ảnh hai con hươu từ đầu ngón tay, bạo phát ngàn vạn đạo kiếm khí ngưng tụ thành một đạo chống đỡ hư kiếm xanh.","detail":"Ngoài đầu ngón tay Vương Lâm lóe lên hư ảnh hai con hươu lần lượt xoay chuyển, bạo phát ra ngàn vạn đạo kiếm khí ngưng tụ làm một để đón đỡ hư kiếm xanh từ thạch kiếm của thế giới bên kia tầng mây. Hư kiếm suy yếu nhưng không tan rã.","congNang":["Phóng hư ảnh hai con hươu phát ra ngàn vạn kiếm khí ngưng tụ phòng thủ hoặc tấn công"],"tabs":{"tienTrinh":[{"chuong":"@c1230","loai":"thi triển","importance":"normal","giaiDoan":"Chống hư kiếm xanh từ thế giới bên kia","text":"Vương Lâm dùng hư ảnh hai con hươu phóng ngàn vạn đạo kiếm khí ngưng tụ thành một đạo đón đỡ hư kiếm xanh, khiến hư kiếm suy yếu nhưng không tan rã hoàn toàn.","anchor":"ngoài đầu ngón tay hắn lóe lên hư ảnh hai con hươu, lần lượt xoay chuyển, bạo phát ra ngàn vạn đạo kiếm khí"}]},"nguon":["@c1230"]},{"id":"cuu-cung-phong-an","name":"Cửu Cung Phong Ấn","cn":"九宫封仙","aliases":["Cửu Cung Phong Tiên"],"loai":"bi-thuat","loaiLabel":"Kiếp pháp (Thiên Kiếp)","phamCap":"Thiên Kiếp cấp","hePhai":"Thiên Kiếp","soHuu":[],"blurb":"Cửu Cung Phong Ấn là kiếp pháp thuộc Thiên Kiếp, sử dụng chín thiên thạch cổ đại từ tinh không đã bị luyện hóa, bố trí theo trận vị Cửu Cung để phong ấn tiên nhân. Chín tinh cầu nhập thể mục tiêu qua chín đốm máu, ngưng tụ tại ngực thì hoàn thành phong ấn; Vương Lâm dựa vào sức Cổ Thần ngăn quá trình ngưng tụ, khiến phép Phong Tiên không phát huy hiệu quả.","detail":"Chín thiên thạch khổng lồ trôi nổi trong tinh không từ vô số năm trước đã bị luyện hóa thành vật của Thiên Kiếp, sắp xếp theo chín cung vị: càn, khảm, cấn, chấn, trung, tốn, ly, bạng, đoài. Pho tượng trên lầu các bạch ngọc phát động phép này bằng câu hô \"Cửu Cung Vô Lượng\", triệu hoán chín thiên thạch thu nhỏ thành chín tinh cầu giáng xuống mục tiêu. Chín tinh cầu xâm nhập cơ thể qua chín đốm máu, gây đau đớn cực độ trong quá trình di chuyển bên trong thân thể, rồi cố ngưng tụ về một điểm duy nhất tại ngực để hoàn thành phong ấn. Bản chất của phép không phải phong mệnh mà là phong ấn, chuyên nhắm vào tiên nhân. Khi bị thi triển lên Vương Lâm, y đã dùng sức mạnh Cổ Thần ngăn cản quá trình ngưng tụ và tuyên bố bản thân là Cổ Thần, khiến Phong Tiên không có hiệu quả đối với mình.","thuocTinh":"Phong ấn","nguonGoc":"Thiên thạch tinh không bị luyện hóa thành vật của Thiên Kiếp","uyLuc":"Phong ấn tiên nhân, chín thiên thạch nhập thể gây đau đớn cực độ trong quá trình xâm nhập và ngưng tụ.","dacDiem":"Chín tinh cầu bố trí theo trận vị Cửu Cung (càn, khảm, cấn, chấn, trung, tốn, ly, bạng, đoài), nhập thể qua chín đốm máu, ngưng tụ ở ngực thì hoàn thành; nguồn gốc từ thiên thạch tinh không bị luyện hóa thành vật của Thiên Kiếp, phát động bởi pho tượng trên lầu các bạch ngọc bằng câu hô.","congNang":["Phong ấn tiên nhân — chín thiên thạch thu nhỏ thành tinh cầu, nhập thể qua chín đốm máu, ngưng tụ tại ngực hoàn thành phong ấn @c1232"],"tabs":{"tienTrinh":[{"chuong":"@c1232","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu phát động nhắm Vương Lâm","text":"Pho tượng trên lầu các bạch ngọc hô Cửu Cung Vô Lượng, triệu chín tinh cầu giáng xuống Vương Lâm. Chín đốm máu xuất hiện trên thân hắn, chín thiên thạch nhập thể cố ngưng tụ ở ngực. Vương Lâm hóa Lục tinh Cổ Thần dùng sức ngăn ngưng tụ, tuyên bố Cổ Thần không phải tiên nên Phong Tiên vô hiệu.","anchor":"Cửu Cung Phong Tiên! Phong này không phải là phong mệnh, mà là phong ấn!"}]},"nguon":["@c1232"]},{"id":"bat-quai-an","name":"Bát Quái Ấn","cn":"八卦印","loai":"bi-thuat","loaiLabel":"Kiếp pháp (Thiên Kiếp)","phamCap":"Thiên Kiếp cấp","hePhai":"Thiên Kiếp","soHuu":[],"blurb":"Bát Quái Ấn là kiếp pháp thuộc Thiên Kiếp, uy lực mạnh hơn Cửu Cung Phong Ấn. Tám ký hiệu Bát Quái tạo thành vòng tròn khổng lồ chứa tám hình thái biến hóa liên tục không có quy luật, đè xuống mục tiêu khiến đối phương lực bất tòng tâm.","detail":"Bát Quái Ấn được pho tượng trên lầu các bạch ngọc phát động bằng câu hô \"Bát Quái Vô Lượng\", triệu xuất tám ký hiệu tượng trưng cho càn–trời, khôn–đất, khảm–nước, ly–hỏa, chấn–sấm, cấn–núi, tốn–gió, đoài–đầm. Tám ký hiệu hợp thành vòng tròn khổng lồ chứa tám hình thái biến hóa liên tục không theo quy luật nào, xuyên qua lầu các bạch ngọc và khe nứt tiến vào hư vô đè xuống Vương Lâm. Uy lực vượt trên Cửu Cung Phong Ấn, khiến Vương Lâm lực bất tòng tâm buộc phải lui bước.","thuocTinh":"Công kích / Phong ấn","uyLuc":"Mạnh hơn Cửu Cung Phong Ấn, khiến Vương Lâm lực bất tòng tâm buộc phải lui bước.","dacDiem":"Tám hình thái biến hóa liên tục không có quy luật.","congNang":["Công kích và phong ấn: tám ký hiệu Bát Quái tạo vòng tròn khổng lồ chứa tám hình thái biến hóa đè xuống mục tiêu @c1232"],"tabs":{"tienTrinh":[{"chuong":"@c1232","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu phát động nhắm Vương Lâm","text":"Pho tượng vung tay phải hô Bát Quái Vô Lượng, tám ký hiệu xuất hiện tạo vòng tròn khổng lồ lao xuyên khe nứt đè xuống Vương Lâm. Uy lực mạnh hơn Cửu Cung khiến Vương Lâm lực bất tòng tâm buộc phải lui bước.","anchor":"Bát Quái này tuyệt luân, ngay khi xuất hiện, trời, đất, nước, lửa, sấm sét, núi, gió, đầm toàn bộ biến ảo hiện ra"}]},"nguon":["@c1232"]},{"id":"bat-quai-thien-kiep","name":"Bát Quái Thiên Kiếp","cn":"八卦天劫","loai":"bi-thuat","loaiLabel":"Trận pháp / Thiên kiếp","phamCap":"Thiên Kiếp","hePhai":"Thiên Đạo","soHuu":[],"blurb":"Bát Quái Thiên Kiếp là thuật pháp từ Thiên Kiếp, phóng hình tròn Bát Quái lao vào mục tiêu rồi tan vỡ thành tám ký hiệu dung nhập huyết mạch, phối hợp Cửu Cung phong ấn để phong ấn và phá phách bên trong cơ thể. Biến hóa theo bội số quẻ từ 64 đến vô tận.","detail":"Bát Quái Thiên Kiếp là một dạng phong ấn thuật xuất phát từ Thiên Kiếp. Khi kích phát, một hình tròn Bát Quái lao thẳng vào mục tiêu, ấn lên toàn thân rồi tan vỡ thành tám ký hiệu xuyên thấu da, dung nhập vào huyết mạch. Tám ký hiệu này phối hợp với Cửu Cung phong ấn, hình thành một trận phong ấn nội thể cực kỳ khủng khiếp, điên cuồng phá phách bên trong cơ thể mục tiêu. Nền tảng biến hóa dựa trên tám quẻ — thiên, địa, thủy, hỏa, lôi, sơn, phong, trạch — từ 64 quẻ nhân lên 128 quẻ rồi tiếp tục biến hóa đến vô tận. Thuật này lần đầu xuất hiện khi Thiên Kiếp giáng xuống Vương Lâm.","congNang":["Phóng hình tròn Bát Quái lao vào mục tiêu, tan vỡ thành tám ký hiệu dung nhập huyết mạch @c1233","Phối hợp Cửu Cung phong ấn, hình thành phong ấn nội thể phá phách bên trong cơ thể mục tiêu @c1233","Biến hóa theo bội số quẻ: từ 64 quẻ lên 128 quẻ rồi vô tận @c1233"],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"major","giaiDoan":"Giáng lâm lên Vương Lâm","text":"Hình tròn Bát Quái từ Thiên Kiếp lao vào Vương Lâm, ấn lên toàn thân tan vỡ thành tám ký hiệu dung nhập huyết mạch. Cùng Cửu Cung điên cuồng phá phách bên trong cơ thể, biến hóa từ 64 quẻ đến vô tận.","anchor":"Bát Quái kia cùng với Cửu Cung cùng lóe sáng lên, hình thành một phong ấn không thể tưởng tượng được"}]},"uyLuc":"Phong ấn xâm nhập huyết mạch, phối hợp Cửu Cung phong ấn điên cuồng phá phách nội thể mục tiêu với biến hóa vô tận không thể tưởng tượng.","dacDiem":"Tám ký hiệu tương ứng tám quẻ — thiên địa thủy hỏa lôi sơn phong trạch — xuyên thấu da dung nhập huyết mạch, lấy nội thể mục tiêu làm chiến trường phong ấn, biến hóa nhân bội không có giới hạn."},{"id":"that-tinh-bac-dau-tran","name":"Thất Tinh Bắc Đẩu trận","cn":"七星北斗阵","loai":"bi-thuat","loaiLabel":"Trận pháp / Thiên kiếp","phamCap":"Thiên Kiếp","hePhai":"Thiên Đạo","soHuu":[],"blurb":"Thất Tinh Bắc Đẩu trận là trận pháp sát kiếp do bảy tu chân tinh lóe ra từ cơn lốc xoáy Thiên Kiếp hợp thành, hấp thụ hết tinh quang thiên địa tạo sát khí kinh thiên, hóa bảy đạo tinh ngân như bảy thanh sát kiếm lao thẳng về mục tiêu. Đây là sát kiếp trực tiếp, không phải phong ấn.","detail":"Thất Tinh Bắc Đẩu trận được hợp thành bởi bảy tu chân tinh mang tên Thiên Khu, Thiên Tuyền, Thiên Ki, Thiên Quyền, Ngọc Nha, Khai Dương và Diêu Quang — tương ứng bảy ngôi sao của chòm Bắc Đẩu. Bảy ngôi tinh này lóe ra từ cơn lốc xoáy Thiên Kiếp, khi hợp trận liền hấp thụ toàn bộ hào quang trời đất, ngưng tụ thành sát khí kinh thiên, rồi hóa thành bảy đạo tinh ngân sáng rực tựa bảy thanh sát kiếm trực chỉ mục tiêu. Bản chất của trận pháp này là sát kiếp chứ không phải phong ấn, mang tính hủy diệt trực tiếp.","congNang":["Hấp thụ hết tinh quang thiên địa, ngưng tụ thành sát khí kinh thiên @c1233","Hóa bảy đạo tinh ngân như bảy thanh sát kiếm lao thẳng về mục tiêu, thi triển sát kiếp trực tiếp @c1233"],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"major","giaiDoan":"Sát kiếp giáng lâm lên Vương Lâm","text":"Bảy tu chân tinh lóe ra hợp thành Bắc Đẩu trận, hấp thụ hết hào quang trời đất tạo sát khí kinh thiên, hóa bảy thanh sát kiếm lao về Vương Lâm.","anchor":"Thất Tinh là sát, Bắc Đẩu là sát, Thất Tinh Bắc Đẩu này không phải là phong ấn, mà là sát kiếp!"}]},"uyLuc":"Hấp thụ toàn bộ hào quang trời đất tạo sát khí kinh thiên, hóa bảy đạo tinh ngân tựa sát kiếm giáng xuống mục tiêu.","dacDiem":"Trận pháp do bảy tu chân tinh Bắc Đẩu hợp thành từ lốc xoáy Thiên Kiếp, bản chất là sát kiếp trực tiếp chứ không phải phong ấn."},{"id":"bat-hoang-phong-thien-tran","name":"Bát Hoang Phong Thiên Trận","cn":"八荒封天阵","loai":"bi-thuat","loaiLabel":"Trận pháp / Thiên kiếp","phamCap":"Thiên Kiếp","hePhai":"Thiên Đạo","soHuu":[],"blurb":"Sáu tấm mai rùa tượng trưng sáu phương vị Trên Dưới Đông Tây Nam Bắc, phong tỏa tất cả đường lui, nguyên thần cũng không thể chạy.","detail":"Thanh âm mơ hồ nói “Thập vô lượng”, sáu tấm mai rùa hiện ra tượng trưng Bát Hoang (Trên Dưới Đông Tây Nam Bắc) tạo thành Phong Thiên Trận, phong tỏa mọi đường lui, bắt buộc mục tiêu phải đánh.","congNang":["Phong tỏa không gian tuyệt đối, ngăn mọi đường thoát kể cả nguyên thần"],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"normal","giaiDoan":"Phong tỏa Vương Lâm","text":"Sáu tấm mai rùa hiện ra phong tỏa mọi đường lui của Vương Lâm, bắt buộc phải đánh.","anchor":"Đây là Phong Thiên Trận, bị trận pháp này bao phủ, thì chỉ có đánh một trận!"}]}},{"id":"ngu-hanh-vo-luong","name":"Ngũ Hành vô lượng","cn":"五行无量","loai":"than-thong","loaiLabel":"Thần thông / Thiên kiếp","phamCap":"Thiên Kiếp","hePhai":"Thiên Đạo","soHuu":[],"blurb":"Năm thủ ấn khổng lồ kim mộc thủy hỏa thổ, mỗi ấn chứa cực hạn một hành. Kim khai thiên, Mộc sinh tử, Thủy và Hỏa cực đoan, Thổ bất khả phá.","detail":"Năm thủ ấn khổng lồ tượng trưng ngũ hành lao về mục tiêu. Kim thủ ấn mang sức mạnh khai thiên. Mộc thủ ấn chứa khí tức sinh tử. Thủy và Hỏa thủ ấn cực đoan đối lập. Thổ thủ ấn nặng nề như đại địa, ngưng tụ toàn bộ sức mạnh đại địa trong tinh không, không thể phá hủy.","congNang":["Công kích ngũ hành toàn diện, mỗi hành đạt cực hạn"],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"normal","giaiDoan":"Lao về Vương Lâm","text":"Năm thủ ấn khổng lồ kim mộc thủy hỏa thổ lao về Vương Lâm, mỗi ấn chứa cực hạn một hành.","anchor":"Kim mộc thủy hỏa thổ, sức mạnh của thiên địa ngũ hành"}]}},{"id":"hu-hoa-no-hoa","name":"Hư hỏa (Nộ hỏa)","cn":"虚火","aliases":["Nộ hỏa"],"loai":"than-thong","loaiLabel":"Thần thông hỏa diễm","phamCap":"Vượt xa thực hỏa, hỏa ý cảnh/tinh thần","hePhai":"Hỏa diễm","soHuu":["Vương Lâm (chưa đạt, kém một đường)"],"blurb":"Loại hỏa ý cảnh vượt xa thực hỏa, có thể nhóm nộ hỏa vô hình trong cơ thể người khác khiến tự thiêu. Cần Chu Tước thức tỉnh lần thứ tư mới đạt.","detail":"Hỏa diễm chia thành thực hỏa và hư hỏa. Hư hỏa còn gọi nộ hỏa, là loại hỏa ý cảnh/tinh thần, có thể nhóm nộ hỏa trong cơ thể người khác khiến kẻ không điều khiển được chắc chắn chết do tự thiêu. Chu Tước đã thức tỉnh ba lần sinh ra bổn nguyên nắm thực hỏa cực hạn; cần thức tỉnh lần thứ tư mới bước vào hư hỏa. Sau khi Vương Lâm hấp thu lửa thiên kiếp, khoảng cách tới lần thức tỉnh thứ tư chỉ còn kém một đường.","congNang":["Nhóm nộ hỏa vô hình trong cơ thể người khác khiến tự thiêu","Vượt xa thực hỏa, thuộc ý cảnh/tinh thần"],"nguon":["@c1234"]},{"id":"thien-kiep-chuoi-cuu-nhat","name":"Thiên kiếp chuỗi (Cửu → Nhất)","cn":"","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"Thiên cực kiếp","hePhai":"","soHuu":[],"blurb":"Chuỗi thiên kiếp hoàn chỉnh diễn biến từ chín tới một: Cửu Cung → Bát Quái → Thất Tinh → Ngũ Hành → Tứ Tượng → Tam Tài → Lưỡng Nghi → Nhất Kiếp (Cực Cảnh).","detail":"Chuỗi thiên kiếp tuần tự: Cửu Cung → Bát Quái → Thất Tinh → (Lục Hòa) → Ngũ Hành → Tứ Tượng (tứ linh: Thanh Long, Chu Tước, Bạch Hổ, Huyền Vũ) → Tam Tài (Thiên/Địa/Nhân tương ứng Nhật/Nguyệt/Tinh, mang quy tắc ban đầu, kết thúc, và loại chưa từng thấy) → Lưỡng Nghi (Âm Dương/Thái Cực) → Nhất Kiếp. Khi tất cả hợp nhất sinh ra lực lượng cực đoan của thiên đạo, chính là Cực Cảnh. Mỗi tầng có âm thanh vô tình tuyên bố vô lượng.","nguon":["@c1234"]},{"id":"thon-linh-phe-the-tuyet-thien","name":"Thôn Linh Phệ Thể Tuyệt Thiên","cn":"吞灵噬体绝天","loai":"than-thong","loaiLabel":"Tiên thuật (ma công)","phamCap":"Cực phẩm (thiên hạ chỉ hai người biết)","hePhai":"Ma đạo","soHuu":["Thanh Thủy","Vương Lâm"],"blurb":"Tiên thuật do Thanh Thủy tự sáng tạo khi mới tới Lôi Tiên Giới, trên danh nghĩa là tiên thuật nhưng thực chất là ma công cực điểm, cực kỳ tàn khốc. Vương Lâm lần đầu thi triển tại Thái Cổ Tinh Thần khi bị trọng thương cực nặng sau khi phá Phong Giới Đại Trận, đối diện mấy trăm tu sĩ giới ngoại.","detail":"Thôn Linh Phệ Thể Tuyệt Thiên là công pháp do Thanh Thủy tự nghĩ ra khi mới xuất hiện ở Lôi Tiên Giới. Tuy mang danh nghĩa tiên thuật, bản chất thực sự là ma công cực điểm mà cả thiên hạ chỉ có Thanh Thủy và Vương Lâm biết tường tận. Khi kích hoạt, người thi triển bắt quyết điểm vào ngực, thân thể héo rũ như xương khô, sau đó hóa thành sương mù đen cuốn lấy đối phương. Sương mù nuốt sạch nguyên thần, huyết nhục, kim thân của mục tiêu, khiến nạn nhân biến thành bao da rỗng mắt xám rồi sụp đổ, hoặc dung nhập vào thân thể đối phương khiến họ bành trướng rồi tự bạo. Tinh hoa nuốt được dùng để chữa thương và khôi phục tu vi cho người thi triển. Công pháp này có thể phát huy uy lực theo nguyên lý súc địa thành thốn ở giới ngoại, dung nhập thiên địa. Vương Lâm lần đầu thi triển Thôn Linh Phệ Thể ","thuocTinh":"Ma đạo / Tiên thuật","nguonGoc":"Thanh Thủy tự nghĩ ra khi mới xuất hiện ở Lôi Tiên Giới","uyLuc":"Nuốt sạch nguyên thần, huyết nhục, kim thân đối phương trong nháy mắt; có thể phát huy súc địa thành thốn ở giới ngoại dung nhập thiên địa.","dacDiem":"Trên danh nghĩa là tiên thuật nhưng thực chất là ma công cực điểm, cực kỳ tàn khốc. Kích hoạt bằng cách bắt quyết điểm vào ngực, thân thể héo rũ như xương khô trước khi hóa sương mù đen. Cả thiên hạ chỉ có Thanh Thủy và Vương Lâm biết công pháp này.","congNang":["Nuốt nguyên thần, huyết nhục, kim thân đối phương để chữa thương và khôi phục tu vi cho người thi triển (@c1235)","Hóa sương mù đen cuốn lấy mục tiêu, biến nạn nhân thành bao da rỗng mắt xám sụp đổ hoặc dung nhập thân thể khiến đối phương bành trướng rồi tự bạo (@c1235)","Có thể phát huy uy lực theo nguyên lý súc địa thành thốn ở giới ngoại, dung nhập thiên địa"],"nguoiTu":[{"ten":"Thanh Thủy","tuChuong":"@c1235","tangDatToi":"Sáng tạo","trangThai":"da-dung"},{"ten":"Vương Lâm","tuChuong":"@c1235","tangDatToi":"Lần đầu thi triển","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1235","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu Vương Lâm thi triển","text":"Vương Lâm bị trọng thương cực nặng sau khi phá Phong Giới Đại Trận, đối diện mấy trăm tu sĩ giới ngoại, lần đầu thi triển Thôn Linh Phệ Thể Tuyệt Thiên. Bắt quyết điểm vào ngực, hóa sương mù đen nuốt sạch tinh hoa tu sĩ để chữa thương.","anchor":"Cả thiên địa, giới nội, giới ngoại, loại tiên thuật tàn khốc này chỉ có hai người là hắn và Vương Lâm biết!"}]},"nguon":["@c1235"]},{"id":"than-thong-ngu-sac","name":"Thần thông ngũ sắc","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)"],"blurb":"Thần thông hóa thiên địa nguyên lực thành mảnh ngũ sắc để ngăn chặn đòn tấn công, do lão giả Toái Niết đại viên mãn thi triển nhưng không đủ chống lại tia chớp đỏ của Vương Lâm.","detail":"Bùng phát toàn bộ nguyên lực, thiên địa nguyên lực hóa thành mảnh thần thông ngũ sắc cố gắng ngăn tia chớp đỏ, nhưng vừa chạm vào liền sụp đổ.","nguon":["@c1236"],"congNang":["Hóa thiên địa nguyên lực thành mảnh ngũ sắc ngăn chặn đòn tấn công"],"tabs":{"tienTrinh":[{"chuong":"@c1236","loai":"thi triển","importance":"normal","giaiDoan":"Lão giả Toái Niết đại viên mãn thi triển","text":"Lão giả bùng phát toàn bộ nguyên lực, hóa thành mảnh thần thông ngũ sắc cố ngăn tia chớp đỏ của Vương Lâm nhưng vừa chạm vào liền sụp đổ.","anchor":"hóa thành một mảnh thần thông ngũ sắc, cố gắng ngăn cả tia chớp màu đỏ kia"}]}},{"id":"truu-tinh-hon-luc","name":"Trừu Tinh Hồn Lực","cn":"抽星魂力","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông rút tinh hồn của cả một hành tinh, thu thành đám khí tinh hồn ẩn chứa tinh không.","detail":"Vương Lâm giơ tay trái hướng xuống mặt đất tung một trảo, rút toàn bộ tinh hồn của tu chân tinh, thu vào tay trái thành đám khí bông to bằng nắm tay ẩn chứa tinh không. Có thể dùng hồi phục nguyên thần.","nguon":["@c1238"],"congNang":["Rút tinh hồn quy mô toàn bộ hành tinh, thu thành đám khí dùng hồi phục nguyên thần @c1238"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1238","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1238","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm thi triển rút tinh hồn tu chân tinh","text":"Vương Lâm dùng Trừu Tinh Hồn Lực rút toàn bộ tinh hồn tu chân tinh, thu bảy đám khí tinh hồn từ nhiều hành tinh để hồi phục nguyên thần.","anchor":"tay tráu giơ lên hướng xuống mặt đất hung hăn tung một trảo - Trừu tinh hồn lực"}]}},{"id":"co-than-bat-tinh-thuat-hu","name":"Cổ Thần Bát Tinh thuật — Hư","cn":"古神八星术——虚","loai":"than-thong","loaiLabel":"Thần thông Cổ Thần","phamCap":"Bát tinh Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm","Thác Sâm"],"blurb":"Thần thông bát tinh Cổ Thần từ thái cổ, vô số ngàn năm chưa xuất hiện. Phát ra hư lực hủy diệt thiên địa, đối đầu thiên đạo.","detail":"Vương Lâm niệm khẩu quyết Cổ Thần tạo ký hiệu không trọn vẹn — vì chỉ có ký ức truyền thừa mà thiếu sức mạnh truyền thừa. Thác Sâm bơm Cổ Thần lực vào hoàn thiện ký hiệu. Ký hiệu hoàn chỉnh phát ánh sáng đen trắng, chứa hư lực hủy diệt thiên địa, quét sạch toàn bộ pháp bảo Nguyệt Tộc: Hội Thần Dịch bị cuốn, mắt Cổ Thần nổ tung, sóng chuông tiêu tán, Diệt Thế Cửu Linh tan thành mây khói, Phong Thần Đại Trận nứt rạn. Sau đó bị đốt xương cửu tinh Cổ Thần đánh vỡ. Cần cả ký ức truyền thừa lẫn sức mạnh truyền thừa mới hoàn chỉnh — Vương Lâm giữ ký ức, Thác Sâm giữ sức mạnh, hai người phối hợp mới thi triển được.","nguon":["@c1239"]},{"id":"phong-than-dai-tran","name":"Phong Thần Đại Trận","cn":"封神大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Đại trận cấp tộc","hePhai":"Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"blurb":"Đại trận phong ấn Cổ Thần do tổ tiên Nguyệt Tộc chuẩn bị vô số vạn năm, mười vạn tộc nhân duy trì, chuyên khắc chế Cổ Thần.","detail":"Mười vạn tộc nhân (mi tâm có ấn ký trăng lưỡi liềm) cùng mấy trăm tu sĩ trên tu chân tinh bốn phía duy trì. Kích hoạt biến tinh vực thành thế giới nguyệt quang — không gian hư ảo, phong ấn mục tiêu bằng vô số sợi dây nguyệt sắc sắc bén, tái sinh không ngừng. Kết hợp khẩu quyết Nguyệt Thần Sát, Thí Thần Khu biến sợi dây thành dây sắc bén hơn. Khi tộc nhân chết, hồn phách hóa nguyệt quang tăng cường trận (Đại Nguyệt Diệt Thần thuật). Liên tiếp triệu ra các chí bảo: Vân Thần Diệt Phiến, Huyết Nguyệt Thú, Cổ Thần Cửu Cốt, Hội Thần Dịch, Mắt của Cổ Thần, Cự Linh Chung, Diệt Thế Đệ Cửu Linh. Bị Bát Tinh thuật Hư xuyên thấu nứt rạn, cuối cùng sụp đổ.","nguon":["@c1239"]},{"id":"than-quyen-co-than","name":"Thần Quyền","cn":"神拳","loai":"than-thong","loaiLabel":"Thần thông Cổ Thần","phamCap":"Lục tinh Cổ Thần","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần thông chỉ lục tinh Cổ Thần mới phát huy, tập trung toàn bộ Cổ Thần lực vào một quyền hủy diệt càn khôn.","detail":"Cần rất nhiều sức mạnh Cổ Thần. Vương Lâm nhờ khí Cổ Thần bốn phía từ pho tượng Cổ Thần mà thi triển: song chưởng nắm lại, huyết kiếm trong tay, cả người hóa lốc xoáy kinh thiên, bên ngoài hiện hư ảnh Cổ Thần. Sức mạnh hóa thành một quyền, hủy diệt càn khôn. Đánh tê dại tay phải Thác Sâm, tâm thần rung động, nhưng Vương Lâm cũng trở thành huyết nhân, tổn hao cực lớn.","nguon":["@c1239"]},{"id":"dai-nguyet-diet-than-thuat","name":"Đại Nguyệt Diệt Thần thuật","cn":"大月灭神术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"blurb":"Bí thuật Nguyệt Tộc biến tử vong tộc nhân thành sức tấn công — hồn phách hóa nguyệt quang tăng cường Phong Thần Đại Trận.","detail":"Khi tộc nhân chết trong trận pháp, hồn phách hóa nguyệt quang bành trướng tăng cường Phong Thần Đại Trận. Khẩu quyết: Lấy máu của tộc ta, nuôi dưỡng thần linh, lấy hồn của tộc ta, phá vỡ thần linh. Hơn một vạn hồn phách bành trướng thành nguyệt quang lao vào Thác Sâm và Vương Lâm.","nguon":["@c1239"]},{"id":"dong-chay-tinh-than","name":"Dòng chảy tinh thần","cn":"星辰之流","loai":"than-thong","loaiLabel":"Thần thông Cổ Thần","phamCap":"","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần thông Cổ Thần — hai tay điểm mi tâm, sáu tinh điểm bay ra tạo dòng chảy khổng lồ có lực hút, hút Cổ Thần lực đối phương biến thành phản kích.","detail":"Vương Lâm dùng Cổ Thần lực đã hút giữ từ Thác Sâm trong đại trận phong thần, cộng thêm Cổ Thần lực bản thân để thi triển. Hai tay điểm vào mi tâm, sáu tinh điểm xoay tròn bay ra hình thành dòng chảy khổng lồ từ mi tâm, có vô tận lực hút. Hút một phần Cổ Thần lực của Thác Sâm biến thành phản kích, khiến tay phải hắn tê dại, tạo cơ hội cho Vương Lâm chém đứt ngón trỏ Thác Sâm. Cần Cổ Thần lực cường đại mới dùng được.","nguon":["@c1239"]},{"id":"tran-phap-cam-che-lam-son","name":"Trận pháp cấm chế Lam Sơn","cn":"蓝山禁制阵法","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Lam Ti tộc","soHuu":["Lam Mộng Đạo Tôn"],"blurb":"Trận pháp bao phủ toàn bộ Lam Sơn trên tu chân tinh của Lam Mộng Đạo Tôn, phát ra lực cản tăng dần theo độ cao, ngăn người ngoài tiếp cận đỉnh núi.","detail":"Trận pháp cấm chế được bố trí trên toàn bộ ngọn Lam Sơn thuộc tu chân tinh riêng của Lam Mộng Đạo Tôn. Lực cản tăng gấp bội theo mỗi bậc thang leo lên, càng gần đỉnh càng kinh thiên — tới mức dường như mấy tu chân tinh cùng đè xuống, đồng thời lực cản từ phía dưới kéo ngược lùi lại. Vương Lâm ở cảnh giới Đệ Nhị Bộ, vận toàn bộ nguyên lực và Cổ Thần lực, phải leo suốt ba ngày mới lên tới đỉnh, trong quá trình mồ hôi lẫn máu, phun máu, mạch máu gần như nổ tung. Khi hắn buông bỏ sự chống cự, lực cản lập tức đẩy tung hắn bay vụt khỏi đỉnh núi, khoảng cách bị kéo ra vô tận.","nguon":["@c1241"]},{"id":"anh-mat-ac-mong","name":"Ánh mắt ác mộng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ánh mắt ác mộng là thần thông do Vương Lâm tự ngộ, huy động năm đạo bổn nguyên trong đồng tử mở mắt, có khả năng phá tan mọi tấm màn che trong thiên địa và thấy bổn nguyên vạn vật. Lần chủ động thi triển ở biên giới Lam Ti tộc gần tới vô hạn so với lần vô tình dùng ở La Thiên Tinh Vực trước đây.","detail":"Ánh mắt ác mộng là thần thông Vương Lâm tự ngộ, từng vô tình thi triển ở La Thiên Tinh Vực. Khi sử dụng, năm đạo bổn nguyên — lửa lam, tia chớp, sinh tử Thái Cực, nhân quả, chân giả — được huy động trong đồng tử xoay tròn, sau đó mở mắt giải phóng ánh mắt mang lực lượng bổn nguyên. Tại biên giới Lam Ti tộc (@c1242), Vương Lâm lần đầu chủ động thi triển thần thông này, uy lực gần tới vô hạn so với lần vô tình dùng trước đó. Nhờ ánh mắt ác mộng, hắn phát hiện được bạch y nữ tử không có sinh cơ mà thần thức không thể cảm nhận, vốn bị lực lượng kỳ dị che giấu thân hình.","thuocTinh":"Ngũ đạo bổn nguyên (lửa lam, tia chớp, sinh tử Thái Cực/nhân quả, chân giả)","nguonGoc":"Vương Lâm tự ngộ, từng vô tình thi triển ở La Thiên Tinh Vực","yeuCau":"Năm đạo bổn nguyên trong đồng tử","dacDiem":"Huy động năm đạo bổn nguyên (lửa lam, tia chớp, sinh tử Thái Cực, nhân quả, chân giả) trong đồng tử xoay tròn rồi mở mắt; phá tan thiên địa, thấy bổn nguyên vạn vật, nhìn xuyên ẩn hình.","congNang":["Phá tan mọi tấm màn che trong thiên địa, thấy bổn nguyên vạn vật @c1242","Nhìn xuyên lực lượng kỳ dị che giấu thân hình, phát hiện tồn tại không có sinh cơ mà thần thức không thể cảm nhận @c1242"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1242","tangDatToi":"Gần tới vô hạn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1242","loai":"thi triển","importance":"major","giaiDoan":"Chủ động thi triển gần vô hạn","text":"Vương Lâm chủ động huy động năm đạo bổn nguyên trong đồng tử thi triển ánh mắt ác mộng ở biên giới Lam Ti tộc, đạt trình độ gần tới vô hạn so với lần vô tình dùng ở La Thiên Tinh Vực. Nhờ đó phát hiện bạch y nữ tử bí ẩn không có sinh cơ.","anchor":"Ánh mắt này đã gần tới vô hạn so với ánh mắt năm đó Vương Lâm vô tình thi triển ra ở La Thiên Tinh Vực"}]},"capNhatToi":"@c1242","nguon":["@c1242"]},{"id":"chin-dai-than-thong-lam-mong","name":"Chín đại thần thông (Lam Mộng Đạo Tôn)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lam Mộng Đạo Tôn","soHuu":["Lam Mộng Đạo Tôn"],"blurb":"Chín đại thần thông là bộ thần thông do Lam Mộng Đạo Tôn nắm giữ, được đạo tôn chủ động đề nghị truyền thụ cho Vương Lâm. Tính tới mốc hiện tại, nội dung cụ thể của chín đại thần thông hoàn toàn chưa được tiết lộ.","detail":"Tại cuối chương @c1242, Lam Mộng Đạo Tôn hiện thân trong ánh sáng lam nhu hòa và chủ động hỏi Vương Lâm có muốn học chín đại thần thông của mình hay không. Đây là lần đầu tiên chín đại thần thông được nhắc tới; ngoài việc thuộc về Lam Mộng Đạo Tôn và được đạo tôn coi trọng đến mức tự mình đề nghị truyền dạy, không có thêm bất kỳ thông tin nào về nguồn gốc chi tiết, cấu thành, công năng hay uy lực của bộ thần thông này.","nguonGoc":"Lam Mộng Đạo Tôn","congNang":[],"nguoiTu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1242","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1242","loai":"xuất hiện","importance":"major","giaiDoan":"Lam Mộng đề nghị truyền thụ","text":"Lam Mộng Đạo Tôn hiện thân cuối chương, chủ động hỏi Vương Lâm có muốn học chín đại thần thông của mình không.","anchor":"Ta có chín đại thần thông, ngươi có học hay không?"}]},"capNhatToi":"@c1242","nguon":["@c1242"]},{"id":"phien-thien-an","name":"Phiên Thiên Ấn","cn":"翻天印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông bước thứ ba","hePhai":"Lam Mộng Đạo Tôn sáng tạo","soHuu":["Lam Mộng Đạo Tôn","Vương Lâm"],"blurb":"Phiên Thiên Ấn là thức thần thông tấn công thứ nhất của Lam Mộng Đạo Tôn, ngưng nguyên khí thiên địa thành đại ấn khổng lồ, lật trời thành đất đất thành trời, trong tinh không có thể đồ diệt vạn linh. Thần thông này được Lam Mộng Đạo Tôn truyền cho Vương Lâm.","detail":"Lam Mộng Đạo Tôn chụp tay lên trời, lam quang tràn ngập, nguyên khí thiên địa ngưng tụ thành đại ấn khổng lồ. Khi ấn hạ xuống, trời biến thành đất, đất biến thành trời, thiên địa nghịch chuyển hoàn toàn. Yêu cầu thi triển: trong tâm người sử dụng phải tồn tại thiên địa thì mới có thể thi triển trong tinh không. Lam Mộng Đạo Tôn đã trực tiếp thi triển Phiên Thiên Ấn trước mặt Vương Lâm và truyền thụ thần thông này cho Vương Lâm @c1243.","congNang":["Ngưng nguyên khí thiên địa thành đại ấn, lật thiên địa nghịch chuyển — trời biến thành đất, đất biến thành trời @c1243","Trong tinh không có thể đồ diệt vạn linh @c1243"],"nguoiTu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","tangDatToi":"Sáng tạo, đại thành","trangThai":"dang-dung"},{"ten":"Vương Lâm","tuChuong":"@c1243","tangDatToi":"Mới học","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"major","giaiDoan":"Lam Mộng thi triển và truyền cho Vương Lâm","text":"Lam Mộng Đạo Tôn thi triển Phiên Thiên Ấn trước mặt Vương Lâm — chụp tay lên trời ngưng nguyên khí thành đại ấn lật thiên địa nghịch chuyển. Vương Lâm chấn động nhận ra trong tinh không có thể đồ diệt vạn linh.","anchor":"Thức thần thông này tên là Phiên Thiên Ấn, có thể lật trời!"}]},"nguon":["@c1243"],"uyLuc":"Đại ấn hạ xuống khiến thiên địa nghịch chuyển, trong tinh không có sức mạnh đồ diệt vạn linh.","dacDiem":"Yêu cầu trong tâm phải tồn tại thiên địa mới có thể thi triển trong tinh không; thi triển bằng cách chụp tay lên trời, lam quang tràn ngập, nguyên khí ngưng thành đại ấn."},{"id":"thuat-phong-ngu-anh-sang-khong-linh","name":"Thuật phòng ngự ánh sáng (cảm ngộ Không Linh)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cảm ngộ cảnh giới Không Linh","hePhai":"Lam Mộng Đạo Tôn sáng tạo","soHuu":["Lam Mộng Đạo Tôn","Vương Lâm"],"blurb":"Thức thần thông phòng ngự thứ hai của Lam Mộng Đạo Tôn, không phải đạo thuật mà là cảm ngộ khi đạt Không Linh — thu hút ánh sáng vạn vật vờn quanh thân thành pho tượng chói lọi hộ thể.","detail":"Lam Mộng vung tay, cỏ cây vạn vật tản ra ánh sáng vô tận, ánh sáng vờn quanh thân thành pho tượng chói lọi cao như đội trời. Nếu học được có thể tự bảo vệ trong Thái Cổ Tinh Thần. Là cảm ngộ cảnh giới chứ không phải đạo thuật thông thường.","congNang":["Phòng ngự, thu hút ánh sáng vạn vật ngưng thành hộ thể chói lọi"],"nguoiTu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","tangDatToi":"Sáng tạo, đại thành","trangThai":"dang-dung"},{"ten":"Vương Lâm","tuChuong":"@c1243","tangDatToi":"Mới học","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"normal","giaiDoan":"Lam Mộng thi triển và truyền cho Vương Lâm","text":"Lam Mộng Đạo Tôn thi triển thuật phòng ngự bằng ánh sáng, cỏ cây vạn vật tản ra ánh sáng vô tận ngưng thành pho tượng chói lọi. Nói nếu học được có thể tự bảo vệ trong Thái Cổ Tinh Thần.","anchor":"Thuật này không phải là đạo thuật nhưng là cảm ngộ của lão phu khi đạt tới cảnh giới Không Linh"}]},"nguon":["@c1243"]},{"id":"tu-canh-khong-buoc-thu-ba","name":"Tứ cảnh Không (hệ thống bước thứ ba)","cn":"","loai":"khac","loaiLabel":"Hệ thống cảnh giới","phamCap":"Bước thứ ba","hePhai":"","soHuu":[],"blurb":"Hệ thống cảnh giới bước thứ ba tu đạo: Không Niết (bước đầu) → Không Linh (cánh cửa) → Không Huyền (đại đạo) → Không Kiếp (đỉnh phong). Chưa ai độ kiếp Không Kiếp thành công, bước thứ tư đạp thiên chỉ trong truyền thuyết.","detail":"Lam Mộng Đạo Tôn giảng giải tứ cảnh Không: Không Niết là bước đầu, Không Linh là cánh cửa, Không Huyền là đại đạo, Không Kiếp là đỉnh phong. Từ cổ chí kim chưa ai độ kiếp Không Kiếp thành công. Bước thứ tư gọi là đạp thiên, chỉ tồn tại trong truyền thuyết, ngay viễn cổ bát phi cũng không đạt tới.","nguon":["@c1243"]},{"id":"dung-bien-dao-thuat","name":"Dung biến đạo thuật","cn":"融变道术","aliases":["Đạo thuật dung hợp"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lam Mộng Đạo Tôn","Vương Lâm"],"blurb":"Dung biến đạo thuật là thức thứ ba mà Lam Mộng Đạo Tôn sáng tạo và truyền dạy cho Vương Lâm. Đây là thần thông chuyên về dung hợp và biến đổi bổn nguyên bản thân, không thuộc phạm trù công kích hay phòng thủ.","detail":"Dung biến đạo thuật do Lam Mộng Đạo Tôn tự sáng tạo, là thức thứ ba trong các thần thông truyền cho Vương Lâm. Bản chất của đạo thuật này nằm ở khả năng dung hợp và thay đổi bổn nguyên bản thân, có thể hóa một thành ngàn vạn hoặc ngưng tụ ngàn vạn thành một thể duy nhất. Khi Lam Mộng Đạo Tôn biểu diễn cho Vương Lâm, ngài biến mây trời thành hơi nước, hơi nước thành giọt nước, giọt nước thành mảnh băng, cuối cùng ngưng tụ toàn bộ thành một thanh băng kiếm dài bảy thước, chiều rộng ba tấc, phát ra hàn khí vô tận, mũi kiếm tỏa ánh sáng năm màu. Thần thông này không mang tính công kích trực tiếp hay phòng thủ, mà tập trung vào sự biến hóa và dung hợp vạn vật từ bổn nguyên.","thuocTinh":"Dung hợp / biến đổi bổn nguyên","nguonGoc":"Lam Mộng Đạo Tôn sáng tạo","congNang":["Dung hợp và thay đổi bổn nguyên bản thân @c1244","Hóa một thành ngàn vạn hoặc ngưng tụ ngàn vạn thành một @c1244","Biến đổi hình thái vật chất liên hoàn: mây thành hơi nước, hơi nước thành giọt nước, giọt nước thành mảnh băng, ngưng tụ thành băng kiếm @c1244"],"nguoiTu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1244","tangDatToi":"Đại thành","trangThai":"dang-tu"},{"ten":"Vương Lâm","tuChuong":"@c1244","tangDatToi":"Đang lĩnh ngộ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1244","loai":"xuất hiện","importance":"major","giaiDoan":"Lam Mộng truyền thức thứ ba","text":"Lam Mộng Đạo Tôn thi triển Dung biến đạo thuật cho Vương Lâm xem, biến mây thành băng kiếm bảy thước, thần thông dung hợp thay đổi bổn nguyên bản thân.","anchor":"đạo thuật Dung biến! Thuật này không phải là công kích hay phòng thủ mà là một loại thần thông tiến hành dung hợp thay đổi bổn nguyên bản thân"}]},"nguon":["@c1244"],"dacDiem":"Không thuộc phạm trù công kích hay phòng thủ, chuyên về dung hợp biến hóa bổn nguyên; khi biểu diễn, băng kiếm ngưng tụ dài bảy thước rộng ba tấc, phát hàn khí vô tận, mũi kiếm tỏa ánh sáng năm màu."},{"id":"ho-phong-hoan-vu","name":"Hô Phong Hoán Vũ (dung hợp)","cn":"","loai":"than-thong","loaiLabel":"Thần thông dung hợp","phamCap":"Không rõ","hePhai":"Lục đạo","soHuu":["Vương Lâm"],"blurb":"Hô phong hoán vũ là cụm thần thông xuất hiện trong câu thơ trên bức họa tầng chín Tàng Phẩm Các. Vương Lâm nhận định đây thực chất gồm hai thần thông riêng biệt — Hô Phong và Hoán Vũ (Vũ đạo). Tại mốc @c1244, Lam Mộng Đạo Tôn dung hợp Hô Phong đạo và Vũ đạo của Vương Lâm thành một giới phòng hộ.","detail":"Ở tầng chín Tàng Phẩm Các, Vương Lâm nhìn thấy bức họa kèm câu thơ nhắc đến Hô phong hoán vũ, và nhận định cụm từ này ám chỉ hai thần thông liên quan đến gió và mưa, được cất giữ tại tầng cao nhất. Về sau, Lam Mộng Đạo Tôn đã dung hợp Hô Phong đạo và Vũ đạo mà Vương Lâm nắm giữ lại với nhau, hình thành một giới phòng hộ có lực phòng ngự đáng kể (@c1244).","thuocTinh":"Phong + Thủy / dung hợp","nguonGoc":"Dung hợp hai đạo trong lục đạo tam trọng thuật của Bạch Phàm, Lam Mộng Đạo Tôn dung hợp giúp","congNang":["Hô Phong đạo và Vũ đạo có thể được dung hợp thành một giới phòng hộ, tạo ra lực phòng ngự mạnh (@c1244)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1244","tangDatToi":"Chưa tự dung hợp","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1244","loai":"xuất hiện","importance":"major","giaiDoan":"Lam Mộng dung hợp giúp Vương Lâm","text":"Lam Mộng Đạo Tôn dung hợp Hô Phong đạo và Vũ đạo của Vương Lâm thành một giới phòng hộ, lực phòng hộ tương đương Quang ảnh thuẫn.","anchor":"Hô Phong che trời, Hóa Vũ phủ đất, tự thành một giới"}]},"nguon":["@c1244"],"dacDiem":"Bản chất gồm hai thần thông tách biệt — Hô Phong (đạo gió) và Vũ (đạo mưa) — có thể dung hợp thành giới phòng hộ khi kết hợp."},{"id":"quang-anh-thuan","name":"Quang Ảnh Thuẫn","cn":"光影盾","aliases":["Quang Anh Thuẫn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lam Mộng Đạo Tôn (tam đại thần thông)","soHuu":["Vương Lâm"],"blurb":"Quang Ảnh Thuẫn là thức thần thông thứ hai trong tam đại thần thông do Lam Mộng Đạo Tôn truyền thụ, sở hữu năng lực ngưng tụ hào quang sức sống từ vạn vật để hóa thành thuẫn phòng ngự. Đây là thần thông liên quan mật thiết đến cửa ải bước thứ ba, người có thể cảm nhận được ánh sáng này đã thuộc hàng cực hiếm. (+) Thần thông của Lam Mộng đạo tôn, ngưng tụ hào quang vô tận bên ngoài thân thể hình thành quang ảnh khổng lồ phòng ngự. [CAN-SOAT-GOP]","detail":"Quang Ảnh Thuẫn là thức thần thông thứ hai trong tam đại thần thông mà Lam Mộng Đạo Tôn truyền thụ cho Vương Lâm. Quá trình tu luyện đòi hỏi tản thần thức bao trùm cả tu chân tinh để cảm nhận ánh sáng sức sống tỏa ra từ vạn vật, rồi ngưng tụ hào quang ấy quanh thân hóa quang ảnh khổng lồ. Vương Lâm dành bốn tháng lần mò mà chưa hoàn toàn minh ngộ, phát hiện bức tường ngăn cách bước thứ ba chính là rào cản then chốt trong quá trình cảm ngộ thần thông này. Về sau, Vương Lâm đã thực chiến thi triển Quang Ảnh Thuẫn, liên tiếp sử dụng ba lần trong một hơi thở để đỡ Tuế Nguyệt cấm và chưởng ấn của Tư Mặc Tử, cho thấy thần thông này có thể thi triển nhanh liên hoàn trong thực chiến phòng ngự.","thuocTinh":"Quang/Sức sống","nguonGoc":"Lam Mộng Đạo Tôn truyền thụ","uyLuc":"Thi triển ba lần trong một hơi thở, đủ sức chống đỡ Tuế Nguyệt cấm và chưởng ấn của Tư Mặc Tử @c1292","dacDiem":"Liên quan trực tiếp đến cửa ải bước thứ ba tu luyện; người có thể cảm nhận được ánh sáng sức sống từ vạn vật đã thuộc hàng cực hiếm; cần tản thần thức bao trùm diện rộng để cảm ngộ.","trangThai":"Vương Lâm đang cảm ngộ, chưa đại thành","congNang":["Ngưng tụ hào quang và ánh sáng sức sống từ vạn vật quanh thân @c1245","Ngưng tụ ánh sáng thành thuẫn phòng ngự, chiết xạ phần lớn lực công kích @c1292","Có thể thi triển liên hoàn nhiều lần trong một hơi thở để liên tục phòng ngự @c1292"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1245","tangDatToi":"thi triển ba lần liên tiếp","trangThai":"đang dùng"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm cảm ngộ, phát hiện ánh sáng sức sống nhưng bị bức tường bước thứ ba cản trở","text":"Vương Lâm dành bốn tháng lần mò Quang Ảnh Thuẫn, tản thần thức bao trùm tu chân tinh, nhìn thấy ánh sáng (sức sống) từ vạn vật ngưng tụ quanh thân hóa quang ảnh khổng lồ nhưng chưa hoàn toàn minh ngộ do bức tường ngăn cách bước thứ ba.","anchor":"thức thần thông thứ hai Quang Anh Thuẫn ở bên trên ẩn chứa sức mạnh hào quang ngưng tụ"},{"chuong":"@c1292","loai":"thi triển","importance":"normal","giaiDoan":"Chống Tuế Nguyệt cấm","text":"Vương Lâm dùng Quang ảnh thuẫn ba lần trong một hơi thở để chống Tuế Nguyệt cấm và chưởng ấn của Tư Mặc Tử.","anchor":"Sau ba lần xuất hiện rồi sụp đổ cũng khiến cho lực lượng của chưởng kia vào lực lượng Tuế Nguyệt, chỉết xạ ra hơn phân nửa"}]},"nguon":["@c1245","@c1292","@c1340","@c1347"]},{"id":"dao-tieu-thuat","name":"Đạo Tiêu Thuật","cn":"","loai":"bi-thuat","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"","soHuu":[],"blurb":"Đạo thuật do lão già trong Thất Thải Giới sử dụng, là lần đầu tiên Vương Lâm tiếp xúc đạo thuật, không thể chống cự nếu không có Cực Cảnh và Thiên Nghịch.","detail":"Đạo thuật do lão già trong Thất Thải Giới sử dụng. Vương Lâm hồi tưởng đây là lần đầu tiên hắn tiếp xúc với đạo thuật, không thể chống cự nếu không có Cực Cảnh và Thiên Nghịch.","congNang":["Đạo thuật tấn công, không thể chống cự nếu không có Cực Cảnh và Thiên Nghịch"],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"nhắc tới","importance":"bridge","giaiDoan":"Vương Lâm hồi tưởng lần đầu tiếp xúc đạo thuật","text":"Vương Lâm hồi tưởng Đạo Tiêu là lần đầu tiếp xúc đạo thuật, do lão già Thất Thải Giới sử dụng.","anchor":"sớm nhất là Đạo Tiêu của lão già ở bên trong Thất Thải Giới kia"}]},"nguon":["@c1245"]},{"id":"dao-thuat-rieng-vuong-lam","name":"Đạo thuật riêng của Vương Lâm","cn":"","loai":"bi-thuat","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo thuật Vương Lâm tự ngộ ra trong Đạo Cảnh dưới sự giúp đỡ của chủ nhân Phong Giới, đạo niệm biến hóa thành gợn sóng quỷ dị đả thương vô hình, từng đánh thương trưởng lão Yêu Tông.","detail":"Vương Lâm tự ngộ ra đạo thuật riêng trong Đạo Cảnh dưới sự giúp đỡ của chủ nhân Phong Giới. Đạo niệm biến hóa thành gợn sóng quỷ dị có thể đả thương vô hình, từng đánh thương trưởng lão Yêu Tông.","congNang":["Đạo niệm biến hóa thành gợn sóng quỷ dị, đả thương vô hình"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1245","tangDatToi":"Đã tự ngộ","trangThai":"đang sử dụng"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"nhắc tới","importance":"bridge","giaiDoan":"Hồi tưởng lần thứ hai tiếp xúc đạo thuật","text":"Vương Lâm hồi tưởng đã tự ngộ ra đạo thuật riêng trong Đạo Cảnh, từng đánh thương trưởng lão Yêu Tông.","anchor":"hiểu ra được một đạo thuật của riêng mình"}]},"nguon":["@c1245"]},{"id":"thanh-van-linh-thuat","name":"Thanh Vân Linh Thuật","cn":"青云灵术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Nguyệt Phệ Tộc","soHuu":["Nguyệt Phệ Tộc"],"blurb":"Thanh Vân Linh Thuật là thần thông quỷ dị do đám người thần bí truyền cho Nguyệt Phệ Tộc, cho phép hấp thụ sức mạnh Cổ Thần. Điều kiện tu luyện bắt buộc là phải có Linh Chủng ký sinh trong cơ thể, hệ thống pháp thuật hoàn toàn khác biệt với Thái Cổ Tinh Thần.","detail":"Thanh Vân Linh Thuật là thần thông do đám người thần bí truyền cho Nguyệt Phệ Tộc khi trợ giúp họ nổi loạn chống lại Cổ Thần. Điều kiện bắt buộc để tu luyện là phải có Linh Chủng ký sinh trong cơ thể; hệ thống pháp thuật này hoàn toàn khác biệt so với đường tu Thái Cổ Tinh Thần thông thường. Nguyệt Phệ Tộc nhờ dựa vào thuật này mà trong đại chiến đã nuốt lấy những Cổ Thần tử vong, từ đó phát triển thành đại tộc Thái Cổ Tinh Thần. Vương Lâm biết được sự tồn tại của Thanh Vân Linh Thuật thông qua việc khai thác trí nhớ lão già đốt ngón tay Cổ Thần @c1248.","thuocTinh":"Hấp thu thần tính Cổ Thần","nguonGoc":"Đám người thần bí truyền cho Nguyệt Tộc","yeuCau":"Cần Linh Chủng ký sinh trong cơ thể","congNang":["Hấp thụ sức mạnh Cổ Thần — Nguyệt Phệ Tộc dựa vào công năng này nuốt lấy Cổ Thần tử vong trong đại chiến @c1248"],"dacDiem":"Cần Linh Chủng ký sinh trong cơ thể mới có thể tu luyện; hệ thống pháp thuật hoàn toàn khác biệt với Thái Cổ Tinh Thần.","nguoiTu":[{"ten":"Nguyệt Phệ Tộc","tuChuong":"@c1248","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1248","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ thông tin qua trí nhớ Cổ Thần","text":"Vương Lâm khai thác trí nhớ lão già đốt ngón tay Cổ Thần, biết được đám người thần bí đã truyền Thanh Vân Linh Thuật cho Nguyệt Tộc. Thuật này cho phép hấp thụ sức mạnh Cổ Thần, cần Linh Chủng ký sinh trong cơ thể mới tu luyện được. Nguyệt Phệ Tộc dựa thuật này nuốt Cổ Thần tử vong phát triển thành đại tộc.","anchor":"có thể khiến cho người của Nguyệt Tộc có thể hấp thụ được sức mạnh của Cổ Thần"}]},"nguon":["@c1248"]},{"id":"thien-linh-quang","name":"Thiên Linh Quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Nữ tử áo trắng"],"blurb":"Thần thông hắc quang do phân thân Bạch Y Nữ Tử thi triển, phá tan Hô Phong Hoán Vũ giới nhưng không thương tổn được chiến hồn, có thể ngưng tụ thành trường kiếm đen tấn công.","detail":"Bạch Y Nữ Tử thi triển trong trận chiến với Vương Lâm. Hắc quang bùng lên trong tay, vung ra phá tan Hô Phong Hoán Vũ giới nhưng chiến hồn bên trong không bị thương tổn, công kích bị triệt tiêu bên ngoài giới. Sau đó ngưng tụ hắc quang thành trường kiếm đen phóng về phía Vương Lâm, nhưng bị Quang Ảnh Thuẫn phản chiết xạ ngược lại.","thuocTinh":"Hắc quang","congNang":["Hắc quang phá giới, có thể ngưng tụ thành trường kiếm đen tấn công"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c1249","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1249","loai":"thi triển","importance":"normal","giaiDoan":"Phân thân thi triển trong trận chiến","text":"Bạch Y Nữ Tử thi triển Thiên Linh Quang, hắc quang phá tan Hô Phong Hoán Vũ giới nhưng không thương tổn chiến hồn, sau đó ngưng tụ thành trường kiếm đen tấn công Vương Lâm nhưng bị Quang Ảnh Thuẫn chiết xạ ngược.","anchor":"Thiên Linh Quang! Sát khí trong mắt Bạch Y Nữ Tử lóe lên, tay phải chợt vung về phía chiến hồn bốn phía xung quanh"}]},"nguon":["@c1249"]},{"id":"na-di","name":"Na Di","cn":"挪移","loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":null,"soHuu":["Bạch Y Nữ Tử"],"blurb":"Thần thông di chuyển xuyên tinh không, cho phép thoát khỏi trận chiến trong khoảnh khắc.","detail":"Bạch Y Nữ Tử dùng lần na di cuối cùng trong khí tức trắng sữa để thoát khỏi nắm đấm Vương Lâm, di chuyển tới phía đông Thái Cổ Tinh Thần. Nàng nói đây là lần na di cuối cùng, tới đó sẽ được cứu. Tuy nhiên thân thể nàng dần trong suốt sau khi na di, sắp biến mất hoàn toàn trước khi bị Định Thần Thuật đóng băng.","nguon":["@c1251"]},{"id":"doat-hon-cuop-huong-hoa","name":"Đoạt Hồn / Cướp Hương Hỏa","cn":null,"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":null,"hePhai":null,"soHuu":["Vương Lâm","Lan Phi"],"blurb":"Kỹ thuật dùng huyết kiếm phá nguyên thần để đoạt hồn phách cùng hương hỏa của đối phương.","detail":"Vương Lâm dùng huyết kiếm đâm vào thiên linh Bạch Y Nữ Tử phá hỏng nguyên thần trước khi khí tức trắng sữa trong thân nàng tự hủy, qua đó đoạt được hồn phách và hương hỏa. Hồn phách nữ tử nhập vào Hô Phong Hoán Vũ giới, sức mạnh hương hỏa nồng đậm bị Vương Lâm hấp thụ. Hành động này được mô tả giống cách Viễn Cổ Lan Phi cướp đoạt hương hỏa.","nguon":["@c1251"]},{"id":"loi-dao-thiem-loi-toc","name":"Lôi đạo Thiểm Lôi Tộc","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Lôi đạo","soHuu":["Thiểm Lôi Tộc"],"blurb":"Công pháp tu luyện lôi đạo của toàn bộ Thiểm Lôi Tộc, cho rằng lôi chia lục đạo, tu được tất cả thì phá vỡ thiên địa, lấy bản nguyên lôi có thể phóng lên Niết Kiếp.","detail":"Tất cả tộc nhân Thiểm Lôi Tộc đều tu luyện Lôi đạo. Theo lý luận của họ, lôi chia ra lục đạo, nếu tu được tất cả thì có thể phá vỡ thiên địa. Nhận truyền thừa sấm sét vạn cổ, lấy bản nguyên lôi, có thể phóng lên Niết Kiếp.","congNang":["Tu luyện lôi lục đạo, lấy bản nguyên lôi, đột phá Niết Kiếp"],"thuocTinh":"Lôi","nguonGoc":"Truyền thừa viễn cổ Thiểm Lôi Tộc","tabs":{"tienTrinh":[{"chuong":"@c1252","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu hệ thống tu luyện Thiểm Lôi Tộc","text":"Lôi đạo Thiểm Lôi Tộc được giới thiệu: lôi chia lục đạo, tu được tất cả thì phá vỡ thiên địa, nhận truyền thừa sấm sét vạn cổ, lấy bản nguyên lôi có thể phóng lên Niết Kiếp.","anchor":"lôi chia ra lục đạo, nếu tu được tất cả thì có thể phá vỡ thiên địa"}]},"nguon":["@c1252"]},{"id":"tu-loi-an","name":"Tụ Lôi Ấn","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Lôi đạo","soHuu":["Thiểm Lôi Tộc"],"blurb":"Tụ Lôi Ấn là công pháp tu luyện bản tộc của Thiểm Lôi Tộc, vận hành theo nguyên lý nén lực lượng sấm sét trong cơ thể nhiều lần rồi bùng ra phản lực cực mạnh trong nháy mắt. Vương Lâm nghiên cứu công pháp này thông qua ngọc giản nhằm điều tra tin tức về tộc ấn Thiểm Lôi Tộc, vì mơ hồ cảm nhận việc hấp thu sấm sét bất diệt có ý nghĩa trọng đại đối với con đường tu luyện của hắn.","detail":"Tụ Lôi Ấn là công pháp tu luyện riêng của tộc nhân Thiểm Lôi Tộc, được ghi chép trong ngọc giản. Cốt lõi của công pháp nằm ở việc nén lực lượng sấm sét bên trong cơ thể lại nhiều lần, sau đó bùng phát toàn bộ phản lực cực mạnh chỉ trong nháy mắt. Việc tu luyện Tụ Lôi Ấn đòi hỏi phải phối hợp với tộc ấn, đồng thời cần quá trình tu luyện lâu dài mới có thể mở được tộc ấn. Vương Lâm tiếp xúc với công pháp này khi đọc ngọc giản chứa nội dung Tụ Lôi Ấn; mục đích thực sự của hắn không chỉ là nghiên cứu bản thân công pháp mà là điều tra tin tức liên quan đến tộc ấn của Thiểm Lôi Tộc, bởi hắn mơ hồ cảm giác rằng việc hấp thu sấm sét bất diệt cực kỳ quan trọng đối với con đường tu luyện của mình. @c1256","thuocTinh":"Lôi","nguonGoc":"Công pháp bản tộc Thiểm Lôi Tộc","dacDiem":"Nén sấm sét nhiều lần, bùng phản lực cực mạnh trong nháy mắt; cần phối hợp tộc ấn và tu luyện lâu dài mới mở được tộc ấn.","congNang":["Nén lực lượng sấm sét trong cơ thể lại nhiều lần rồi bùng ra phản lực cực mạnh trong nháy mắt @c1256"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1256","tangDatToi":"Đang nghiên cứu","trangThai":"dang-hoc"}],"tabs":{"tienTrinh":[{"chuong":"@c1256","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm bắt đầu nghiên cứu","text":"Vương Lâm đọc ngọc giản chứa công pháp Tụ Lôi Ấn của Thiểm Lôi Tộc, mục đích thực sự là điều tra tộc ấn vì mơ hồ cảm giác hấp thu sấm sét bất diệt cực kỳ quan trọng.","anchor":"Mục đích Vương Lâm nghiên cứu công pháp này chính là điều tra những tin tức liên quan đến tộc ấn của Thiểm Lôi Tộc"}]},"nguon":["@c1256"]},{"id":"toc-an-thiem-loi-toc","name":"Tộc ấn Thiểm Lôi Tộc","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Cơ chế","phamCap":"Không rõ","hePhai":"Thiểm Lôi Tộc","soHuu":["Thiểm Lôi Tộc"],"blurb":"Tộc ấn Thiểm Lôi Tộc là ký hiệu khắc trên mi tâm mỗi tộc nhân Thiểm Lôi Tộc, thực chất là một cơ chế hương hỏa — tộc nhân nhận ký hiệu, tu luyện sấm sét suốt đời, rồi khi chết toàn bộ tính mạng và sấm sét đều bị hấp thu trở lại cho sấm sét bất diệt. Bên trong tộc ấn ẩn giấu một ý chí đang ngủ say, dung nhập vào linh hồn nên không dễ phá hủy.","detail":"Tộc ấn là ký hiệu gốc của Thiểm Lôi Tộc, bắt nguồn từ sấm sét bất diệt, được truyền xuống dưới dạng ký hiệu nhánh trên mi tâm từng tộc nhân. Vương Lâm sau hơn một tháng nghiên cứu đã phát hiện bản chất thực sự của tộc ấn: bên trong ẩn giấu một ý chí đang ngủ say, ý chí này thường trực hấp thu lực lượng sấm sét từ ký hiệu nhánh trên mi tâm tộc nhân. Cơ chế vận hành cực kỳ giống Môn Đồ Hương Hỏa — tộc nhân tiếp nhận ký hiệu, tu luyện sấm sét cả đời, nhưng khi qua đời thì toàn bộ tính mạng và sấm sét tích lũy được đều bị dâng ngược trở lại cho sấm sét bất diệt. Do ký hiệu đã dung nhập sâu vào linh hồn, dù bị cưỡng chế rút ra vẫn lưu lại dấu vết, khiến nó gần như không thể bị xóa bỏ hoàn toàn.","thuocTinh":"Lôi","nguonGoc":"Sấm sét bất diệt của Thiểm Lôi Tộc","dacDiem":"Ẩn giấu ý chí ngủ say bên trong, dung nhập vào linh hồn tộc nhân nên không dễ phá hủy; cơ chế vận hành giống Môn Đồ Hương Hỏa — tộc nhân tu luyện sấm sét cả đời rồi khi chết bị thu hồi tất cả về cho sấm sét bất diệt.","congNang":["Cấp sấm sét cho tộc nhân tu luyện thông qua ký hiệu nhánh trên mi tâm @c1257","Hấp thu lại toàn bộ tính mạng và sấm sét khi tộc nhân chết, dâng về cho sấm sét bất diệt @c1257","Ẩn giấu ý chí ngủ say bên trong, thường trực hấp thu lực lượng sấm sét từ tộc nhân @c1257","Dung nhập vào linh hồn tộc nhân, dù bị rút ra vẫn còn dấu vết, không dễ phá hủy @c1257"],"tabs":{"tienTrinh":[{"chuong":"@c1257","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Vương Lâm phát hiện bản chất hương hỏa","text":"Vương Lâm nghiên cứu hơn một tháng, phát hiện ý chí ẩn giấu bên trong tộc ấn, xác nhận cơ chế hương hỏa giống Môn Đồ Hương Hỏa.","anchor":"Vấn đề này và Môn Đồ Hương Hỏa.Cực kỳ giống nhau!"}]},"nguon":["@c1257"]},{"id":"hoa-loi-vi-vu","name":"Hóa Lôi Vi Vụ","cn":"化雷为雾","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt học thất truyền","hePhai":"Lôi đạo","soHuu":["Vương Lâm"],"blurb":"Hóa Lôi Vi Vụ là tuyệt học cổ xưa đã thất truyền của Thiểm Lôi Tộc, lấy sấm sét làm nền tảng hóa thành sương mù, vừa có thể phòng hộ vừa có thể giam cầm, biến hóa vô cùng giữa vô hình và hữu hình. Vương Lâm là người đầu tiên trong lịch sử tự học được thuật này nhờ nguyên thần chứa luồng sấm sét bất diệt, khi lợi dụng khe nứt sương mù bộc lộ cấu trúc mà dùng thần thức sấm sét xâm nhập áp chế rồi thôi diễn ngược lại.","detail":"Hóa Lôi Vi Vụ là thuật đại thần thông cổ xưa của Thiểm Lôi Tộc, vận hành bằng cách hút sấm sét từ Lôi vực rồi bóp nát thành sương mù. Sương mù sấm sét có thể dàn rộng thành vòng phòng hộ hoặc co rút lại tạo giam cầm, biến hóa linh hoạt giữa trạng thái vô hình và hữu hình. Hiệu quả của thuật này mơ hồ tương tự thuật Hô Phong Hoán Vũ, nhưng dùng sấm sét làm nền tảng thay vì phong vũ. Thuật đã thất truyền trong Thiểm Lôi Tộc từ lâu. Vương Lâm lợi dụng khe nứt mở ra khiến cấu trúc sương mù sấm sét bộc lộ, dùng thần thức sấm sét xâm nhập áp chế hoàn toàn, rồi thôi diễn ngược lại mà tự lĩnh ngộ — trở thành người đầu tiên trong lịch sử làm được điều này, nhờ nguyên thần vốn chứa luồng sấm sét bất diệt.","thuocTinh":"Lôi","nguonGoc":"Tuyệt học cổ xưa của Thiểm Lôi Tộc, đã thất truyền","uyLuc":"Sấm sét hóa sương mù phòng hộ và giam cầm, biến hóa vô cùng, khi bộc lộ cấu trúc cần thần thức sấm sét bậc cực cao mới có thể xâm nhập áp chế hoàn toàn.","dacDiem":"Tương tự thuật Hô Phong Hoán Vũ về hiệu quả, nhưng lấy sấm sét làm nền tảng thay vì phong vũ; đã thất truyền trong Thiểm Lôi Tộc, Vương Lâm là người đầu tiên trong lịch sử tự học được nhờ nguyên thần chứa luồng sấm sét bất diệt.","trangThai":"Vương Lâm vừa học được","congNang":["Sấm sét hóa thành sương mù, dàn rộng tạo vòng phòng hộ","Co rút sương mù sấm sét tạo giam cầm","Biến hóa vô cùng giữa trạng thái vô hình và hữu hình"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1259","tangDatToi":"Mới học","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1259","loai":"tái hiện","importance":"major","giaiDoan":"Thất truyền được Vương Lâm tái hiện","text":"Vương Lâm lợi dụng khe nứt sương mù sấm sét bộc lộ cấu trúc, dùng thần thức sấm sét xâm nhập áp chế hoàn toàn rồi thôi diễn ngược lại, tự học được tuyệt học thất truyền này — là người đầu tiên trong lịch sử Thiểm Lôi Tộc.","anchor":"học được một trong những tuyệt học thất truyền của Thiểm Lôi Tộc, Hóa Lôi Vi Vụ"}]},"capNhatToi":"@c1259","nguon":["@c1259"]},{"id":"loi-luc-dao","name":"Lôi Lục Đạo","cn":"雷六道","loai":"khac","loaiLabel":"Hệ thống lý luận","phamCap":"Không rõ","hePhai":"Thiểm Lôi Tộc","soHuu":["Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Lôi Lục Đạo là hệ thống phân loại toàn bộ sấm sét trong thiên địa thành sáu đạo, do tổ tiên Thiểm Lôi Tộc nghiên cứu phát hiện. Nếu có thể hấp thu và luyện hóa trọn vẹn cả sáu loại sấm sét, người tu luyện sẽ đạt được sức mạnh lôi lực quỷ thần khó lường.","detail":"Tổ tiên Thiểm Lôi Tộc sau quá trình nghiên cứu đã phát hiện sấm sét trong thiên địa có thể phân thành sáu đạo theo thứ tự: Thiên Uẩn Lôi, Địa Dung Lôi, Nguyên Hóa Lôi, Từ Xá Lôi, Đạo Ý Lôi và Linh Niệm Lôi. Lão già Dương Thực tại cửa đông Lôi Tinh Điện là người tiết lộ hệ thống này cho Vương Lâm @c1260. Lôi Lục Đạo ẩn tàng trong khe nứt nguyên thần của Vương Lâm; khi bộc phát, nó lao ra phát hào quang cùng lôi quang mãnh liệt, đồng thời có khả năng triệu xuất và luyện hóa lôi lực tích lũy của Thiểm Lôi Tộc @c1281.","congNang":["Phân loại toàn bộ sấm sét trong thiên địa thành sáu đạo: Thiên Uẩn Lôi, Địa Dung Lôi, Nguyên Hóa Lôi, Từ Xá Lôi, Đạo Ý Lôi, Linh Niệm Lôi @c1260","Hấp thu và luyện hóa toàn bộ sáu loại sấm sét, đạt sức mạnh lôi lực quỷ thần khó lường @c1260","Triệu xuất và luyện hóa lôi lực tích lũy của Thiểm Lôi Tộc @c1281","Bộc phát từ khe nứt nguyên thần, phóng hào quang và lôi quang mãnh liệt @c1281"],"cacTang":[{"ten":"Thiên Uẩn Lôi","moTa":"Loại thứ nhất","chuong":"@c1260"},{"ten":"Địa Dung Lôi","moTa":"Loại thứ hai","chuong":"@c1260"},{"ten":"Nguyên Hóa Lôi","moTa":"Loại thứ ba","chuong":"@c1260"},{"ten":"Từ Xá Lôi","moTa":"Loại thứ tư","chuong":"@c1260"},{"ten":"Đạo Ý Lôi","moTa":"Loại thứ năm","chuong":"@c1260"},{"ten":"Linh Niệm Lôi","moTa":"Loại thứ sáu và cuối cùng, sinh ra từ cơ thể tu sĩ thiên tài trong bảy trăm vạn thiên địa khi thiên kiếp hàng lâm","chuong":"@c1260"}],"tabs":{"tienTrinh":[{"chuong":"@c1260","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu tiết lộ","text":"Lão già Dương Thực cửa đông Lôi Tinh Điện tiết lộ cho Vương Lâm: tổ tiên Thiểm Lôi Tộc nghiên cứu phát hiện sấm sét chia làm sáu loại, hấp thu toàn bộ đạt lực lượng quỷ thần khó lường.","anchor":"Lôi chia Lục đạo có thứ tự là Thiên Uẩn Lôi, Địa Dung Lôi, Nguyên Hóa Lôi, Từ Xá Lôi, Đạo Ý Lôi và cuối cùng là Linh Niệm Lôi"},{"chuong":"@c1281","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu được Vương Lâm triệu xuất trong đợt này","text":"Lôi Lục đạo lao ra từ khe nứt trong nguyên thần Vương Lâm, phát ra hào quang và lôi quang khiến hắn phải lập tức chuyển nơi luyện hóa.","anchor":"Lôi lục đạo đã được Thiểm Lôi tộc sưu tập cả vài vạn năm vì vậy mà rất hùng mạnh"}]},"nguon":["@c1260","@c1281"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1281","tangDatToi":"đang luyện hóa","trangThai":"dang-tu"}],"uyLuc":"Nếu luyện hóa trọn vẹn cả sáu đạo sấm sét sẽ đạt được lực lượng quỷ thần khó lường; khi bộc phát từ nguyên thần phóng hào quang cùng lôi quang cực kỳ mãnh liệt.","dacDiem":"Ẩn tàng trong khe nứt nguyên thần người tu luyện, phân chia sấm sét thiên địa thành sáu đạo rõ ràng theo hệ thống do tổ tiên Thiểm Lôi Tộc sáng lập."},{"id":"linh-niem-loi","name":"Linh Niệm Lôi","cn":"灵念雷","loai":"khac","loaiLabel":"Loại sấm sét","phamCap":"Không rõ","hePhai":"Thiểm Lôi Tộc","soHuu":["Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Linh Niệm Lôi là loại sấm sét thứ sáu và cuối cùng trong Lôi Lục Đạo, đồng thời là loại duy nhất được sinh ra từ sinh mệnh tu sĩ. Nó ngưng tụ khi tu sĩ tư chất kinh người tại cảnh giới Hóa Thần đỉnh phong bị thiên kiếp hủy diệt hình thần, chuyển hóa toàn bộ sinh mệnh thành sấm sét. Toàn bộ Linh Niệm Lôi do Thiểm Lôi Tộc tích lũy nhiều năm đã bị Vương Lâm hấp thu, tăng cường nguyên thần sấm sét và lôi tu của hắn.","detail":"Linh Niệm Lôi là loại sấm sét đặc biệt nhất trong Lôi Lục Đạo, đồng thời là loại duy nhất được sinh ra từ sinh mệnh tu sĩ. Chữ \"linh\" đại biểu cho vạn linh. Trong bảy trăm vạn thiên địa, những tu sĩ tư chất kinh người khi đạt tới Hóa Thần đỉnh phong sẽ bị thiên kiếp hàng lâm; trong cơ thể họ sinh ra một loại lực lượng quỷ dị. Bề ngoài, đồng đạo coi đó là độ kiếp thành công, nhưng thực chất hình thần câu diệt, toàn bộ sinh mệnh chuyển hóa thành Linh Niệm Lôi. Bản chất của quá trình ngưng tụ này được ngọc giản nhiệm vụ cửa tây tiết lộ. Linh Niệm Lôi chính là sản vật của thiên kiếp hủy diệt hình thần tu sĩ, được Thiểm Lôi Tộc thu hoạch và tích lũy qua nhiều năm. Về sau, toàn bộ Linh Niệm Lôi mà Thiểm Lôi Tộc tích lũy đã bị Vương Lâm hấp thu, giúp nguyên thần sấm sét và lôi tu của hắn được tăn","congNang":["Ngưng tụ từ sinh mệnh tu sĩ thiên tài trong bảy trăm vạn thiên địa khi bị thiên kiếp hủy diệt hình thần tại cảnh giới Hóa Thần đỉnh phong, chuyển hóa toàn bộ hình thần thành sấm sét @c1260","Tăng cường nguyên thần sấm sét và lôi tu của người hấp thu @c1281"],"tabs":{"tienTrinh":[{"chuong":"@c1260","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lần đầu tiết lộ bản chất","text":"Ngọc giản nhiệm vụ cửa tây tiết lộ: tu sĩ thiên tài trong bảy trăm vạn thiên địa ngưng tụ Linh Niệm Lôi khi độ kiếp, tưởng thành công nhưng thực ra hình thần câu diệt, hóa thành Linh Niệm Lôi cho Thiểm Lôi Tộc.","anchor":"trong cơ thể sinh ra một luồng lực lượng cực kỳ quỷ dị"},{"chuong":"@c1281","loai":"thi triển","importance":"normal","giaiDoan":"Bị Vương Lâm hấp thu","text":"Toàn bộ Linh Niệm lôi Thiểm Lôi tộc tích lũy nhiều năm bị Vương Lâm hấp thu, khiến nguyên thần sấm sét và lôi tu của hắn tăng mạnh.","anchor":"tất cả Linh Niệm lôi được Thiểm Lôi tộc kiếm đựoc trong rất nhiều năm qua đã bị Vương Lâm hấp thu toàn bộ"}]},"nguon":["@c1260","@c1281"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1281","tangDatToi":"hấp thu toàn bộ phần tích lũy của Thiểm Lôi tộc","trangThai":"da-tu"}],"dacDiem":"Là loại sấm sét duy nhất trong Lôi Lục Đạo được sinh ra từ sinh mệnh tu sĩ; chữ \"linh\" đại biểu cho vạn linh, bản chất là sản vật của quá trình thiên kiếp hủy diệt hình thần tu sĩ tư chất kinh người tại cảnh giới Hóa Thần đỉnh phong."},{"id":"loi-long-hoa-than","name":"Lôi Long hóa thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi đạo","soHuu":["Chu Thiên Tử"],"blurb":"Thần thông Khuy Niết của Chu Thiên Tử — vỗ mi tâm phóng ký hiệu, toàn thân tràn đầy sấm sét hóa thành Lôi Long kết hợp sóng âm thôn phệ đối thủ.","detail":"Chu Thiên Tử vỗ mi tâm phóng ký hiệu, toàn thân tràn đầy lực lượng sấm sét hóa thành Lôi Long, kết hợp sóng âm và sấm sét thành lực lượng mạnh nhất cấp Khuy Niết. Bị Vương Lâm (tu vi vượt Toái Niết) phá tan chỉ bằng một vung tay.","thuocTinh":"Lôi","nguonGoc":"Thiểm Lôi Tộc (suy đoán từ Chu Thiên Tử)","uyLuc":"Toàn lực cấp Khuy Niết, bị phá bởi tu sĩ vượt Toái Niết chỉ một vung tay","dacDiem":"Hóa toàn thân thành Lôi Long sấm sét, kết hợp sóng âm","congNang":["Hóa thành Lôi Long toàn thân sấm sét thôn phệ đối thủ"],"nguoiTu":[{"ten":"Chu Thiên Tử","tuChuong":"@c1261","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1261","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu","text":"Chu Thiên Tử toàn lực thi triển Lôi Long hóa thân tấn công Vương Lâm trong con đường bảy trăm vạn thiên địa, bị phá tan chỉ một vung tay.","anchor":"toàn thân Chu Thiên Tử tràn đầy lực lượng sấm sét giống như hóa thành một Lôi long"}]},"nguon":["@c1261"]},{"id":"than-thong-anh-mat-vuong-lam","name":"Thần thông ánh mắt (Vương Lâm)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông ánh mắt là thuật công kích đặc biệt của Vương Lâm, dung nhập thần thông vào ánh mắt để tấn công trực tiếp đối phương. Tại chương 1262, thuật này được thi triển lên Chu Thiên Tử, kích nổ toàn bộ sấm sét bên trong cơ thể lão, phá tan nguyên thần và thân xác cùng lúc.","detail":"Vương Lâm dung nhập thần thông vào ánh mắt, biến ánh nhìn thành phương tiện công kích trực tiếp. Cơ chế hoạt động tựa như phóng sấm sét và lửa qua ánh mắt vào cơ thể đối phương. Trong trận chiến với Chu Thiên Tử, Vương Lâm sử dụng thần thông này để kích nổ toàn bộ sấm sét mà lão đã tu luyện tích lũy suốt mấy ngàn năm ngay bên trong cơ thể, đồng thời phá hủy cả nguyên thần lẫn thân thể của đối phương. @c1262","congNang":["Công kích trực tiếp qua ánh mắt, dung nhập thần thông vào tầm nhìn để tấn công @c1262","Kích nổ toàn bộ sấm sét bên trong cơ thể đối phương, phá tan nguyên thần và thân xác cùng lúc @c1262"],"tabs":{"tienTrinh":[{"chuong":"@c1262","loai":"thi triển","importance":"major","giaiDoan":"Giết Chu Thiên Tử","text":"Vương Lâm dùng thần thông ánh mắt kích nổ toàn bộ sấm sét trong cơ thể Chu Thiên Tử, phá tan nguyên thần và thân xác lão.","anchor":"Ánh mắt Vương Lâm giống như ngọn lửa mang theo sấm động kinh thiên"}]},"dinhDanh":"goc","capNhatToi":"@c1262","nguon":["@c1262"],"uyLuc":"Kích nổ toàn bộ sấm sét tu luyện mấy ngàn năm bên trong cơ thể Chu Thiên Tử, phá tan đồng thời cả nguyên thần lẫn thân thể đối phương. @c1262","dacDiem":"Thần thông được dung nhập vào ánh mắt thay vì phóng chiêu thức thông thường, biến ánh nhìn thành vũ khí công kích, có khả năng kích hoạt lực lượng sẵn có bên trong cơ thể đối phương để tự hủy diệt từ bên trong."},{"id":"sam-set-gia-thien-kiep","name":"Sấm sét giả thiên kiếp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi đạo Thiểm Lôi Tộc","soHuu":["Trương Cảnh Vân","Tu sĩ họ Chu"],"blurb":"Thần thông của tu sĩ Thiểm Lôi Tộc, huyễn hóa sấm sét thành hình thái giống thiên kiếp để tấn công tu sĩ hạ giới, tự coi mình là thiên đạo.","detail":"Tu sĩ Thiểm Lôi Tộc bấm pháp quyết huyễn hóa sấm sét thành thiên kiếp giả đánh xuống, mục đích kích thích tu sĩ sinh ra Linh Niệm Lôi. Trương Cảnh Vân và tu sĩ họ Chu đều sử dụng thần thông này trong bảy trăm vạn thiên địa.","congNang":["Huyễn hóa sấm sét thành thiên kiếp giả đánh xuống tu sĩ"],"nguoiTu":[{"ten":"Trương Cảnh Vân","tuChuong":"@c1264","tangDatToi":"","trangThai":"tu-vong"},{"ten":"Tu sĩ họ Chu","tuChuong":"@c1264","tangDatToi":"","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c1264","loai":"thi triển","importance":"normal","giaiDoan":"Trương Cảnh Vân và tu sĩ họ Chu thi triển","text":"Trương Cảnh Vân dùng sấm sét giả thiên kiếp tấn công Vương Lâm với vẻ khinh miệt, bị siết chết. Tu sĩ họ Chu dùng sấm sét giết hai tu sĩ Anh Biến.","anchor":"hai tay bấm pháp quyết rồi huyễn hóa ra sấm sét giống như thiên kiếp"}]},"nguon":["@c1264"]},{"id":"loi-ban-nguyen-tu-luyen-phap","name":"Lôi bản nguyên tu luyện pháp","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ (cấp Đệ Tam Bộ đại năng)","hePhai":"Lôi đạo","soHuu":["Vương Lâm"],"blurb":"Lôi bản nguyên tu luyện pháp là con đường tu luyện lôi pháp chân chính xuất phát từ ký ức thái cổ của lôi bản nguyên, được kích hoạt khi Linh Niệm Lôi dung nhập nguyên thần Vương Lâm. Công pháp yêu cầu hấp thu đủ chín loại sấm sét khác biệt cộng thêm lôi bản nguyên thành mười luồng viên mãn để đại thành, cho phép đột phá từ Đệ Nhị Bộ lên Đệ Tam Bộ đại năng.","detail":"Ký ức thái cổ từ lôi bản nguyên — vốn tồn tại từ thuở thiên địa sơ khai — tiết lộ rằng lôi không chỉ có Lục đạo như Thiểm Lôi Tộc vẫn biết mà thực tế có Cửu đạo. Chín loại sấm sét khác biệt quấn quanh nhau tạo đồ án quái dị, lôi bản nguyên xoay tròn bên trong. Con đường tu luyện chân chính đòi hỏi hấp thu đủ cả chín loại sấm sét cộng thêm lôi bản nguyên thành mười luồng viên mãn thì mới đại thành. Thiểm Lôi Tộc chỉ nắm được sáu đạo, hoàn toàn không hay biết ba đạo còn lại, nên chưa từng có ai trong tộc đạt tới cảnh giới đại thành thực sự. Vương Lâm nhờ Linh Niệm Lôi dung nhập nguyên thần mà tiếp nhận được ký ức này, đồng thời Linh Niệm Lôi chính là loại sấm sét thứ chín mà hắn hấp thu, còn thiếu tám loại nữa mới đủ điều kiện viên mãn. Lôi bản nguyên của Vương Lâm có bản chất giống sấm sét ","thuocTinh":"Lôi","nguonGoc":"Ký ức lôi bản nguyên từ thuở thiên địa sơ khai, truyền vào nguyên thần khi Linh Niệm Lôi dung nhập","yeuCau":"Sở hữu lôi bản nguyên","uyLuc":"Đại thành lôi bản nguyên đủ sức đột phá từ Đệ Nhị Bộ thành Đệ Tam Bộ đại năng.","dacDiem":"Thiểm Lôi Tộc chỉ biết lôi chia Lục đạo, thực tế có Cửu đạo; lôi bản nguyên của Vương Lâm có bản chất giống sấm sét bất diệt, đã tồn tại từ sớm trước khi con đường tu luyện này được tiết lộ.","cacTang":[{"ten":"Loại thứ chín — Linh Niệm Lôi","moTa":"Đã hấp thu, dung nhập nguyên thần khai mở ký ức thái cổ.","chuong":"@c1265"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1265","tangDatToi":"Đã hấp thu loại thứ 9, thiếu 8","trangThai":"dang-tu"}],"congNang":["Kích hoạt ký ức thái cổ của lôi bản nguyên từ thuở thiên địa sơ khai, tiết lộ chân tướng Cửu đạo lôi mà Thiểm Lôi Tộc không biết @c1265","Hấp thu đủ chín loại sấm sét khác biệt cộng lôi bản nguyên thành mười luồng viên mãn thì đại thành @c1265","Đại thành lôi bản nguyên cho phép đột phá Đệ Nhị Bộ lên Đệ Tam Bộ đại năng @c1265"],"tabs":{"tienTrinh":[{"chuong":"@c1265","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Khai mở ký ức, lộ bí mật Cửu đạo lôi","text":"Linh Niệm Lôi dung nhập nguyên thần Vương Lâm, kích hoạt ký ức lôi bản nguyên thái cổ tiết lộ con đường tu luyện chín loại sấm sét cộng bản nguyên thành mười viên mãn.","anchor":"chín loại tia chớp khác biệt quấn quanh lấy nhau, dung hợp vào nhau tạo thành một đồ án cực kỳ quái dị"}]},"capNhatToi":"@c1265","dinhDanh":"goc","nguon":["@c1265"]},{"id":"gio-bao-sam-set","name":"Gió bão sấm sét","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lôi đạo","soHuu":["Vương Lâm"],"blurb":"Vương Lâm hóa thân thành gió bão sấm sét phạm vi vạn trượng, gương mặt khổng lồ giấu bên trong, quét sạch mọi tu sĩ gặp trên đường.","detail":"Thần thông chiến đấu diện rộng: hóa thành gió bão sấm sét bao phủ phạm vi vạn trượng tinh không, bên trong lộ gương mặt khổng lồ. Uy lực cực mạnh, từ tu sĩ Vấn Đỉnh đến Khuy Niết Tịnh Niết đều không thể phản kháng, hình thần câu diệt.","congNang":["Hóa thân gió bão sấm sét phạm vi vạn trượng, diệt tu sĩ từ Vấn Đỉnh đến Khuy Niết/Tịnh Niết không thể kháng cự"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1265","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1265","loai":"thi-trien","importance":"normal","giaiDoan":"Tàn sát tu sĩ Thiểm Lôi Tộc","text":"Vương Lâm hóa gió bão sấm sét vạn trượng quét sạch hơn ngàn tu sĩ Thiểm Lôi Tộc trong vài ngày, từ Vấn Đỉnh đến Khuy Niết đều hình thần câu diệt.","anchor":"gió bão bao phủ tinh không, bên trong lộ ra một gương mặt khổng lồ, đó chính là Vương Lâm"}]},"capNhatToi":"@c1265","dinhDanh":"goc","nguon":["@c1265"]},{"id":"thuat-tan-linh","name":"Thuật Tán Linh","cn":"散灵术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không","soHuu":["Tán Linh"],"blurb":"Thần thông do Tán Linh tự sáng tạo, đem tu vi dung nhập vào cơ thể con người tạo phân thân để tránh thiên kiếp.","detail":"Tán Linh tự ngộ ra thần thông này: đem tu vi vượt quá Hóa Thần dung nhập vào cơ thể con người, tạo phân thân, mỗi phân thân chứa một phần tu vi. Nhờ đó tu vi tăng trưởng mà không dẫn đến thiên kiếp. Cực hạn là 971 phân thân. Khi đạt giới hạn, mỗi phân thân hợp vào chủ thể rồi lại tán linh ra 871 phân thân khác, cứ lặp lại chu trình hợp–tán liên tục. Bằng phương pháp này, Tán Linh tu từ Hóa Thần qua Vấn Đỉnh, Tịnh Niết rồi đạt Toái Niết. Phân thân nhỏ nhất cuối cùng cũng đạt Tịnh Niết hoặc Khuy Niết.","nguon":["@c1267"]},{"id":"than-thong-an-than-tan-linh","name":"Thần thông ẩn thân của Tán Linh","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không","soHuu":["Tán Linh"],"blurb":"Thần thông che giấu thân thể xuất thần nhập hóa, cho phép phân thân xâm nhập tinh không mà không bị phát hiện.","detail":"Thần thông ẩn thân được truyền thừa từ rất lâu, cho phép phân thân che giấu thân thể đạt mức xuất thần nhập hóa. Kể cả tu sĩ Thiên Nhân Đệ Tứ Suy cũng không nhận ra — thanh niên đầu láng (phân thân Tán Linh) từng theo dõi một tu sĩ cảnh giới đó suốt mấy tháng mà không bị phát hiện. Tuy nhiên Vương Lâm vẫn chỉ ra ngay chỗ hắn ẩn giấu.","nguon":["@c1267"]},{"id":"tran-phap-truyen-tong-bay-tram-van","name":"Trận pháp truyền tống (bảy trăm vạn thiên địa → Thiểm Lôi Tộc)","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiểm Lôi Tộc","soHuu":["Thiểm Lôi Tộc"],"blurb":"Trận pháp khổng lồ tại quảng trường trung tâm bảy trăm vạn thiên địa, dùng truyền tống tu sĩ về Thiểm Lôi Tộc.","detail":"Trận pháp truyền tống nằm bên cạnh tòa đại điện cao ngất tại quảng trường trung tâm mảng đại lục. Dùng để vận chuyển tu sĩ từ bảy trăm vạn thiên địa về Thiểm Lôi Tộc. Bị Vương Lâm cưỡng bức xé rách khi đang vận chuyển để tiến vào, gây kinh hoàng cho tu sĩ Thiểm Lôi Tộc và hơn mười người đang được truyền tống.","congNang":["Truyền tống tu sĩ từ bảy trăm vạn thiên địa về Thiểm Lôi Tộc"],"tabs":{"tienTrinh":[{"chuong":"@c1268","loai":"dùng","importance":"normal","giaiDoan":"Bị Vương Lâm phá","text":"Vương Lâm cưỡng bức xé rách trận pháp đang vận chuyển để tiến vào, gây kinh hoàng cho tu sĩ xung quanh.","anchor":"dưới tiếng nổ kinh thiên, trận pháp đang vận chuyển lập tức bị xé ra một lổ hổng"}]},"nguon":["@c1268"]},{"id":"thai-co-loi-gioi","name":"Thái Cổ Lôi Giới","cn":"太古雷界","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Gần tiếp cận Đệ Tam Bộ đại năng","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Thần thông cốt lõi Thiểm Lôi Tộc, mở lôi giới thái cổ triệu hoán hồn phách Thái Cổ Lôi Long trưởng thành đã chết từ thời thái cổ.","detail":"Đại trưởng lão dùng máu tu vi Thiên Nhân Đệ Ngũ Suy làm vật dẫn, thi triển thần thông mở Thái Cổ Lôi Giới, triệu hoán hồn phách tám con Thái Cổ Lôi Long trưởng thành. Tám con lôi long mỗi con dài hơn vạn trượng, đồng thời khống chế toàn bộ sấm sét trong tinh không, khiến Vương Lâm mất quyền điều khiển sấm sét. Thần thông này gần tiếp cận Đệ Tam Bộ đại năng, cần rút lực hương hỏa để thi triển.","nguon":["@c1270"]},{"id":"sinh-menh-than-thong","name":"Sinh Mệnh Thần Thông","cn":"生命神通","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chỉ Thiên Nhân Đệ Ngũ Suy thi triển được","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Hy sinh thọ nguyên bản thân, tản ra sinh cơ để cưỡng chế thúc đẩy thần thông, phát huy khí tức Đệ Tam Bộ đại năng.","detail":"Đại trưởng lão hy sinh 500 năm thọ nguyên, triệu ra la bàn khổng lồ hấp thu sinh cơ, sau đó rút một luồng sấm sét bất diệt từ miếu thờ thánh địa phá tan bảy vạn tầng lưới sấm sét của Vương Lâm trong nháy mắt. Đây là nguyên nhân Thiên Nhân Đệ Ngũ Suy là cường giả duy nhất dưới Đệ Tam Bộ — chỉ cảnh giới này mới có đủ sinh cơ thọ nguyên để đánh đổi. Đại giá: giảm thọ nguyên vĩnh viễn.","nguon":["@c1270"]},{"id":"hon-don-bat-diet-loi","name":"Hồn Độn Bất Diệt Lôi","cn":"混沌不灭雷","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Bộ đại năng cấp","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Tên gọi khi đại trưởng lão kết hợp Sinh Mệnh Thần Thông với tế tổ, rút luồng sấm sét bất diệt từ miếu thờ thánh địa hóa thành lôi công hủy diệt.","detail":"Đại trưởng lão hiến tế sinh cơ 500 năm thọ nguyên đổi lấy thánh thể, thỉnh thánh lôi chuyển lên người, hóa thành Hồn Độn Bất Diệt Lôi. Luồng sấm sét này phá tan bảy vạn tầng lưới sấm sét tự khôi phục của Vương Lâm trong nháy mắt, uy lực đạt cấp Đệ Tam Bộ đại năng.","nguon":["@c1270"]},{"id":"y-chi-sam-set","name":"Ý chí sấm sét","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Ẩn giấu ý chí trong sấm sét, không chỉ tổn thương nguyên thần mà còn khống chế nguyên thần đối phương.","detail":"Đại trưởng lão ẩn giấu ý chí trong mỗi luồng sấm sét do lôi long hóa thành. Ý chí này không chỉ tổn thương nguyên thần đối phương mà còn có thể điều khiển nguyên thần. Dùng tuyên ngôn lấy danh nghĩa đại trưởng lão để tái chiếm quyền điều khiển toàn bộ lôi long bị đối thủ cướp quyền, đánh Vương Lâm liên tục lui.","nguon":["@c1270"]},{"id":"luoi-sam-set-bay-van-tang","name":"Lưới sấm sét bảy vạn tầng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bảy vạn tầng lưới sấm sét ẩn giấu ý chí, tự khôi phục sau khi bị xé, ngăn chặn tu sĩ sấm sét tiếp cận.","detail":"Sau khi nguyên thần tiến hóa thành lôi nguyên thần viên mãn, Vương Lâm vung tay tạo ra bảy vạn tầng lưới sấm sét bao phủ thân thể. Lưới ẩn giấu ý chí của Vương Lâm, bị xé nát vẫn tự khôi phục. Tu sĩ sấm sét trừ khi có thể đối kháng được lôi bản nguyên của Vương Lâm, nếu không sẽ không thể phá vỡ. Cuối cùng bị Hồn Độn Bất Diệt Lôi phá tan.","nguon":["@c1270"]},{"id":"loi-quyen","name":"Lôi quyền","cn":"雷拳","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Liên tục đánh quyền ngưng tụ sấm sét thành nắm tay khổng lồ, kết hợp lực lượng Cổ Thần không thể bị phục chế.","detail":"Bản thể Vương Lâm thi triển — liên tục đánh quyền ngưng tụ sấm sét thành nắm tay khổng lồ từ mười trượng tăng dần lên hai vạn trượng, mỗi quyền nặng hơn quyền trước. Kết hợp lực lượng Cổ Thần bên trong, khiến lôi quyền không thể bị Lôi Sát Kính phục chế — phần sấm sét bị phục chế nhưng lực lượng Cổ Thần đè bẹp bản sao, rồi phá vỡ luôn Lôi Sát Kính.","nguon":["@c1270"]},{"id":"bay-tram-van-giet-tien-an","name":"Bảy trăm vạn giết tiên ấn","cn":"七百万杀仙印","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"Tán Linh Thượng Nhân (tự ngộ)","soHuu":["Tán Linh Thượng Nhân"],"blurb":"Đại thần thông của Tán Linh, dùng thần thức khắc toàn bộ bảy trăm vạn thiên địa vào lòng sau hàng ngàn năm tế luyện, huyễn hóa vô số mảnh vỡ hư ảo thu nhỏ phong ấn đối phương.","detail":"Tán Linh Thượng Nhân đã đi khắp bảy trăm vạn thiên địa trong vài ngàn năm, dùng thần thức khắc ghi toàn bộ thiên địa vào tâm, tạo ra hư ảnh thu nhỏ bao phủ và phong ấn mục tiêu. Khi thi triển, vô số mảnh vỡ hư ảo bao vây đối phương, vừa phong ấn vừa tấn công quy mô lớn. Trong trận chiến với đại trưởng lão Thiểm Lôi Tộc, hư ảnh bị Lôi Vân Chấn phá vỡ nhưng đổi lại khiến Lôi Vân Chấn tan rã hơn phân nửa.","nguon":["@c1271"]},{"id":"bang-diet-thuat","name":"Băng Diệt Thuật","cn":"崩灭术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tán Linh Thượng Nhân","soHuu":["Tán Linh Thượng Nhân"],"blurb":"Tán Linh tự hủy 971 ký hiệu đồng loạt nổ tung, tạo lực lượng hủy diệt chặn vòng xoáy Lục Đạo Thần Lôi.","detail":"Thần thông tự hủy toàn bộ 971 ký hiệu mà Tán Linh đã tạo ra, khiến chúng đồng thời nổ tung giải phóng lực lượng hủy thiên diệt địa. Trong trận chiến tại bảy trăm vạn thiên địa, Băng Diệt Thuật được dùng để chặn vòng xoáy Lục Đạo Thần Lôi của đại trưởng lão Thiểm Lôi Tộc, khiến vòng xoáy khựng lại và đại trưởng lão phun máu.","nguon":["@c1271"]},{"id":"tuyet-thien-tran-phong-an-bat-hoang","name":"Tuyệt Thiên trận phong ấn bát hoang","cn":"绝天阵封印八荒","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Đại trận","hePhai":"Tán Linh Thượng Nhân","soHuu":["Tán Linh Thượng Nhân"],"blurb":"Đại trận lấy tính mạng hàng tỷ sinh linh trên bảy trăm vạn thiên địa làm trận pháp, phong ấn bát hoang ngăn mọi lực lượng bên ngoài, đồng thời ngưng tụ Trảm Thiên kiếm.","detail":"Tán Linh kích hoạt đại trận dùng tính mạng tất cả sinh linh (hàng tỷ phàm nhân và tu sĩ) trên bảy trăm vạn thiên địa làm nguồn lực. Tất cả sinh linh tình nguyện ngồi xuống, bùng ra ý niệm nghịch thiên phản kháng Tiên Giới giả tạo, dâng hiến tính mạng. Luồng gió bão ý niệm bao phủ toàn bộ bảy trăm vạn thiên địa, tạo tường đồng vách sắt ngăn cản mọi lực lượng bên ngoài tiến vào, kể cả sấm sét bất diệt từ thánh địa Thiểm Lôi Tộc cũng bị đẩy lui. Tán Linh dung hợp vào trận pháp làm trận linh, đồng thời ngưng tụ ra Trảm Thiên kiếm giao cho Vương Lâm.","nguon":["@c1271"]},{"id":"luc-dao-than-loi","name":"Lục Đạo Thần Lôi","cn":"六道神雷","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Truyền thừa Thiểm Lôi Tộc","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Sáu loại sấm sét truyền thừa qua các thế hệ Thiểm Lôi Tộc, tạo vòng xoáy hủy diệt: Thiên ẩn lôi, Địa dung lôi, Nguyên hóa lôi, Từ hàm lôi, Đạo ý lôi, Linh Niệm Lôi.","detail":"Đại trưởng lão vỗ vào tộc ấn trên mi tâm triệu hồi sáu loại sấm sét truyền thừa các thế hệ Thiểm Lôi Tộc: (1) Thiên ẩn lôi — sấm sét ẩn trong tinh không, mỗi luồng là một tu chân tinh; (2) Địa dung lôi — bụi bặm và mảnh tinh cầu tan vỡ cúng bái dung hợp thành sấm sét; (3) Nguyên hóa lôi — phá vỡ nguyên thần tạo hắc động hấp thu nguyên lực thiên địa; (4) Từ hàm lôi — khu vực đặc biệt tràn lực từ, mỗi ba ngàn năm sinh ra một luồng; (5) Đạo ý lôi — sưu tập ý cảnh Nội giới luyện hóa thành đạo niệm; (6) Linh Niệm Lôi. Sáu luồng tạo vòng xoáy tấn công hủy diệt. Bị phá hủy hoàn toàn bởi Băng Diệt Thuật của Tán Linh kết hợp lực hương hỏa của Vương Lâm.","nguon":["@c1271"]},{"id":"loi-van-chan","name":"Lôi Vân Chấn","cn":"雷云震","loai":"than-thong","loaiLabel":"Thần thông (Hình Lôi Chấn Thuật)","phamCap":"Thiên Nhân Đệ Ngũ Suy","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Dâng 1.000 năm thọ nguyên triệu hồi la bàn khổng lồ, ngưng tụ tầng mây sấm sét, dùng chấn động khiến máu huyết và tâm thần đối phương hỗn loạn.","detail":"Đại trưởng lão Thiểm Lôi Tộc thi triển Thiên Nhân Đệ Ngũ Suy, dâng hiến 1.000 năm thọ nguyên triệu hồi Hình Lôi Chấn Thuật — Lôi Vân Chấn. La bàn khổng lồ xuất hiện, tầng mây sấm sét bao phủ bầu trời, phát ra chấn động khiến máu huyết đối phương lưu chuyển hỗn loạn, tâm thần biến đổi, thân thể có nguy cơ tan vỡ. Bị 971 ký hiệu của Tán Linh kết hợp Phiên Thiên Ấn phá vỡ, tan rã hơn phân nửa.","nguon":["@c1271"]},{"id":"nam-dau-thuat","name":"Nam Đẩu thuật","cn":"南斗术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ nhất thần thông Thiểm Lôi Tộc","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Đệ nhất thần thông Thiểm Lôi Tộc, dâng vạn năm thọ nguyên phá căn nguyên truyền thừa Đệ Tam Bộ, mượn lực sao trời hóa thành Cửu Kiếp Sa Tinh.","detail":"Đại trưởng lão Thiểm Lôi Tộc tuyệt vọng dâng vạn năm thọ nguyên, phá vỡ căn nguyên truyền thừa Đệ Tam Bộ, dùng hương hỏa tộc nhân Thiểm Lôi Tộc thúc động Nam Đẩu thuật. Mượn lực lượng sao trời hóa thành Cửu Kiếp Sa Tinh, tinh đồ Cửu Tinh Liên Châu xuất hiện trên bầu trời, chín luồng u quang xuyên qua tinh đồ đối đầu sóng kiếm Trảm Thiên của Vương Lâm. Tiếng nổ kinh thiên khiến tinh không xuất hiện khe nứt khổng lồ. U quang Cửu Kiếp Sa Tinh cuối cùng bị uy lực kiếm xé toạc hoàn toàn.","nguon":["@c1271"]},{"id":"that-kiem-tram-thien-son","name":"Thất Kiếm Trảm Thiên Sơn","cn":"七剑斩天山","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"","hePhai":"Tán Linh Thượng Nhân / Bảy trăm vạn thiên địa","soHuu":["Vương Lâm"],"blurb":"Bảy kiếm chém ra bằng Trảm Thiên kiếm, mỗi kiếm mang theo sinh mệnh sinh linh bảy trăm vạn thiên địa dâng hiến, uy lực hủy diệt thiên địa.","detail":"Vương Lâm cầm Trảm Thiên kiếm (do Tán Linh ngưng tụ từ Tuyệt Thiên trận) chém ra bảy kiếm liên tiếp. Mỗi kiếm chém ra, sinh linh bảy trăm vạn thiên địa dâng tính mạng, kiếm quang mang theo linh hồn người tình nguyện hy sinh. Kiếm thứ nhất phá hủy bộ giáp sấm sét bất diệt (bảo vật truyền thừa Đệ Tam Bộ vượt xa Lôi Sát kính). Kiếm thứ hai uy lực giảm bảy phần. Kiếm thứ ba phá sấm sét âm dương bất diệt. Kiếm thứ tư và năm khiến đại trưởng lão lục phủ ngũ tạng tan vỡ. Kiếm thứ sáu khiến biên giới bảy trăm vạn thiên địa tan vỡ từng mảng, tinh không nứt rạn. Kiếm thứ bảy chưa xuất hiện. Bản thân Vương Lâm cũng chịu phản phệ nghiêm trọng: máu thịt xương cốt va chạm, thân thể vang tiếng nổ.","nguon":["@c1271"]},{"id":"sam-set-am-duong-bat-diet","name":"Sấm sét âm dương bất diệt","cn":null,"loai":"than-thong","loaiLabel":"Thần thông (Đệ Tam Bộ)","phamCap":"Thuật Đệ Tam Bộ","hePhai":"Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Đại trưởng lão dâng 3.000 năm thọ nguyên, dùng Thiểm Lôi ấn hóa thành Âm Dương đồ phân ra hai luồng sấm sét phá nguyên thần và thân thể.","detail":"Đại trưởng lão Thiểm Lôi Tộc dâng 3.000 năm thọ nguyên triệu hồi Thiểm Lôi ấn, hóa thành thuật Đệ Tam Bộ — Âm Dương đồ phân ra hai luồng sấm sét bất diệt: một luồng phá nguyên thần, một luồng phá thân thể. Bị kiếm thứ ba của Vương Lâm (Thất Kiếm Trảm Thiên Sơn) phá hủy.","nguon":["@c1271"]},{"id":"tam-tuc-thuat","name":"Tam Tức Thuật","cn":"三息术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cực phẩm (đạo thuật bộ tộc cấm)","hePhai":"Thiểm Lôi tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"blurb":"Tam Tức Thuật là đạo thuật cấm do tu sĩ thần bí năm xưa truyền lại cho Thiểm Lôi tộc, có thể trong ba hơi thở hút sạch thọ nguyên kẻ địch nhưng người thi triển chắc chắn phải chết. Đây là thuật lấy mạng đổi mạng, khiến ngay cả Đệ Tam Bộ đại năng đối mặt cũng cực kỳ đau đầu.","detail":"Tam Tức Thuật là nguyên nhân cốt lõi khiến Thiểm Lôi tộc dù không sở hữu Đệ Tam Bộ đại năng vẫn giữ vị thế bộ tộc cực mạnh trong Thái Cổ Tinh Thần. Nguồn gốc công pháp bắt nguồn từ đám tu sĩ thần bí năm xưa truyền lại cho Thiểm Lôi tộc. Bản chất của thuật này là trong ba lần hít thở, hút sạch toàn bộ thọ nguyên của kẻ địch, nhưng đổi lại người thi triển tất phải chết — là thuật lấy mạng đổi mạng đúng nghĩa. Trong trận chiến với Vương Lâm, Đại trưởng lão Thiểm Lôi tộc đã thi triển Tam Tức Thuật, bắt đầu hút thọ nguyên của Vương Lâm (@c1272).","thuocTinh":"Lôi đạo / Thọ nguyên","nguonGoc":"Tu sĩ thần bí năm xưa truyền lại cho Thiểm Lôi tộc","uyLuc":"Đệ Tam Bộ đại năng đối mặt cũng cực kỳ đau đầu; trong ba hơi thở có thể hút sạch thọ nguyên kẻ địch, bất kể tu vi.","dacDiem":"Trong ba hơi thở hút sạch thọ nguyên kẻ địch, người thi triển chắc chắn chết — là đạo thuật cấm mang tính đồng quy vu tận.","congNang":["Trong ba hơi thở hút sạch toàn bộ thọ nguyên kẻ địch (@c1272)","Thuật lấy mạng đổi mạng — người thi triển chắc chắn chết sau khi sử dụng"],"nguoiTu":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tuChuong":"@c1272","tangDatToi":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1272","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Đại trưởng lão Thiểm Lôi tộc thi triển Tam Tức Thuật trong trận chiến với Vương Lâm, bắt đầu hút thọ nguyên Vương Lâm.","anchor":"Trong ba lần hít thở có thể làm tất cả kẻ địch mất hết tất cả thọ nguyên"}]},"nguon":["@c1272"]},{"id":"truyen-thuyet-de-tam-bo","name":"Truyền thuyết Đệ Tam Bộ (con đường bản nguyên đại thành không hương hỏa)","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp / Truyền thuyết","phamCap":"Đệ Tam Bộ","hePhai":"","soHuu":[],"blurb":"Con đường cổ xưa trở thành Đệ Tam Bộ đại năng mà không cần hương hỏa môn đồ, chỉ dựa vào cảm ngộ bản thân tự lực bản nguyên đại thành, đánh vỡ cánh cửa thiên địa. Lâu đời hơn cả con đường hương hỏa phổ biến, phương pháp này cực kỳ hiếm và được coi là truyền thuyết trong Tam Bộ.","detail":"Có hai con đường trở thành Đệ Tam Bộ đại năng. Con đường phổ biến dựa vào lực lượng hương hỏa môn đồ tẩm bổ bản nguyên để mở cánh cửa thiên địa, đạt bản nguyên đại thành. Con đường thứ hai lâu đời hơn, được coi là truyền thuyết: không cần hương hỏa, tu sĩ chỉ dựa vào cảm ngộ bản thân và sức mình để bản nguyên đại thành, đánh vỡ cánh cửa thiên địa mà đạt Đệ Tam Bộ. Tu sĩ nào đi trọn con đường này sẽ trở thành truyền thuyết trong Tam Bộ. Vương Lâm đang hướng về con đường thứ hai này. @c1273","thuocTinh":"Bản nguyên","nguonGoc":"Truyền thuyết cổ xưa, lâu đời hơn con đường hương hỏa","yeuCau":"Tự lực cảm ngộ, không dựa hương hỏa môn đồ","uyLuc":"Bản nguyên đại thành, đánh vỡ cánh cửa thiên địa, đạt cảnh giới Đệ Tam Bộ đại năng.","dacDiem":"Cực kỳ hiếm, được coi là truyền thuyết; lâu đời hơn con đường hương hỏa phổ biến; hoàn toàn dựa vào cảm ngộ và tự lực của bản thân tu sĩ.","trangThai":"hoat-dong","congNang":["Tự lực bản nguyên đại thành mà không cần hương hỏa môn đồ @c1273","Đánh vỡ cánh cửa thiên địa để đạt Đệ Tam Bộ đại năng @c1273"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1273","tangDatToi":"","trangThai":"đang hướng tới"}],"tabs":{"tienTrinh":[{"chuong":"@c1273","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ hai con đường Đệ Tam Bộ","text":"Tiết lộ hai con đường trở thành Đệ Tam Bộ đại năng: phổ biến dựa hương hỏa, truyền thuyết tự lực bản nguyên đại thành. Vương Lâm đang hướng về con đường truyền thuyết.","anchor":"Tu sĩ nào dùng phương pháp này để trở thành Đệ Tam Bộ thì sẽ trở thành truyền thuyết trong Tam Bộ"}]},"capNhatToi":"@c1273","nguon":["@c1273"]},{"id":"bat-long-hop-nhat-cuu-long-quy-vi-tri-tran-thon-loi","name":"Bát Long Hợp Nhất / Cửu Long Quy Vị, Trí Trận Thôn Lôi","cn":"","aliases":["Bát Long Hợp Nhất","Cửu Long Quy Vị","Trí Trận Thôn Lôi"],"loai":"than-thong","loaiLabel":"Thần thông lôi đạo","phamCap":"không rõ","hePhai":"lôi đạo","soHuu":["Vương Lâm"],"blurb":"Thần thông lôi đạo do Vương Lâm thi triển khi công phá đại trận phòng hộ Thiểm Lôi tộc. Chiêu này hợp tám hồn phách Thái Cổ Lôi Long với nguyên thần Thái Cổ Lôi Long của hắn để hình thành lôi long vạn trượng, thôn lôi phá trận.","detail":"Vương Lâm lấy nguyên thần Thái Cổ Lôi Long của bản thân làm lõi chủ đạo, ra lệnh cho tám hồn phách Thái Cổ Lôi Long còn lại dung nhập, hình thành thế Bát Long Hợp Nhất, Cửu Long Quy Vị, Trí Trận Thôn Lôi. Nguyên thần của hắn đóng vai trò áp chế tám linh hồn kia, thống nhất chúng thành một lôi long khổng lồ. Lôi long được tạo ra lao thẳng vào đại trận phòng hộ của Thiểm Lôi tộc, khiến tầng phòng hộ nứt vỡ và bị xé mở lỗ hổng lớn.","thuocTinh":"lôi đạo","uyLuc":"Có thể hợp hồn Thái Cổ Lôi Long thành lôi long vạn trượng để công phá đại trận phòng hộ Thiểm Lôi tộc, khiến tầng phòng hộ nứt vỡ và bị xé mở lỗ hổng lớn.","dacDiem":"Lấy nguyên thần Thái Cổ Lôi Long của Vương Lâm làm lõi mạnh nhất, áp chế tám linh hồn Thái Cổ Lôi Long còn lại.","congNang":["Hợp tám hồn phách Thái Cổ Lôi Long với nguyên thần Thái Cổ Lôi Long của Vương Lâm để tạo lôi long khổng lồ phá trận @c1274"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1274","tangDatToi":"thi triển phá trận","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1274","loai":"thi triển","importance":"major","giaiDoan":"phá trận Thiểm Lôi tộc","text":"Vương Lâm thi triển Bát Long Hợp Nhất, Cửu Long Quy Vị, Trí Trận Thôn Lôi để hợp chín hồn phách lôi long thành lôi long công phá phòng hộ Thiểm Lôi tộc.","anchor":"Bát Long Hợp Nhất! Lại thêm vào nguyên thần Thái Cổ Lôi Long của ta, Cửu Long Quy Vị, Trí Trận Thôn Lôi"}]},"trangThai":"đang dùng","capNhatToi":"@c1274","nguon":["@c1274"]},{"id":"dai-tran-phong-ho-thiem-loi-toc","name":"Đại trận phòng hộ Thiểm Lôi tộc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp phòng hộ","phamCap":"không rõ","hePhai":"Thiểm Lôi tộc","soHuu":["Thiểm Lôi tộc"],"blurb":"Trận pháp phòng hộ bao bọc mười sáu tu chân tinh của Thiểm Lôi tộc. Khi Vương Lâm dùng lôi long công phá, trận pháp bị nứt vỡ rồi bị xé mở lỗ hổng khổng lồ.","detail":"Đại trận hiện thành thanh quang và tử quang như vỏ trứng bao trùm địa bàn Thiểm Lôi tộc. Dưới đòn công kích liên tục của lôi long do Vương Lâm tạo ra, trận pháp không chịu nổi, tan thành nhiều mảnh và lộ ra lỗ hổng lớn.","thuocTinh":"phòng hộ","uyLuc":"Có thể bao phủ mười sáu tu chân tinh Thiểm Lôi tộc bằng tầng phòng hộ thanh quang và tử quang.","dacDiem":"Bị lôi long của Vương Lâm va đập tới nứt vỡ và mở lỗ hổng.","congNang":["Phòng hộ mười sáu tu chân tinh Thiểm Lôi tộc @c1274"],"tabs":{"tienTrinh":[{"chuong":"@c1274","loai":"xuất hiện","importance":"normal","giaiDoan":"bị phá lỗ hổng","text":"Đại trận phòng hộ Thiểm Lôi tộc hiện hình như vỏ trứng nhưng bị lôi long của Vương Lâm công phá tới tan rã và mở ra lỗ hổng lớn.","anchor":"trận pháp tan rã hóa thành rất nhiều mảnh vỡ văng ra, một lỗ hổng khổng lồ được xé toạc ra"}]},"trangThai":"bị phá lỗ hổng","capNhatToi":"@c1274","nguon":["@c1274"]},{"id":"vong-xoay-hu-vo-keo-sam-set","name":"Vòng xoáy hư vô kéo sấm sét","cn":"","loai":"than-thong","loaiLabel":"Hiện tượng thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Âm thanh trong vòng xoáy"],"blurb":"Vòng xoáy khổng lồ xuất hiện trong hư vô tinh không, có tia chớp xoay chuyển và kéo sấm sét bất diệt vào trung tâm. Chủ thể phía sau chưa lộ danh tính.","detail":"Khi sấm sét bất diệt rời khỏi miếu thờ, vòng xoáy hư vô mở ra trong tinh không và phát ra lực hút mạnh nhằm kéo nó vào. Vương Lâm phải đuổi theo, nắm giữ và tranh đoạt trực tiếp với lực lượng trong vòng xoáy.","dinhDanh":"goc","thuocTinh":"hư vô, lôi điện","uyLuc":"Có thể kéo sấm sét bất diệt vào trung tâm vòng xoáy và buộc Vương Lâm phải hóa thân Cổ Thần để đối kháng.","dacDiem":"Vòng xoáy khổng lồ xuất hiện trong tinh không, bên trong có tia chớp xoay chuyển.","congNang":["Kéo sấm sét bất diệt vào trung tâm vòng xoáy @c1275"],"nguoiTu":[{"ten":"Âm thanh trong vòng xoáy","tuChuong":"@c1275","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1275","loai":"xuất hiện","importance":"normal","giaiDoan":"mở ra trong hư vô","text":"Vòng xoáy hư vô xuất hiện, kéo sấm sét bất diệt vào trung tâm và dẫn tới cuộc giằng co với Vương Lâm.","anchor":"trong hư vô đột nhiên xuất hiện một vòng xoáy khổng lồ"}]},"capNhatToi":"@c1275","nguon":["@c1275"]},{"id":"hoa-len-thanh-phien","name":"Hỏa Lên Thành Phiến","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông hỏa","phamCap":"khong-ro","hePhai":"Hỏa bản nguyên","soHuu":["Vương Lâm"],"blurb":"Thần thông hỏa của Vương Lâm khiến hỏa bản nguyên bùng thành biển lửa lam sắc. Trong chương này nó huyễn hóa Chu Tước và dung nhập vào huyết kiếm.","detail":"Hỏa Lên Thành Phiến được Vương Lâm thi triển trong đòn chém sứ giả thiên đạo. Hỏa lam sắc phủ rộng, hóa thành Chu Tước rồi hợp cùng lôi, lực lượng Cổ Thần và huyết kiếm để tăng uy lực kiếm kích.","thuocTinh":"Hỏa","uyLuc":"Có thể phủ phạm vi lớn bằng hỏa lam sắc và gia trì vào kiếm chiêu.","congNang":["Hỏa lam sắc phủ phạm vi lớn và dung nhập vào huyết kiếm trong đòn chém sứ giả @c1276"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1276","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1276","loai":"thi triển","importance":"normal","giaiDoan":"Dùng trong một kiếm chém sứ giả","text":"Vương Lâm thi triển Hỏa Lên Thành Phiến, để hỏa lam sắc hóa Chu Tước và dung nhập vào huyết kiếm.","anchor":"Hỏa Lên Thành Phiến"}]},"capNhatToi":"@c1276","nguon":["@c1276"]},{"id":"luc-luong-co-than-cua-vuong-lam","name":"Lực lượng Cổ Thần của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần lực huyết mạch","phamCap":"khong-ro","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần lực Cổ Thần mà Vương Lâm bộc phát trong lúc tranh đoạt sấm sét bất diệt và đối đầu sứ giả thiên đạo. Nó giúp ngưng hư ảnh Cổ Thần, kéo sấm sét và gia trì huyết kiếm.","detail":"Trong trận đối đầu vòng xoáy, lực lượng Cổ Thần khắp thân Vương Lâm bùng lên, vừa kéo sấm sét bất diệt, vừa khiến hư ảnh Cổ Thần hiện ra sau lưng hắn. Nguồn lực này tiếp tục dồn vào huyết kiếm để chém đứt bàn tay khổng lồ.","thuocTinh":"Cổ Thần","uyLuc":"Chống lực kéo của vòng xoáy, ngưng hư ảnh Cổ Thần và gia trì huyết kiếm.","congNang":["Bộc phát để kéo sấm sét bất diệt và gia trì một kiếm chém bàn tay sứ giả @c1276"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1276","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1276","loai":"thi triển","importance":"normal","giaiDoan":"Bộc phát đối đầu sứ giả","text":"Vương Lâm bộc phát lực lượng Cổ Thần toàn thân để kéo sấm sét, hiện hư ảnh Cổ Thần và dồn lực vào huyết kiếm.","anchor":"lực lượng Cổ Thần khắp toàn thân Vương Lâm"}]},"capNhatToi":"@c1276","nguon":["@c1276"]},{"id":"loi-hoa-dung-hop","name":"Lôi hỏa dung hợp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Chiến pháp bản nguyên phối hợp","phamCap":"khong-ro","hePhai":"Lôi bản nguyên, Hỏa bản nguyên","soHuu":["Vương Lâm"],"blurb":"Chiến pháp phối hợp lôi và hỏa của Vương Lâm. Trong chương này nó được dùng để tăng uy lực huyết kiếm khi chém sứ giả thiên đạo.","detail":"Vương Lâm dung hợp lôi long, hỏa lam sắc và lực lượng Cổ Thần vào huyết kiếm, tạo thành một kiếm chém thiên. Lôi hỏa dung hợp là mắt xích giúp các nguồn lực bản nguyên cộng hưởng trong đòn đánh.","thuocTinh":"Lôi, Hỏa","uyLuc":"Tăng uy lực kiếm kích khi nhiều nguồn lực cùng dồn vào huyết kiếm.","congNang":["Dung hợp lôi và hỏa để gia trì một kiếm chém bàn tay sứ giả @c1276"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1276","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1276","loai":"thi triển","importance":"normal","giaiDoan":"Gia trì huyết kiếm","text":"Vương Lâm dung hợp lôi và hỏa trong huyết kiếm để tung một kiếm chém thiên.","anchor":"Lôi và hỏa dung hợp lại với nhau"}]},"capNhatToi":"@c1276","nguon":["@c1276"]},{"id":"loi-ban-nguyen-dai-thanh","name":"Lôi bản nguyên đại thành","cn":"","aliases":["Lôi bổn nguyên đại thành"],"loai":"cong-phap","loaiLabel":"Bản nguyên tu luyện","phamCap":"đại thành","hePhai":"Lôi bản nguyên","soHuu":["Vương Lâm"],"blurb":"Lôi bản nguyên đại thành là mục tiêu tu luyện mà Vương Lâm hướng tới sau khi nuốt sấm sét bất diệt. Điều kiện đạt đại thành gồm luyện hóa sấm sét bất diệt, luyện hóa hồn phách tám con Thái Cổ Lôi Long và vơ vét minh ngộ về sấm sét trong nguyên thần đại trưởng lão.","detail":"Tại chương 1276, Vương Lâm xác định rõ lộ trình để lôi bản nguyên đạt tới đại thành: thứ nhất là luyện hóa sấm sét bất diệt, thứ hai là luyện hóa hồn phách của tám con Thái Cổ Lôi Long, thứ ba là vơ vét minh ngộ về sấm sét chứa trong nguyên thần của đại trưởng lão. Khi hoàn tất cả ba nguồn này, lôi bản nguyên sẽ đại thành và tu vi của Vương Lâm sẽ tăng mạnh.","thuocTinh":"Lôi","yeuCau":"Luyện hóa sấm sét bất diệt, hồn phách tám Thái Cổ Lôi Long và minh ngộ sấm sét trong nguyên thần đại trưởng lão.","uyLuc":"Khi đại thành sẽ khiến tu vi Vương Lâm tăng mạnh.","congNang":["Khi hoàn tất lôi bản nguyên đại thành, tu vi Vương Lâm sẽ tăng mạnh @c1276"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1276","tangDatToi":"đang hướng tới đại thành","trangThai":"đang luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1276","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Điều kiện đại thành","text":"Vương Lâm nêu rõ các nguồn cần luyện hóa và vơ vét để lôi bản nguyên đạt đại thành.","anchor":"lôi bản nguyên của ta sẽ đại thành"}]},"capNhatToi":"@c1276","nguon":["@c1276"]},{"id":"nguyen-than-do-xet-long-dat","name":"Nguyên thần dò xét lòng đất","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông nguyên thần","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm tách một phần nguyên thần theo hai chân dung nhập xuống đất để dò xét. Trong chương này, hắn dùng nó tìm ra mỏ Phàn Tinh dưới lòng đô thành.","detail":"Vương Lâm không kinh động người phàm mà chia một phần nhỏ nguyên thần thấm xuống lòng đất, quét tìm tài nguyên bên dưới đô thành. Thần thông này giúp hắn phát hiện mỏ Phàn Tinh và thu lấy một phần để luyện hóa cùng cất trữ.","thuocTinh":"nguyên thần dò xét","congNang":["Dò tìm tài nguyên dưới lòng đất mà người xung quanh không phát hiện @c1277"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1277","tangDatToi":"vận dụng dò xét lòng đất","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"thi triển","importance":"normal","giaiDoan":"Dò mỏ Phàn Tinh","text":"Vương Lâm chia một phần nguyên thần dung nhập xuống lòng đất để tìm mỏ Phàn Tinh dưới đô thành.","anchor":"nguyên thần được chia ra một phần nhỏ để theo hai chân dung nhập vào trong lòng đất"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"loi-ban-nguyen","name":"Lôi bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Bản nguyên lôi tồn tại trong nguyên thần Vương Lâm. Nó liên hệ trực tiếp với hình thái Thái Cổ Lôi Long và quá trình thôn phệ linh hồn lôi long.","detail":"Trong nguyên thần Vương Lâm, lôi bản nguyên cùng hỏa bản nguyên cùng tồn tại. Khi tám Thái Cổ Lôi Long bị biển lửa luyện hóa, nguyên thần lôi long của hắn chờ cơ hội thôn phệ để tăng cường căn cơ lôi đạo.","thuocTinh":"lôi","dacDiem":"Tồn tại trong nguyên thần Vương Lâm và phối hợp với nguyên thần Thái Cổ Lôi Long khi thôn phệ linh hồn lôi long.","congNang":["Làm nền tảng lôi đạo trong nguyên thần Vương Lâm @c1277"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1277","tangDatToi":"đang vận dụng trong nguyên thần","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"nhắc tới","importance":"normal","giaiDoan":"Cùng hỏa bản nguyên hiện rõ","text":"Lôi bản nguyên được nêu là một nền tảng trong nguyên thần Vương Lâm khi hắn luyện hóa tám Thái Cổ Lôi Long.","anchor":"trong nguyên thần của hắn ngoài lôi bản nguyên thì vẫn còn hỏa bản nguyên"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"hoa-ban-nguyen","name":"Hỏa bản nguyên","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bản nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Bản nguyên hỏa trong nguyên thần Vương Lâm. Nó phóng ra biển lửa lam sắc để thiêu đốt và luyện hóa tám Thái Cổ Lôi Long.","detail":"Hỏa bản nguyên bùng lên thành biển lửa lam sắc trong nguyên thần, bao phủ tám Thái Cổ Lôi Long đang bị giam giữ. Khi rượu gạo trong bụng Vương Lâm hóa thành hỏa lực, biển lửa này càng mạnh và đẩy nhanh quá trình luyện hóa.","thuocTinh":"hỏa","uyLuc":"Có thể hóa thành biển lửa lam sắc thiêu đốt linh hồn Thái Cổ Lôi Long trong nguyên thần.","congNang":["Luyện hóa linh hồn Thái Cổ Lôi Long bị giam trong nguyên thần @c1277"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1277","tangDatToi":"vận dụng biển lửa lam sắc","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"thi triển","importance":"normal","giaiDoan":"Biển lửa luyện long","text":"Hỏa bản nguyên bùng ra biển lửa lam sắc, bao phủ tám Thái Cổ Lôi Long để luyện hóa.","anchor":"lập tức có biển lửa lam sắc bùng ra bao phủ tất cả"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"hu-anh-chu-tuoc-trong-bien-lua","name":"Hư ảnh Chu Tước trong biển lửa","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông hỏa diễm","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hư ảnh Chu Tước hiện ra trong biển lửa lam sắc của Vương Lâm. Nó bay quanh tám Thái Cổ Lôi Long và phun thêm hỏa lực để hỗ trợ luyện hóa.","detail":"Khi hỏa bản nguyên trong nguyên thần Vương Lâm hóa thành biển lửa, hư ảnh Chu Tước xuất hiện bên trong, liên tục bay vòng quanh tám Thái Cổ Lôi Long. Hư ảnh này phun hỏa lực, làm quá trình thiêu đốt và luyện hóa mạnh hơn.","thuocTinh":"hỏa diễm Chu Tước","uyLuc":"Gia tăng hỏa lực trong biển lửa lam sắc để luyện hóa Thái Cổ Lôi Long.","congNang":["Hỗ trợ biển lửa lam sắc thiêu đốt tám Thái Cổ Lôi Long @c1277"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1277","tangDatToi":"triệu hư ảnh trong biển lửa","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1277","loai":"thi triển","importance":"normal","giaiDoan":"Chu Tước trợ hỏa","text":"Hư ảnh Chu Tước bay quanh tám Thái Cổ Lôi Long và phun thêm hỏa lực trong biển lửa lam sắc.","anchor":"chu tước liên tục bay vòng quanh tám con Thái Cổ Lôi Long"}]},"capNhatToi":"@c1277","nguon":["@c1277"]},{"id":"thuat-thien-dai-tinh-than","name":"Thuật Thiên Đại Tinh Thần","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thuật thôi diễn","phamCap":"khong-ro","hePhai":"Trường Tôn Hội","soHuu":["Vân Lạc"],"blurb":"Thuật Thiên Đại Tinh Thần là thuật thôi diễn do Đại Tư Vân Lạc của Trường Tôn Hội sử dụng. Thuật này tìm ra hình ảnh và ký ức thần thức của thủ phạm diệt Thiểm Lôi Tộc.","detail":"Được nhắc trong quá trình Trường Tôn Hội phát Thái Cổ Tinh Thần Lệnh, Thuật Thiên Đại Tinh Thần giúp Vân Lạc thôi diễn hình ảnh cùng ký ức thần thức của hung thủ, rồi phân tán kết quả cho sinh linh Thái Cổ Tinh Thần truy sát.","thuocTinh":"thôi diễn","uyLuc":"Có thể tìm hình ảnh và ký ức thần thức của mục tiêu bị truy sát.","dacDiem":"Gắn với vai trò Đại Tư của Vân Lạc trong Trường Tôn Hội.","congNang":["Thôi diễn hình ảnh và ký ức thần thức của thủ phạm diệt Thiểm Lôi Tộc @c1278"],"nguoiTu":[{"ten":"Vân Lạc","tuChuong":"@c1278","tangDatToi":"khong-ro","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1278","loai":"xuất hiện","importance":"normal","giaiDoan":"Truy tìm hung thủ","text":"Vân Lạc dùng Thuật Thiên Đại Tinh Thần để tìm hình ảnh và ký ức thần thức của thủ phạm diệt Thiểm Lôi Tộc.","anchor":"đã thôi diễn thuật Thiên Đại Tinh Thần để tìm ra hình ảnh và ký ức thần thức"}]},"capNhatToi":"@c1278","nguon":["@c1278"]},{"id":"dao-thuat-dung-hop","name":"Đạo thuật Dung hợp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"khong-ro","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo thuật Dung hợp là đạo thuật Vương Lâm thi triển khi ép sấm sét bất diệt dung nhập nguyên thần. Nó phục vụ mục tiêu làm lôi bản nguyên của hắn đại thành.","detail":"Trong quá trình dung hợp sấm sét bất diệt của Thiểm Lôi Tộc, Vương Lâm mở mắt thi triển Đạo thuật Dung hợp, để luồng lôi đình này trở thành vật trong nguyên thần và trợ lực cho lôi bản nguyên đại thành.","thuocTinh":"dung hợp","uyLuc":"Ép sấm sét bất diệt dung nhập nguyên thần để tăng lôi bản nguyên.","dacDiem":"Được thi triển khi sấm sét bất diệt có ý chí phản kháng.","congNang":["Dung hợp sấm sét bất diệt vào nguyên thần của Vương Lâm @c1278"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1278","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1278","loai":"thi triển","importance":"normal","giaiDoan":"Dung hợp sấm sét bất diệt","text":"Vương Lâm thi triển Đạo thuật Dung hợp để đưa sấm sét bất diệt vào nguyên thần, hướng tới lôi bản nguyên đại thành.","anchor":"Đạo thuật…Dung hợp! Hai mắt Vương Lâm mở ra thật mạnh"}]},"capNhatToi":"@c1278","nguon":["@c1278"]},{"id":"thuat-toc-an-nghich-chuyen-hinh-anh-nam-thang","name":"Thuật tộc ấn nghịch chuyển hình ảnh năm tháng","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông dò xét","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lão già mặc đạo bào có tộc ấn","Bảy tu sĩ trung niên theo lão già đạo bào"],"blurb":"Thần thông dò xét dùng tộc ấn ở mi tâm và u quang phối hợp để làm hiện lại dấu vết quá khứ trong một khu vực. Lão già đạo bào dùng thuật này ở thành tây để truy tìm tu sĩ che giấu.","detail":"Khi thi triển, tộc ấn trên mi tâm lão già đạo bào phát hào quang quét ngang thiên địa; bảy tu sĩ trung niên vây quanh, bấm pháp quyết và nối u quang vào thân thể lão để tăng uy lực. Thuật khiến nhà cửa, người sống và cả dấu vết người chết hiện ra như nghịch chuyển năm tháng, phục vụ việc lùng sục kẻ ẩn náu, nhưng bị Vương Lâm phá hình ảnh dò xét nên không phát hiện được hắn.","thuocTinh":"dò xét, hồi chiếu dấu vết quá khứ","uyLuc":"Có thể quét qua thành tây và làm hiện lại nhiều hình ảnh quá khứ của nhà cửa, phàm nhân và người đã chết.","dacDiem":"Cần tộc ấn ở mi tâm làm trung tâm, có thể được nhiều tu sĩ hỗ trợ bằng u quang.","congNang":["Dò xét dấu vết quá khứ trong khu vực bị hào quang quét qua @c1279","Tìm kiếm tu sĩ che giấu bằng cách hiện lại hình ảnh nghịch chuyển năm tháng @c1279"],"nguoiTu":[{"ten":"Lão già mặc đạo bào có tộc ấn","tuChuong":"@c1279","tangDatToi":"thi triển được","trangThai":"dang-tu"},{"ten":"Bảy tu sĩ trung niên theo lão già đạo bào","tuChuong":"@c1279","tangDatToi":"hỗ trợ thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1279","loai":"thi triển","importance":"normal","giaiDoan":"Dò xét thành tây","text":"Lão già đạo bào cùng bảy tu sĩ trung niên dùng tộc ấn và u quang quét qua thành tây, làm hiện lại hình ảnh quá khứ để tìm tu sĩ ẩn náu.","anchor":"Khi luồng hào quang bùng ra từ mi tâm lão già quét ngang thiên địa"}]},"capNhatToi":"@c1279","nguon":["@c1279"]},{"id":"thuat-sam-set-cat-nguyen-than","name":"Thuật sấm sét cắt nguyên thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Sấm sét","soHuu":["Vương Lâm"],"blurb":"Thần thông sấm sét được Vương Lâm dùng để cắt một phần nguyên thần đối phương. Trong chương này, hắn dùng nó với lão già đạo bào để lấy ký ức mà không giết bản thể.","detail":"Vương Lâm lợi dụng khoảnh khắc sấm chớp và sự không phát giác của nhóm truy tìm để áp sát lão già đạo bào, điểm vào mi tâm rồi tách một phần nguyên thần mang đi. Phần nguyên thần này được hắn bóp nát để rút ký ức về bố trí truy tìm của Thái Cổ Tinh Thần.","congNang":["Cắt một phần nguyên thần của đối phương để lấy ký ức @c1280"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1280","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"thi triển","importance":"normal","giaiDoan":"Cắt nguyên thần lão già đạo bào","text":"Vương Lâm thi triển thuật sấm sét để cắt một phần nguyên thần lão già đạo bào, rồi dùng phần nguyên thần đó đọc ký ức về vòng truy tìm.","anchor":"dùng thuật sấm sét cắt một phần nguyên thần đối phương"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"than-thong-tinh-toan-cua-van-lac-dai-tu-truong-ton-hoi","name":"Thần thông tính toán của Vân Lạc Đại Tư Trường Tôn Hội","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Suy tính","soHuu":["Vân Lạc"],"blurb":"Thần thông suy tính của Vân Lạc Đại Tư Trường Tôn Hội. Năng lực này được nhắc là có thể tính ra địa phương của Vương Lâm.","detail":"Trong ký ức nguyên thần mà Vương Lâm rút ra, thần thông của Vân Lạc được xem là nguy cơ trực tiếp vì có thể tính ra nơi hắn đang ở. Đây là căn cứ khiến nhóm truy tìm thu hẹp phạm vi trong tinh vực.","congNang":["Tính ra địa phương của mục tiêu @c1280"],"nguoiTu":[{"ten":"Vân Lạc","tuChuong":"@c1280","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"nhắc tới","importance":"normal","giaiDoan":"Truy tìm Vương Lâm","text":"Thần thông của Vân Lạc được nhắc là có thể tính ra địa phương của Vương Lâm, trở thành mối nguy trong cuộc lục soát của Thái Cổ Tinh Thần.","anchor":"thần thông của người này có thể tính ra ta đang ở địa phương nào"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"thien-an-loi","name":"Thiên Ẩn Lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi lực","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Đại trưởng lão Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Một trong sáu loại lôi được Vương Lâm gọi ra sau khi nuốt nguyên thần đại trưởng lão Thiểm Lôi Tộc.","detail":"Thiên Ẩn Lôi được nêu trong mệnh lệnh triệu xuất sáu loại lôi của Vương Lâm. Nó thuộc nhóm sấm sét mà hắn muốn thu lấy từ nguyên thần đại trưởng lão Thiểm Lôi Tộc.","congNang":["Một trong sáu luồng sấm sét được triệu gọi sau khi Vương Lâm thôn phệ nguyên thần đại trưởng lão Thiểm Lôi Tộc @c1280"],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"xuất hiện","importance":"normal","giaiDoan":"Sáu loại lôi","text":"Thiên Ẩn Lôi được Vương Lâm gọi ra cùng các loại lôi khác sau khi nuốt nguyên thần đại trưởng lão Thiểm Lôi Tộc.","anchor":"Thiên Ẩn Lôi, Địa Dung Lôi, Nguyên hóa lôi"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"dia-dung-loi","name":"Địa Dung Lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi lực","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Đại trưởng lão Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Một trong sáu loại lôi được Vương Lâm triệu xuất trong quá trình hấp thu lôi lực của đại trưởng lão Thiểm Lôi Tộc.","detail":"Địa Dung Lôi xuất hiện trong danh sách sáu loại lôi mà Vương Lâm ra lệnh hiện ra, cùng Thiên Ẩn Lôi và Nguyên Hóa Lôi.","congNang":["Một trong sáu luồng sấm sét được triệu gọi @c1280"],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"xuất hiện","importance":"normal","giaiDoan":"Sáu loại lôi","text":"Địa Dung Lôi được gọi ra cùng các loại lôi khác sau khi nguyên thần sấm sét của Vương Lâm biến hóa.","anchor":"Thiên Ẩn Lôi, Địa Dung Lôi, Nguyên hóa lôi"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"nguyen-hoa-loi","name":"Nguyên Hóa Lôi","cn":"","aliases":["Nguyên hóa lôi"],"loai":"than-thong","loaiLabel":"Lôi lực","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Đại trưởng lão Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Một trong sáu luồng sấm sét Vương Lâm muốn đoạt từ nguyên thần đại trưởng lão Thiểm Lôi Tộc.","detail":"Nguyên Hóa Lôi được gọi cùng Địa Dung Lôi và Từ Hợp Lôi trong mệnh lệnh triệu xuất sáu loại lôi của Vương Lâm.","congNang":["Một trong sáu luồng sấm sét được triệu gọi @c1280"],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"xuất hiện","importance":"normal","giaiDoan":"Sáu loại lôi","text":"Nguyên Hóa Lôi xuất hiện trong nhóm lôi lực mà Vương Lâm gọi ra sau khi thôn phệ nguyên thần đại trưởng lão Thiểm Lôi Tộc.","anchor":"Địa Dung Lôi, Nguyên hóa lôi, Từ Hợp lôi"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"tu-hop-loi","name":"Từ Hợp Lôi","cn":"","aliases":["Từ Hợp lôi"],"loai":"than-thong","loaiLabel":"Lôi lực","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Đại trưởng lão Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Một loại lôi trong sáu luồng sấm sét được Vương Lâm gọi ra ở cuối chương.","detail":"Từ Hợp Lôi nằm giữa Nguyên Hóa Lôi và Đạo Ý Lôi trong mệnh lệnh triệu xuất sáu loại lôi, cho thấy nó thuộc nhóm lôi lực Vương Lâm muốn thu lấy.","congNang":["Một trong sáu luồng sấm sét được triệu gọi @c1280"],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"xuất hiện","importance":"normal","giaiDoan":"Sáu loại lôi","text":"Từ Hợp Lôi được Vương Lâm gọi ra cùng các loại lôi khác khi nguyên thần sấm sét mở mắt lóe lôi quang.","anchor":"Nguyên hóa lôi, Từ Hợp lôi, Đạo Ý lôi"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"dao-y-loi","name":"Đạo Ý Lôi","cn":"","aliases":["Đạo Ý lôi"],"loai":"than-thong","loaiLabel":"Lôi lực","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Đại trưởng lão Thiểm Lôi Tộc","Vương Lâm"],"blurb":"Một trong sáu loại lôi hiện ra theo mệnh lệnh của Vương Lâm.","detail":"Đạo Ý Lôi được liệt kê cùng Từ Hợp Lôi và Linh Niệm Lôi ở cuối chương, thuộc nhóm sấm sét liên quan đến nguyên thần đại trưởng lão Thiểm Lôi Tộc.","congNang":["Một trong sáu luồng sấm sét được triệu gọi @c1280"],"tabs":{"tienTrinh":[{"chuong":"@c1280","loai":"xuất hiện","importance":"normal","giaiDoan":"Sáu loại lôi","text":"Đạo Ý Lôi được Vương Lâm gọi ra sau khi thôn phệ nguyên thần đại trưởng lão Thiểm Lôi Tộc.","anchor":"Từ Hợp lôi, Đạo Ý lôi, Linh Niệm lôi"}]},"capNhatToi":"@c1280","nguon":["@c1280"]},{"id":"chin-luong-sam-set-bao-quanh-loi-ban-nguyen","name":"Chín luồng sấm sét bao quanh lôi bản nguyên","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Hệ thống tu luyện lôi","phamCap":"Gắn với lôi bản nguyên đại thành","hePhai":"Lôi bản nguyên","soHuu":["Vương Lâm"],"blurb":"Cấu trúc đại thành của lôi bản nguyên đòi hỏi chín luồng sấm sét bao quanh. Tại @c1282, Vương Lâm hoàn chỉnh sáu luồng đã có rồi tự tạo ba luồng cuối — Cực cảnh lôi, Huyết Mạch lôi (Lôi Oa hóa thành), và Nghịch mệnh lôi — từ đó dẫn ra Không Đại Môn của Đệ Tam Bộ.","detail":"Lôi bản nguyên muốn đạt trạng thái đại thành cần đủ chín luồng sấm sét bao quanh. Ngoài sáu luồng Vương Lâm đã luyện hóa hoặc dung hợp trước đó, hắn phải tự tạo thêm ba luồng còn lại. Luồng thứ bảy là Cực cảnh, luồng thứ tám là Huyết Mạch lôi do Lôi Oa hóa thành, và luồng thứ chín là Nghịch mệnh lôi — được tạo từ cả đời nghịch tu của hắn. Khi chín luồng sấm sét đủ đầy, lôi bản nguyên đại thành, đồng thời dẫn động Không Đại Môn của Đệ Tam Bộ.","thuocTinh":"Lôi bản nguyên","dacDiem":"Cần chín luồng sấm sét bao quanh lôi bản nguyên để đạt trạng thái đại thành.","congNang":["Hoàn chỉnh lôi bản nguyên đại thành khi đủ chín luồng sấm sét bao quanh @c1282","Dẫn động Không Đại Môn của Đệ Tam Bộ @c1282"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1282","tangDatToi":"Chín luồng hoàn chỉnh","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1282","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Đại thành cần chín luồng","text":"Vương Lâm nhận ra lôi bản nguyên muốn đại thành cần thêm ba luồng sấm sét và sau đó tự tạo đủ chín luồng.","anchor":"Nếu muốn lôi bản nguyên được đại thành thì cần phải có ba luồng sấm sét nữa"}]},"capNhatToi":"@c1282","nguon":["@c1282"]},{"id":"huyet-mach-loi","name":"Huyết Mạch lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi đình huyết mạch","phamCap":"Luồng sấm sét thứ tám","hePhai":"Lôi bản nguyên","soHuu":["Vương Lâm","Lôi Oa"],"blurb":"Huyết Mạch lôi là luồng sấm sét thứ tám trong hệ thống lôi bản nguyên của Vương Lâm, do Lôi Oa hóa thành sau khi được phong làm linh hồn lôi đồ thứ tám. Nó nhập vào mắt phải Vương Lâm, mang theo ý chí sinh linh và huyết mạch sấm sét vốn có của Lôi Oa.","detail":"Vương Lâm nhận định Lôi Oa là mãnh thú sở hữu huyết mạch sấm sét cùng ý chí sinh linh, khác biệt với các luồng lôi thuần túy khác. Dựa trên đặc tính đó, Vương Lâm phong Lôi Oa làm linh hồn lôi đồ thứ tám. Lôi Oa hóa thành một luồng sấm sét được đặt tên Huyết Mạch lôi, dung nhập vào hệ thống lôi bản nguyên của Vương Lâm với tư cách luồng lôi thứ tám, bao quanh lôi bản nguyên.","thuocTinh":"Huyết mạch sấm sét","nguonGoc":"Do Lôi Oa hóa thành","dacDiem":"Mang ý chí sinh linh của Lôi Oa và huyết mạch sấm sét, khác với các luồng lôi thuần túy không có ý chí sinh linh.","congNang":["Làm luồng sấm sét thứ tám bao quanh lôi bản nguyên của Vương Lâm @c1282"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1282","tangDatToi":"Luồng thứ tám","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1282","loai":"xuất hiện","importance":"major","giaiDoan":"Luồng sấm sét thứ tám","text":"Lôi Oa được Vương Lâm phong làm linh hồn lôi đồ thứ tám và hóa thành Huyết Mạch lôi.","anchor":"ta ban cho ngươi tên là Huyết Mạch lôi"}]},"capNhatToi":"@c1282","nguon":["@c1282"]},{"id":"nghich-menh-loi","name":"Nghịch mệnh lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi đình nghịch ý","phamCap":"Luồng sấm sét thứ chín","hePhai":"Lôi bản nguyên","soHuu":["Vương Lâm"],"blurb":"Nghịch mệnh lôi là luồng sấm sét thứ chín chưa từng tồn tại trong thiên địa, do Vương Lâm lấy cả đời nghịch tu và sinh mệnh hóa thành. Nó là luồng lôi duy nhất có thể hoàn chỉnh chín luồng sấm sét quanh lôi bản nguyên, dẫn tới đại thành.","detail":"Khi tám luồng sấm sét quanh lôi bản nguyên đã hội đủ nhưng vẫn thiếu luồng thứ chín, Vương Lâm dùng toàn bộ ý chí phản kháng thiên địa, phản kháng vận mệnh cùng con đường nghịch tu cả một đời để hóa thành một luồng lôi chưa từng có — Nghịch mệnh lôi. Loại lôi này không hề tồn tại sẵn trong thiên địa mà hoàn toàn sinh ra từ nghịch ý và nghịch đạo của Vương Lâm. Nó trở thành luồng sấm sét thứ chín duy nhất, hoàn chỉnh chín luồng quanh lôi bản nguyên và đưa lôi bản nguyên tới đại thành, dẫn tới sự xuất hiện của Không Đại Môn.","thuocTinh":"Nghịch ý, lôi đình","nguonGoc":"Cả đời nghịch tu của Vương Lâm","dacDiem":"Vô hình vô ảnh với người thường, chỉ kẻ có nghịch ý hoặc là nghịch tu mới có thể phát hiện.","congNang":["Là luồng sấm sét thứ chín duy nhất, hoàn chỉnh chín luồng quanh lôi bản nguyên để đạt đại thành @c1282"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1282","tangDatToi":"Luồng thứ chín","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1282","loai":"xuất hiện","importance":"major","giaiDoan":"Luồng sấm sét thứ chín","text":"Vương Lâm lấy đời nghịch tu hóa thành Nghịch mệnh lôi, hoàn chỉnh chín luồng sấm sét quanh lôi bản nguyên.","anchor":"dùng cả đời nghịch tu của ta hóa thành một luồng nghịch lôi"}]},"capNhatToi":"@c1282","nguon":["@c1282"]},{"id":"khong-dai-mon","name":"Không Đại Môn","cn":"","aliases":["Cánh cửa Không Chi","Thiên Địa đại môn"],"loai":"khac","loaiLabel":"Cửa cảnh giới Đệ Tam Bộ","phamCap":"Đệ Tam Bộ","hePhai":"Không Chi","soHuu":[],"blurb":"Không Đại Môn là cánh cửa hư ảo khổng lồ bao phủ cả bầu trời, hiện ra sau khi chín luồng sấm sét quanh lôi bản nguyên của Vương Lâm hoàn chỉnh và Nghịch mệnh lôi nhập vào mắt phải hắn. Đây là thử thách ngưỡng cửa bước vào Đệ Tam Bộ, nơi Vương Lâm quyết tâm thử phá dù biết khả năng rất khó.","detail":"Sau khi chín luồng sấm sét quanh lôi bản nguyên hoàn chỉnh và Nghịch mệnh lôi nhập vào mắt phải Vương Lâm, một cánh cửa vô biên bao phủ bầu trời xuất hiện, được nhận ra là Không Đại Môn — ngưỡng cửa của Đệ Tam Bộ. Cánh cửa mang hình thái hư ảo rộng lớn tựa tinh không, toát ra sức mạnh khó tả. Vương Lâm cảm nhận uy áp từ Không Đại Môn và quyết định thử đánh vỡ nó để bước vào cảnh giới mới, dù tự biết khả năng thành công rất thấp.","thuocTinh":"Không Chi, cảnh giới Đệ Tam Bộ","dacDiem":"Cánh cửa hư ảo vô biên bao phủ cả bầu trời như tinh không.","congNang":["Hiện ra khi chín luồng sấm sét quanh lôi bản nguyên của Vương Lâm hoàn chỉnh, đóng vai trò là thử thách — ngưỡng cửa bước vào Đệ Tam Bộ @c1282"],"tabs":{"tienTrinh":[{"chuong":"@c1282","loai":"xuất hiện","importance":"major","giaiDoan":"Cửa Đệ Tam Bộ hiện thế","text":"Không Đại Môn hiện ra trên bầu trời sau khi Nghịch mệnh lôi nhập vào mắt phải Vương Lâm.","anchor":"Đệ Tam Bộ, Không Đại Môn"}]},"capNhatToi":"@c1282","nguon":["@c1282"]},{"id":"loi-do","name":"Lôi đồ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Lôi đạo","hePhai":"Lôi bản nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đồ án lôi đạo do Vương Lâm tự ngưng tụ, từ mắt phải lao ra khi hắn vận dụng lôi bản nguyên đại thành.","detail":"Lôi đồ có thể phóng lớn tới quy mô vạn trượng, dẫn động sấm sét thiên địa để công kích cánh cửa Không Chi. Sau khi Vương Lâm trấn áp tu sĩ bằng Thập Vạn Đại Sơn, lôi đồ còn được phân tán lên đỉnh núi để gia cố thế trấn áp.","dinhDanh":"goc","thuocTinh":"Lôi đạo","uyLuc":"Dẫn động sấm sét thiên địa, va chạm cánh cửa Không Chi và gia cố mười vạn lôi sơn.","dacDiem":"Do Vương Lâm tự ngưng tụ, xuất hiện từ mắt phải khi lôi bản nguyên bùng phát.","congNang":["Dẫn lôi, công kích cánh cửa Không Chi và gia cố thế trấn áp bằng lôi sơn @c1283"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1283","tangDatToi":"Tự ngưng tụ và thi triển","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1283","loai":"thi triển","importance":"normal","giaiDoan":"Công kích Không Môn và gia cố lôi sơn","text":"Vương Lâm dùng lôi đồ dẫn động sấm sét thiên địa để công kích cánh cửa Không Chi, sau đó dùng nó gia cố mười vạn lôi sơn trấn áp vài vạn tu sĩ.","anchor":"Nó chính là tồn tại đứng đầu sấm sét, là lôi đồ mà Vương Lâm tự mình ngưng tụ ra."}]},"capNhatToi":"@c1283","nguon":["@c1283"]},{"id":"muoi-van-loi-son-tran-phap-ap-che","name":"Mười vạn lôi sơn / trận pháp áp chế","cn":"","aliases":["Mười vạn lôi sơn"],"loai":"than-thong","loaiLabel":"Thần thông trấn áp","phamCap":"Không rõ","hePhai":"Lôi đạo","soHuu":["Vương Lâm"],"blurb":"Thế trấn áp quy mô lớn do Vương Lâm dẫn sấm sét dung nhập Thập Vạn Đại Sơn mà thành.","detail":"Vương Lâm khiến mười vạn ngọn núi hóa thành lôi sơn phủ xuống đầu vài vạn tu sĩ, làm nguyên lực thiên địa rối loạn khiến họ khó thoát trong thời gian ngắn. Lôi đồ được dùng như ký hiệu gia cố để thế trấn áp trở nên vững chắc hơn.","dinhDanh":"goc","thuocTinh":"Lôi đạo, trấn áp","uyLuc":"Trấn áp vài vạn tu sĩ và làm rối loạn nguyên lực thiên địa quanh Thập Vạn Đại Sơn.","dacDiem":"Dựa trên địa thế Thập Vạn Đại Sơn, lấy sấm sét và lôi đồ gia cố thành thế áp chế.","congNang":["Trấn áp quy mô lớn bằng mười vạn lôi sơn và giam giữ vài vạn tu sĩ trong thời gian ngắn @c1283"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1283","tangDatToi":"Thi triển thành công","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1283","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp vài vạn tu sĩ","text":"Vương Lâm dẫn sấm sét nhập Thập Vạn Đại Sơn, hóa thành mười vạn lôi sơn đè xuống và dùng lôi đồ ổn định thế trấn áp.","anchor":"Dùng mười vạn lôi sơn trấn áp vài vạn tu sĩ, hành động lần này đủ để Vương Lâm một đòn thành danh."}]},"capNhatToi":"@c1283","nguon":["@c1283"]},{"id":"phap-thuat-tai-hien-hinh-anh-cua-tu-mac-tu","name":"Pháp thuật tái hiện hình ảnh của Tư Mặc Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tư Mặc Tử","soHuu":["Tư Mặc Tử"],"blurb":"Thần thông Tư Mặc Tử dùng tại Thập Vạn Đại Sơn để tái hiện cảnh vừa xảy ra. Nó giúp hắn quan sát ba lần Vương Lâm công kích Không Môn và cảnh trấn áp tu sĩ.","detail":"Tư Mặc Tử vung tay khiến cuồng phong nổi lên trong thiên địa, ngưng thành hình ảnh khổng lồ tái hiện dấu vết tại Thập Vạn Đại Sơn. Nhờ đó hắn phát hiện Vương Lâm không dựa vào hương hỏa mà vẫn làm Không Môn xuất hiện.","dinhDanh":"goc","congNang":["Tái hiện cảnh vừa xảy ra trong khu vực, gồm cảnh Vương Lâm đánh Không Môn và trấn áp tu sĩ @c1284"],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1284","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1284","loai":"thi triển","importance":"normal","giaiDoan":"Tái hiện dấu vết Thập Vạn Đại Sơn","text":"Tư Mặc Tử thi triển pháp thuật để ngưng thành hình ảnh khổng lồ, qua đó xem lại sự việc Vương Lâm làm Không Môn xuất hiện.","anchor":"Dần dần tất cả tạo thành một hình ảnh khổng lồ"}]},"nguon":["@c1284"]},{"id":"lam-quang-hien-anh-cua-lam-mong-dao-ton","name":"Lam quang hiện ảnh của Lam Mộng Đạo Tôn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lam Ti tộc","soHuu":["Lam Mộng Đạo Tôn"],"blurb":"Thần thông hiện ảnh bằng lam quang của Lam Mộng Đạo Tôn. Lão dùng nó tại Lam Sơn để quan sát cảnh Vương Lâm đánh Không Môn.","detail":"Lam Mộng Đạo Tôn bấm pháp quyết khiến lam quang trên bầu trời Lam Sơn nhanh chóng ngưng tụ rồi hiện ra vài hình ảnh. Những hình ảnh đó cho lão thấy ba lần Vương Lâm công kích Không Môn.","dinhDanh":"goc","congNang":["Ngưng tụ lam quang để hiện hình ảnh liên quan đến dị tượng Không Môn @c1284"],"nguoiTu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1284","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1284","loai":"thi triển","importance":"normal","giaiDoan":"Hiện ảnh Không Môn","text":"Lam Mộng Đạo Tôn thi pháp tại Lam Sơn để hiện ra cảnh Vương Lâm ba lần đánh lên Không Môn.","anchor":"lam quang vạn trượng nhanh chóng ngưng tụ lại rồi đột nhiên xuất hiện vài hình ảnh"}]},"nguon":["@c1284"]},{"id":"chin-que-to-tien-phieu-mieu-toc-truyen-xuong","name":"Chín quẻ tổ tiên Phiêu Miễu tộc truyền xuống","cn":"","loai":"khac","loaiLabel":"Bói quẻ","phamCap":"không rõ","hePhai":"Phiêu Miễu tộc","soHuu":["Cô gái hắc y"],"blurb":"Hệ quẻ truyền thừa của tổ tiên Phiêu Miễu tộc. Khi Không Môn của Vương Lâm huyễn hóa, cô gái hắc y nhận ra dị tượng đã ứng ba trong chín quẻ.","detail":"Các quẻ được gắn với những dấu hiệu như hoa tàn, sóng nước, sấm sét, biển lửa, đảo chia lìa và xương tổ tiên tan. Trong chương này, cô gái hắc y nhận ra ba quẻ đã ứng nghiệm cùng lúc.","dinhDanh":"goc","congNang":["Dùng các dị tượng để đối chiếu lời truyền của tổ tiên và nhận biết biến cố lớn @c1284"],"nguoiTu":[{"ten":"Cô gái hắc y","tuChuong":"@c1284","tangDatToi":"nhận ra ba quẻ ứng nghiệm","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1284","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Ba quẻ ứng nghiệm","text":"Cô gái hắc y đối chiếu dị tượng hoa cỏ, hồ nước và sấm sét với lời truyền của tổ tiên, rồi nhận ra ba trong chín quẻ đã xuất hiện.","anchor":"Chín quẻ mà tổ tiên truyền xuống, lúc này lại xuất hiện ba quẻ"}]},"nguon":["@c1284"]},{"id":"thien-loi-than-thong","name":"Lôi đình thần thông của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dẫn lôi đình quy mô lớn của Vương Lâm, có thể gom vô tận lôi đình từ bốn phương tám hướng hóa thành lưới điện đánh xuống mục tiêu.","detail":"Trong lần ra mặt vì Chung Đại Hồng bị Ám Hạt Tộc đánh thương, Vương Lâm dùng lôi đình thần thông phá thành trì hoang phế của Ám Hạt Tộc. Vô tận lôi đình hội tụ thành lưới điện khổng lồ, đánh xuống khiến thành trì tan nát, đại điện nổ tung và bảo tháp dưới đất lộ ra.","nguon":["@c1285"]},{"id":"lac-an-than-thuc-cua-am-hat-toc","name":"Lạc ấn thần thức của Ám Hạt Tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông truy tung","phamCap":"","hePhai":"Ám Hạt Tộc","soHuu":["Thiếu chủ Ám Hạt Tộc","Nam tử trung niên Ám Hạt Tộc"],"blurb":"Thủ đoạn lưu dấu thần thức lên mục tiêu bị đánh thương để theo dõi hướng đi và lần ra nơi ẩn náu.","detail":"Thiếu chủ Ám Hạt Tộc sai người đánh thương một tu sĩ và lưu lạc ấn thần thức để xem hắn đi đâu. Dấu vết này được đặt trên Chung Đại Hồng sau khi hắn rời thành, về sau bị Vương Lâm nhìn ra cùng với thương thế trong cơ thể Chung.","nguon":["@c1285"]},{"id":"mot-chi-loi-dinh-cua-vuong-lam","name":"Một chỉ lôi đình của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm điểm một chỉ khiến thiên địa biến sắc, dẫn lôi đình giáng xuống diệt sát nam tử trung niên Ám Hạt Tộc.","detail":"Thần thông lôi được Vương Lâm thi triển trong lúc xử kẻ đã hại người của mình. Một chỉ điểm ra làm thiên địa biến sắc, lôi đình đánh xuống khiến thân thể nam tử trung niên tan nát, xương cốt vỡ vụn, nguyên thần trực tiếp bị diệt, đủ trấn nhiếp toàn bộ tu sĩ quanh thành trì.","nguon":["@c1286"]},{"id":"ban-tay-hu-ao-cua-vuong-lam","name":"Bàn tay hư ảo của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông bắt giữ","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm hóa ra bàn tay khổng lồ trước người để chụp giữ Ám hạt châu đang lao tới.","detail":"Khi thanh niên thiếu chủ Ám Hạt Tộc dùng Ám hạt châu đánh lén, Vương Lâm không né tránh mà biến hóa một bàn tay khổng lồ trước người. Bàn tay này chụp lấy hạt châu, để nó nổ tung trong tay nhưng không khiến Vương Lâm bị thương tổn.","nguon":["@c1286"]},{"id":"luoi-dien-phong-an","name":"Lưới điện phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông lôi phong ấn","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm vung tay tạo lưới điện phong tỏa thanh niên thiếu chủ Ám Hạt Tộc.","detail":"Sau khi Ám hạt châu đánh lén thất bại, Vương Lâm vung tay khiến một tấm lưới điện xuất hiện, tràn khắp thân thể thanh niên thiếu chủ. Mục tiêu lập tức mất khả năng chống cự, bị phong ấn và lơ lửng giữa không trung.","nguon":["@c1286"]},{"id":"bien-lua-phong-an","name":"Biển lửa phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông hỏa","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm phất tay gọi biển lửa cuốn lấy tộc nhân Ám Hạt Tộc, vừa đánh thương vừa phong ấn.","detail":"Trong lúc truy quét bảo tháp Ám Hạt Tộc, Vương Lâm phất tay tạo ra biển lửa ầm ầm tràn ra. Biển lửa cuốn hai lão già, khiến họ phun máu, rồi ngọn lửa xâm nhập cơ thể hóa thành phong ấn.","nguon":["@c1286"]},{"id":"bo-cap-den-hu-ao","name":"Bọ cạp đen hư ảo","cn":"","loai":"than-thong","loaiLabel":"Thần thông Ám Hạt Tộc","phamCap":"","hePhai":"Ám Hạt Tộc","soHuu":["Lão giả Ám Hạt Tộc hắc bào"],"blurb":"Lực lượng từ tầng cuối bảo tháp hóa thành bọ cạp đen hư ảo gần mười trượng lao vào Vương Lâm.","detail":"Thần thông do lão giả Ám Hạt Tộc hắc bào phát động từ đáy bảo tháp. Lực lượng ngưng thành một con bọ cạp màu đen hư ảo lớn gần mười trượng, mang uy thế phá bảo tháp và lao thẳng vào Vương Lâm, sau đó bị quyền Cổ Thần đối kháng.","nguon":["@c1286"]},{"id":"bo-cap-toc-an-bon-duoi","name":"Bọ cạp tộc ấn bốn đuôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông tộc ấn","phamCap":"","hePhai":"Ám Hạt Tộc","soHuu":["Lão giả Ám Hạt Tộc hắc bào"],"blurb":"Lão giả Ám Hạt Tộc tách tộc ấn khỏi mi tâm, hóa thành bọ cạp trăm trượng bốn đuôi để công kích.","detail":"Tộc ấn của lão giả Ám Hạt Tộc hắc bào có hình bọ cạp bốn đuôi. Khi giao chiến, tộc ấn thoát khỏi mi tâm, hóa thành bọ cạp trăm trượng, bốn đuôi quất về phía Vương Lâm; sau khi lão bị trấn áp, tộc ấn tan về nguyên thần.","nguon":["@c1286"]},{"id":"loi-the-toc-an-thai-co","name":"Lời thề tộc ấn thái cổ","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức ràng buộc tộc ấn","phamCap":"","hePhai":"Ám Hạt Tộc","soHuu":["Lão giả Ám Hạt Tộc hắc bào","Ám Hạt Tộc"],"blurb":"Nghi thức dùng tộc ấn phát thệ, ràng buộc Ám Hạt Tộc quy phục Vương Lâm.","detail":"Theo đề nghị của Chung Đại Hồng, lão giả Ám Hạt Tộc phải lấy tộc ấn phát lời thề thái cổ trước Vương Lâm. Lời thề quy định nếu phản bội sẽ bị tộc ấn cắn trả, cả tộc diệt tuyệt, từ đó toàn bộ Ám Hạt Tộc bị ràng buộc tôn Vương Lâm làm chủ.","nguon":["@c1286"]},{"id":"toc-an-long-giap-toc","name":"Tộc ấn Long Giáp Tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Long Giáp Tộc","soHuu":["Tộc trưởng Long Giáp Tộc","Long Giáp Tộc"],"blurb":"Thần thông tộc ấn phòng hộ của Long Giáp Tộc. Khi tộc trưởng Long Giáp Tộc thi triển, lớp phòng hộ bên ngoài khiến tu sĩ bình thường khó phá.","detail":"Tộc ấn Long Giáp Tộc được nhắc trong lời giới thiệu về tộc trưởng Long Giáp Tộc: đây là thủ đoạn phòng hộ ngoài thân, có thể tạo lớp phòng hộ khiến tu sĩ bình thường không thể phá vỡ.","congNang":["Phòng hộ ngoài thân, khiến tu sĩ bình thường khó phá lớp bảo vệ khi tộc trưởng Long Giáp Tộc thi triển @c1288"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1288","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ công dụng phòng hộ","text":"Tộc ấn Long Giáp Tộc được giới thiệu là thần thông phòng hộ của tộc trưởng Long Giáp Tộc, có thể khiến tu sĩ bình thường khó phá lớp bảo vệ bên ngoài.","anchor":"thi triển thần thông tộc ấn Long Giáp Tộc thì tu sĩ bình thường không thể phá vỡ lớp phòng hộ bên ngoài"}]},"capNhatToi":"@c1288","nguon":["@c1288"]},{"id":"than-thong-ngung-loi-cua-thiem-loi-toc","name":"Thần thông ngưng lôi của Thiểm Lôi tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiểm Lôi tộc","soHuu":["Thiểm Lôi tộc","Vương Lâm"],"blurb":"Thần thông lôi đạo của Thiểm Lôi tộc, được Vương Lâm nhắc như một phần lực lượng nhập vào viên đan sau khi dung lôi đình.","detail":"Khi Vương Lâm luyện một vạn Băng long đan thành một viên đan mới, hắn dung nhập lôi đình và nhắc tới thần thông ngưng lôi của Thiểm Lôi tộc. Yếu tố này góp phần khiến uy lực viên đan tăng lên, đủ đạt mức có thể làm bị thương tu sĩ thiên nhân đệ tứ suy trước khi tiếp tục được gia trì bằng máu Cổ Thần và tinh khí.","nguon":["@c1289"]},{"id":"de-cuu-bang","name":"Đệ cửu băng","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Chiêu cuối trong Sơn Băng thuật, được Vương Lâm trực tiếp phát động sau khi thuật có hồn phách nhờ sơn hồn toàn tu chân tinh.","detail":"Sau khi Sơn Băng thuật dung hợp toàn bộ sơn hồn trên tu chân tinh, Vương Lâm bỏ qua các bậc giữa và trực tiếp dẫn tới lần sụp đổ cuối cùng. Đệ cửu băng tạo thành cơn lốc hủy diệt từ núi đá, nham thạch, khói đen và sơn hồn để va chạm với thần thông của Tư Mặc Tử.","nguon":["@c1290"]},{"id":"pha-thien-dao","name":"Phá Thiên Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Phá Thiên tông","soHuu":["Tư Mặc Tử"],"blurb":"Thần thông của Phá Thiên tông, được Tư Mặc Tử thi triển trong trận chiến với Vương Lâm.","detail":"Phá Thiên Đạo là thần thông trong Phá Thiên tông, được Vương Lâm biết là chỉ các đời tông chủ và đại đệ tử mới được tu hành. Khi Tư Mặc Tử thi triển thuật biến trời thành tranh, đất thành mực và bản thân thành bút để phá thiên đạo, Vương Lâm lập tức liên hệ tới thần thông này và nghi vấn lai lịch thật của hắn.","nguon":["@c1290"]},{"id":"troi-la-tranh-dat-la-muc-ta-la-but","name":"Trời là tranh, đất là mực, ta là bút","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Tư Mặc Tử"],"blurb":"Chiêu thức Tư Mặc Tử dùng để biến thiên địa thành một giới tranh mực, khiến Vương Lâm liên hệ tới Phá Thiên Đạo.","detail":"Tư Mặc Tử dùng lời quyết khiến bầu trời hóa thành tranh trắng, mặt đất hóa thành mực đen, còn bản thân như một cây bút vung phá trong thiên địa. Biểu hiện của thuật này khiến Vương Lâm nhớ tới Phá Thiên tông và thần thông Phá Thiên Đạo.","nguon":["@c1290"]},{"id":"con-loc-than-thong-cua-tu-mac-tu","name":"Cơn lốc thần thông của Tư Mặc Tử","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Tư Mặc Tử"],"blurb":"Thần thông công kích bằng gió lốc của Tư Mặc Tử, dùng để đối kháng Sơn Băng thuật của Vương Lâm.","detail":"Tư Mặc Tử bắt quyết làm cơn lốc bên ngoài thân chấn động, gào thét xuyên qua thân thể rồi lao thẳng về phía Vương Lâm. Thần thông này va chạm với Sơn Băng thuật đã được Vương Lâm ban sơn hồn trên tu chân tinh.","nguon":["@c1290"]},{"id":"thuat-bo-chay-cua-tham-lang","name":"Thuật bỏ chạy của Tham Lang","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thủ đoạn đào thoát mà Tham Lang tự nhận là sở trường mạnh nhất của mình.","detail":"Tham Lang tự tin rằng nếu nói về bỏ chạy thì trong thiên địa hiếm người sánh được với hắn. Sau khi bị huyết quang trọng thương, hắn vẫn dùng hai ma ảnh dưới chân hóa thành hắc khí, vờn quanh thân thể thành gió lốc đen để tiếp tục trốn thoát.","nguon":["@c1290"]},{"id":"sat-chieu-bon-ngan-van-dao-kiem-khi-cua-vuong-lam","name":"Sát chiêu bốn ngàn vạn đạo kiếm khí của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông / kiếm khí","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát chiêu kiếm khí Vương Lâm chuẩn bị để đối phó Tư Mặc Tử, dồn gần bốn ngàn vạn đạo kiếm khí vào một chỉ.","detail":"Trong trận với phân thân Tư Mặc Tử, Vương Lâm dùng một chỉ chứa gần bốn ngàn vạn đạo kiếm khí để phá màn mực phòng ngự, đánh trọng thương đối phương và về sau tự hóa kiếm khí phá sập thiên địa của Phá Thiên Đạo.","thuocTinh":"Kiếm khí","uyLuc":"Phá phòng ngự, trọng thương phân thân bước thứ ba và phá tù ngục thần thông.","dacDiem":"Được nêu là một trong ba sát chiêu Vương Lâm chuẩn bị cho Tư Mặc Tử.","congNang":["Dồn gần bốn ngàn vạn đạo kiếm khí vào một chỉ để phá phòng ngự và đánh trọng thương đối thủ @c1291","Vờn quanh thân thể để tự thân hóa thành kiếm khí, phá sập thiên địa Phá Thiên Đạo @c1291"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1291","tangDatToi":"Thi triển trong thực chiến","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1291","loai":"thi triển","importance":"normal","giaiDoan":"Đối đầu Tư Mặc Tử","text":"Vương Lâm dùng sát chiêu kiếm khí phá phòng ngự và trọng thương phân thân Tư Mặc Tử, sau đó tiếp tục lấy kiếm khí phá tù ngục Phá Thiên Đạo.","anchor":"Đây là sát chiêu của Vương Lâm, là một trong ba chiêu Vương Lâm chuẩn bị cho Tư Mặc Tử"}]},"capNhatToi":"@c1291","nguon":["@c1291"]},{"id":"phien-thien-than-thong","name":"Phiên thiên thần thông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lam Mộng Đạo Tôn","soHuu":["Vương Lâm","Lam Mộng Đạo Tôn"],"blurb":"Thần thông nghịch chuyển thiên địa, được Tư Mặc Tử nhận ra là thần thông của Lam Mộng Đạo Tôn.","detail":"Vương Lâm dùng Phiên thiên thần thông sau khi phá vây khỏi Phá Thiên Đạo, khiến trời thành đất, đất thành trời rồi ép hai phía lại để nén Tư Mặc Tử.","thuocTinh":"Thiên địa nghịch chuyển","nguonGoc":"Lam Mộng Đạo Tôn","uyLuc":"Đảo ngược thiên địa và tạo áp lực nén lên đối thủ.","dacDiem":"Tư Mặc Tử nhận ra nguồn gốc của thần thông ngay khi Vương Lâm thi triển.","congNang":["Nghịch chuyển trời đất và ép thiên địa vào nhau để nén đối thủ @c1291"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1291","tangDatToi":"Thi triển trong thực chiến","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1291","loai":"thi triển","importance":"normal","giaiDoan":"Sau khi phá Phá Thiên Đạo","text":"Vương Lâm dùng Phiên thiên thần thông đối lại thiên địa của Tư Mặc Tử, buộc đối phương lấy Tuế Nguyệt Cấm chống đỡ.","anchor":"Phiên thiên thần thông của Lam Mộng Đạo Tôn!"}]},"capNhatToi":"@c1291","nguon":["@c1291"]},{"id":"thien-hoang-dia-lao","name":"Thiên hoang địa lão","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tuế nguyệt","soHuu":["Tư Mặc Tử"],"blurb":"Thần thông do Tư Mặc Tử ngộ ra từ Tuế Nguyệt cấm. Khi thi triển, thuật này làm bầu trời và mặt đất hiện trạng thái suy hoại như bị năm tháng ăn mòn.","detail":"Thiên hoang địa lão khiến bầu trời khô vàng, mặt đất nứt nẻ và già đi, rồi chuyển hóa thành lực hủy diệt trong thế công của Tư Mặc Tử. Đây là phần mở màn trong đòn cấm chế hắn dùng để áp chế Vương Lâm.","nguonGoc":"Do Tư Mặc Tử hiểu ra từ Tuế Nguyệt cấm.","thuocTinh":"Tuế nguyệt, suy hoại thiên địa","congNang":["Làm thiên địa suy hoại, bầu trời khô vàng và mặt đất nứt nẻ như già đi."],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1292","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1292","loai":"xuất hiện","importance":"normal","giaiDoan":"Giao chiến năm nhịp thở","text":"Tư Mặc Tử thi triển Thiên hoang địa lão, thuật ngộ từ Tuế Nguyệt cấm để làm thiên địa suy hoại.","anchor":"Thiên hoang địa lão, thuật này của Tư Mặc Tử là do hắn hiểu ra được từ Tuế Nguyệt cấm"}]},"capNhatToi":"@c1292","nguon":["@c1292"]},{"id":"cuc-kiep-loi","name":"Cực kiếp lôi","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Lôi đình","phamCap":"không rõ","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Một trong ba đạo lôi đình cuối cùng được Vương Lâm đưa vào lôi đồ vạn trượng. Nó cùng Huyết mạch lôi và Nghịch mệnh lôi làm lôi đồ bộc phát năng lượng mạnh.","detail":"Cực kiếp lôi được liệt kê trong ba đạo cuối của chín đạo lôi đình bao quanh lôi bổn nguyên. Khi lôi đồ thành hình, nhóm lôi đình này góp phần khiến lôi đồ phát ra quang mang vạn trượng trong đòn đánh vào Tư Mặc Tử.","thuocTinh":"Lôi đình","congNang":["Tăng cường uy lực cho lôi đồ vạn trượng của Vương Lâm."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1292","tangDatToi":"dung nhập lôi đồ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1292","loai":"thi triển","importance":"normal","giaiDoan":"Lôi đồ vạn trượng","text":"Cực kiếp lôi xuất hiện trong ba đạo lôi đình cuối cùng của lôi đồ, góp phần tăng uy lực đòn phản công của Vương Lâm.","anchor":"nhất là ba đạo cuối cùng chính là cực kiếp lôi, huyết mạch lôi và nghịch mệnh lôi"}]},"capNhatToi":"@c1292","nguon":["@c1292"]},{"id":"chuong-an-thien-nhan-de-ngu-suy","name":"Chưởng ấn thiên nhân đệ ngũ suy","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Công kích thần thông","phamCap":"thiên nhân đệ ngũ suy","hePhai":"Không rõ","soHuu":["Tư Mặc Tử"],"blurb":"Chưởng ấn do Tư Mặc Tử tung ra, chứa toàn bộ lực lượng thiên nhân đệ ngũ suy. Đòn này phối hợp với Tuế Nguyệt cấm để đánh vào Quang ảnh thuẫn của Vương Lâm.","detail":"Trong giao phong đầu, Tư Mặc Tử tung chưởng ấn mang lực thiên nhân đệ ngũ suy. Chưởng ấn phá qua lực Tuế Nguyệt quanh Quang ảnh thuẫn và trực tiếp va chạm với phòng ngự của Vương Lâm.","thuocTinh":"Thiên nhân đệ ngũ suy","congNang":["Dồn lực thiên nhân đệ ngũ suy vào chưởng ấn để công kích trực diện."],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1292","tangDatToi":"thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1292","loai":"xuất hiện","importance":"normal","giaiDoan":"Chưởng công kích Quang ảnh thuẫn","text":"Tư Mặc Tử tung chưởng ấn chứa toàn bộ lực thiên nhân đệ ngũ suy để đánh vào phòng ngự của Vương Lâm.","anchor":"Chưởng ấn này ẩn chứa toàn bộ lực lượng của thiên nhân đệ ngũ suy"}]},"capNhatToi":"@c1292","nguon":["@c1292"]},{"id":"mot-chi-cua-dai-de","name":"Một chỉ của đại đế","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Điên Lạc đại đế","soHuu":["Điên Lạc đại đế"],"blurb":"Thần thông từ dòng xoáy trên trời ngưng thành ngón tay khổng lồ, điểm xuống Tư Mặc Tử khi hắn định thuấn di khỏi vùng đất Điên Lạc.","detail":"Một chỉ này do sóng không khí từ dòng xoáy trên trời hóa thành, được dùng để chặn phân thân Thiên Nhân Đệ Ngũ Suy của Tư Mặc Tử đang trọng thương và chuẩn bị bỏ chạy.","uyLuc":"Đe dọa phân thân Thiên Nhân Đệ Ngũ Suy đã trọng thương.","congNang":["Ngưng thành ngón tay khổng lồ từ dòng xoáy trên trời để điểm xuống mục tiêu đang định bỏ chạy @c1293"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1293","loai":"thi triển","importance":"normal","giaiDoan":"Chặn Tư Mặc Tử","text":"Một chỉ từ dòng xoáy trên trời điểm xuống Tư Mặc Tử khi hắn sắp thuấn di khỏi vùng đất Điên Lạc.","anchor":"một ngón tay ầm ầm xuyên ra, hướng về phía Tư Mặc Tử hung hăng điểm một cái"}]},"capNhatToi":"@c1293","nguon":["@c1293"]},{"id":"cong-phap-an-dau-tu-vi-cua-su-gia-dai-de","name":"Công pháp ẩn dấu tu vi của sứ giả đại đế","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Điên Lạc Địa","soHuu":["Nam tử trung niên hồng sam"],"blurb":"Công pháp giúp nam tử trung niên hồng sam che giấu khí tức tu vi rất sâu, khiến Vương Lâm cũng không phát hiện được tu vi thật.","detail":"Khi sứ giả đại đế xuất hiện, hắn không lộ khí tức tu vi. Vương Lâm nhận định đối phương tu luyện một công pháp ẩn dấu tu vi tuyệt đỉnh nào đó.","thuocTinh":"Ẩn dấu tu vi","congNang":["Che giấu khí tức tu vi đến mức Vương Lâm không phát hiện được tu vi thật @c1293"],"dinhDanh":"goc","nguoiTu":[{"ten":"Nam tử trung niên hồng sam","tuChuong":"@c1293","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1293","loai":"xuất hiện","importance":"normal","giaiDoan":"Sứ giả che giấu tu vi","text":"Công pháp được nhận ra qua việc nam tử trung niên hồng sam không lộ khí tức tu vi khi xuất hiện trước Vương Lâm.","anchor":"Hiển nhiên hắn tu luyện một công pháp ẩn dấu tu vi tuyệt đỉnh nào đó"}]},"capNhatToi":"@c1293","nguon":["@c1293"]},{"id":"hac-hoa-trong-doc-dan-dai-de","name":"Hắc hỏa trong độc đan đại đế","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Hỏa diễm độc sát","phamCap":"Không rõ","hePhai":"Điên Lạc đại đế","soHuu":["Điên Lạc đại đế"],"blurb":"Hắc hỏa phát sinh từ độc đan đại đế, dùng để xử tử tộc trưởng Long Giáp Tộc. Ngọn lửa thiêu rụi cả nguyên thần, huyết nhục và xương cốt.","detail":"Khi tộc trưởng Long Giáp Tộc nuốt độc đan, đan dược hóa thành hỏa diễm màu đen và cháy dữ dội trong cơ thể. Vương Lâm kinh hãi trước loại lửa yêu dị này vì nó có thể thiêu sạch nguyên thần và thân thể, khiến người trúng chết không còn cặn bã.","congNang":["Thiêu rụi nguyên thần, huyết nhục và xương cốt của người nuốt độc đan @c1294"],"uyLuc":"Có thể xử tử tộc trưởng Long Giáp Tộc tới mức sau khi ngọn lửa tắt không còn cặn bã.","dacDiem":"Lộ vẻ yêu dị, bốc cháy từ bên trong cơ thể sau khi độc đan vào miệng.","trangThai":"đã hiển lộ","capNhatToi":"@c1294","tabs":{"tienTrinh":[{"chuong":"@c1294","loai":"thi triển","importance":"normal","giaiDoan":"Độc đan hóa hắc hỏa","text":"Hắc hỏa bùng lên trong cơ thể tộc trưởng Long Giáp Tộc sau khi hắn nuốt độc đan, thiêu rụi nguyên thần và thân thể hắn.","anchor":"Ngọn lửa màu đen này lộ ra vẻ yêu dị, ở trong cơ thể điên cuồng bốc cháy"}]},"nguon":["@c1294"]},{"id":"than-thong-quy-di-cua-tham-lang","name":"Thần thông quỷ dị của Tham Lang","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Tham Lang","soHuu":["Tham Lang"],"blurb":"Những thủ đoạn quỷ dị mà Tham Lang am hiểu, thường có uy lực lớn và khó lường. Chúng góp phần khiến người tu vi cao hơn cũng khó đối phó hắn.","detail":"Thần thông quỷ dị của Tham Lang được nhắc cùng với số lượng pháp bảo phong phú và khả năng bỏ chạy, tạo nên danh tiếng khó bắt, khó giết của hắn tại vùng đất Điên Lạc.","thuocTinh":"quỷ dị","uyLuc":"Thường có uy lực vô cùng theo lời thuật lại trong chương.","dacDiem":"Khó lường, kết hợp với pháp bảo và tốc độ bỏ chạy để phản kích hoặc thoát khỏi truy sát.","congNang":["Tạo ra các thủ đoạn khó đoán, thường có uy lực lớn khi Tham Lang bị truy sát @c1295"],"nguoiTu":[{"ten":"Tham Lang","tuChuong":"@c1295","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1295","loai":"nhắc tới","importance":"normal","giaiDoan":"Danh tiếng tại Điên Lạc","text":"Thần thông quỷ dị của Tham Lang được nêu là một nguyên nhân khiến hắn khó bị bắt dù tu vi ban đầu không quá cao.","anchor":"am hiểu một chút thần thông quỷ dị, thường thường có uy lực vô cùng"}]},"dinhDanh":"goc","capNhatToi":"@c1295","nguon":["@c1295"]},{"id":"nam-dao-bon-nguyen-luc-cua-vuong-lam","name":"Năm đạo bổn nguyên lực của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"Chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Năm đạo bổn nguyên lực mà Vương Lâm tự nhận có được, khiến hắn nghi Điên Lạc đại đế đã nhìn ra nội tình của mình.","detail":"Trong khi suy xét vì sao Điên Lạc đại đế đổi thái độ, Vương Lâm cho rằng đối phương có thể đã nhận ra việc hắn có năm đạo bổn nguyên lực, hoặc nhìn ra hỏa bổn nguyên khi hắn dùng Viêm hỏa dị tinh.","thuocTinh":"Bổn nguyên","dacDiem":"Gồm năm đạo bổn nguyên lực theo suy đoán của Vương Lâm.","congNang":["Là nền tảng khiến Vương Lâm nghi Điên Lạc đại đế nhìn ra thực lực và bí mật của mình @c1296"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1296","tangDatToi":"Chưa rõ","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1296","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Điên Lạc đại đế nghi nhìn ra","text":"Vương Lâm tự suy đoán rằng Điên Lạc đại đế có thể biết hắn sở hữu năm đạo bổn nguyên lực.","anchor":"Ta có năm đạo bổn nguyên lực"}]},"dinhDanh":"goc","capNhatToi":"@c1296","nguon":["@c1296"]},{"id":"nguyen-than-tinh-khi-hoa-cuong-phong-luoi-anh-sang","name":"Nguyên thần tinh khí hóa cuồng phong/lưới ánh sáng","cn":"","aliases":["Nguyên thần tinh khí hóa cuồng phong","Nguyên thần tinh khí hóa lưới ánh sáng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm vận dụng nguyên thần tinh khí để xóa ấn ký và thu bảo. Trong chương 1297, nó vừa hóa cuồng phong phá thần thức ấn ký trên phi kiếm, vừa hóa lưới ánh sáng bao phủ thụ nhân.","detail":"Vương Lâm há mồm phun nguyên thần tinh khí, dùng nó xử lý các bảo vật Tham Lang bỏ lại. Khi đối với chín mươi chín phi kiếm, nguyên thần tinh khí hóa thành cuồng phong khiến thần thức ấn ký của Tham Lang tan vỡ; khi đối với Táng Thiên Mộc Linh, nó hóa thành lưới ánh sáng để cuốn thụ nhân vào không gian trữ vật.","thuocTinh":"nguyên thần tinh khí","uyLuc":"Có thể xóa thần thức ấn ký của Tham Lang trên pháp bảo và bao phủ thụ nhân phòng hộ mạnh.","dacDiem":"Cùng một luồng nguyên thần tinh khí có thể biến hóa thành cuồng phong hoặc lưới ánh sáng tùy mục đích.","congNang":["Xóa thần thức ấn ký trên pháp bảo. @c1297","Bao phủ và thu nhiếp pháp bảo cỡ lớn vào không gian trữ vật. @c1297"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1297","tangDatToi":"vận dụng thành thục","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1297","loai":"thi triển","importance":"normal","giaiDoan":"Thu bảo Tham Lang","text":"Vương Lâm phun nguyên thần tinh khí để xóa ấn ký trên phi kiếm và hóa lưới ánh sáng thu thụ nhân.","anchor":"Vương Lâm há mồm phun ra một luồng nguyên thần tinh khí"}]},"capNhatToi":"@c1297","nguon":["@c1297"]},{"id":"tran-phong-ho-chin-bia-va-chin-muoi-chin-phi-kiem","name":"Trận phòng hộ chín bia và chín mươi chín phi kiếm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Tham Lang","soHuu":["Tham Lang"],"blurb":"Trận thế do chín tấm bia đá phối hợp với chín mươi chín phi kiếm tạo thành. Nó vừa có lớp phòng hộ từ bia đá, vừa có phi kiếm xoay tròn phóng kiếm khí như kiếm long.","detail":"Trên tu chân tinh Ám Hạt Tộc, chín tấm bia đá khổng lồ dường như hợp thành một trận pháp, bên ngoài có chín mươi chín thanh phi kiếm xoay quanh, phóng ra kiếm khí hóa thành kiếm long. Sau khi Tham Lang bỏ chạy, các cấu kiện của trận thế lần lượt bị Vương Lâm thu lấy.","thuocTinh":"phòng hộ và kiếm khí","uyLuc":"Có thể tạo thế phòng hộ bằng chín bia và công kích bằng kiếm khí của chín mươi chín phi kiếm.","dacDiem":"Dựa trên sự phối hợp giữa Hộ Cốt Cửu Bi và phi kiếm của Tham Lang.","congNang":["Dùng chín bia đá tạo phòng hộ quanh khu vực. @c1297","Dùng chín mươi chín phi kiếm xoay tròn phát kiếm khí công kích. @c1297"],"tabs":{"tienTrinh":[{"chuong":"@c1297","loai":"xuất hiện","importance":"normal","giaiDoan":"Bảo vật Tham Lang bày trên mặt đất","text":"Trận thế chín bia và chín mươi chín phi kiếm xuất hiện quanh các bảo vật Tham Lang bỏ lại trên tu chân tinh Ám Hạt Tộc.","anchor":"Chung quanh còn có chín tấm bia đá khổng lồ, dường như hợp thành một trận pháp"}]},"capNhatToi":"@c1297","nguon":["@c1297"]},{"id":"nhat-diep-phong-thien","name":"Nhất diệp phong thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thần thông phong ấn gắn với phiến lá khô của Tham Lang, chuyên dùng để phong bế gợn sóng không gian và cắt đường truy kích.","detail":"Tham Lang ném phiến lá vào gợn sóng tinh không, tạo lực phong ấn khổng lồ khiến Vương Lâm bị phản chấn khi thử phá. Tham Lang tự tin rằng ngay cả tu sĩ thiên nhân đệ ngũ suy muốn phá cũng phải tốn công.","thuocTinh":"phong ấn không gian","uyLuc":"Có thể phong bế nơi Vương Lâm sắp hiện thân trong gợn sóng tinh không và khiến đòn phá giải bị phản chấn.","dacDiem":"Cần phối hợp với phiến lá khô Cổ Tức Diệp.","congNang":["Phong bế gợn sóng không gian để chặn đường hiện thân hoặc truy kích."],"nguoiTu":[{"ten":"Tham Lang","tuChuong":"@c1298","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1298","loai":"thi triển","importance":"normal","giaiDoan":"Phong bế gợn sóng tinh không","text":"Tham Lang dùng Nhất diệp phong thiên để cản Vương Lâm đang truy kích qua gợn sóng không gian.","anchor":"Nhất diệp phong thiên của lão phu dù là tu sĩ thiên nhân đệ ngũ suy muốn phá vỡ cũng phải tốn một phen công phu"}]},"capNhatToi":"@c1298","nguon":["@c1298"]},{"id":"co-than-tinh-diem-cua-vuong-lam","name":"Cổ Thần tinh điểm của Vương Lâm","cn":"","loai":"khac","loaiLabel":"Dấu hiệu Cổ Thần","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Tinh điểm Cổ Thần trên mi tâm Vương Lâm tự hiện khi hắn cảm nhận khí tức Cổ Thần trong đồng tử Cổ Ma.","detail":"Khi Vương Lâm nhìn thấy dòng khí Cổ Thần trong đồng tử trái của các ma hồn Cổ Ma, tinh điểm Cổ Thần trên mi tâm hắn tự động biến ảo và xoay tròn.","thuocTinh":"Cổ Thần","dacDiem":"Tự động hiện ra khi Vương Lâm cảm ứng được Cổ Thần lực liên quan đến phong ấn trên Cổ Ma.","congNang":["Biểu hiện sự cộng hưởng của Vương Lâm với khí tức Cổ Thần trong phong ấn Cổ Ma."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1298","tangDatToi":"","trangThai":"đang có"}],"tabs":{"tienTrinh":[{"chuong":"@c1298","loai":"nhắc tới","importance":"normal","giaiDoan":"Cảm ứng Cổ Thần lực","text":"Tinh điểm Cổ Thần của Vương Lâm tự hiện khi hắn cảm nhận khí tức Cổ Thần trong đồng tử Cổ Ma.","anchor":"trên mi tâm hắn liền có Cổ Thần tinh điểm tự động biến ảo ra, xoay tròn"}]},"capNhatToi":"@c1298","nguon":["@c1298"]},{"id":"yeu-lang-hang-the-phat-diet-dao-thien","name":"Yêu Lang hàng thế, phạt diệt đạo thiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cổ Yêu","soHuu":["Tham Lang"],"blurb":"Yêu pháp Tham Lang thi triển khi bị Vương Lâm truy đuổi tới đường cùng.","detail":"Tham Lang mở khe không gian, dẫn yêu khí Cổ Yêu tràn ra, khiến sương đỏ nhập vào thất khiếu rồi gọi hư ảnh yêu lang vạn trượng lao tới tấn công Vương Lâm.","thuocTinh":"yêu khí Cổ Yêu","uyLuc":"Có thể gọi hư ảnh yêu lang vạn trượng và tạo dòng xoáy yêu khí khổng lồ.","dacDiem":"Gắn với yêu khí Cổ Yêu, nhưng bị Vương Lâm hóa Cổ Thần lục tinh dùng huyết kiếm chém đôi trong lần thi triển này.","congNang":["Mở khe không gian, dẫn yêu khí Cổ Yêu và gọi yêu lang vạn trượng tấn công @c1299"],"nguoiTu":[{"ten":"Tham Lang","tuChuong":"@c1299","tangDatToi":"","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1299","loai":"thi triển","importance":"normal","giaiDoan":"Tham Lang phản kích","text":"Tham Lang dùng Yêu Lang hàng thế, phạt diệt đạo thiên để gọi yêu khí Cổ Yêu và hư ảnh yêu lang vạn trượng tấn công Vương Lâm.","anchor":"Yêu Lang hàng thế, phạt diệt đạo thiên"}]},"capNhatToi":"@c1299","nguon":["@c1299"]},{"id":"loi-dinh-bon-nguyen-vuong-lam","name":"Bổn nguyên lực lôi đình của Vương Lâm","cn":"","aliases":["Lôi đình bổn nguyên lực của Vương Lâm"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lực lượng lôi đình thuộc bổn nguyên của Vương Lâm, được hắn dùng cùng thần thức để tra xét ký ức Tham Lang.","detail":"Sau khi bắt lại Tham Lang đang bỏ chạy, Vương Lâm đặt tay lên thiên linh đối phương, để thần thức tiến vào nguyên thần tra xét trí nhớ. Bổn nguyên lực lôi đình của hắn theo đó xâm nhập, đủ để quét kỹ ký ức Tham Lang một lượt và xác nhận lời khai về cổ mộ, pho tượng cùng các pháp bảo.","nguon":["@c1300"]},{"id":"than-thong-tao-dong-phu","name":"Thần thông tạo động phủ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm dùng để tạo động phủ khổng lồ làm nơi bế quan.","detail":"Sau khi trở về tu chân tinh, Vương Lâm thi triển thần thông này để dựng một tòa động phủ lớn, chuẩn bị triển khai kế hoạch tiếp theo.","congNang":["Tạo động phủ bế quan tại chỗ @c1301"],"tabs":{"tienTrinh":[{"chuong":"@c1301","loai":"thi triển","importance":"normal","giaiDoan":"Tạo động phủ","text":"Vương Lâm thi triển thần thông để tạo một tòa động phủ khổng lồ ngay sau khi trở về tu chân tinh.","anchor":"Mà Vương Lâm sau khi trở về liền lập tức thi triển thần thông, tạo ra một tòa động phủ khổng lồ"}]},"capNhatToi":"@c1301","nguon":["@c1301"]},{"id":"cam-che-ngoai-dong-phu-vuong-lam","name":"Cấm chế ngoài động phủ Vương Lâm","cn":"","loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Nhiều tầng cấm chế bao quanh động phủ của Vương Lâm trên tu chân tinh.","detail":"Cấm chế phong tỏa khu vực mấy trăm dặm quanh động phủ, khiến tu sĩ bên ngoài không thể bước vào phạm vi bế quan của Vương Lâm.","congNang":["Phong tỏa phạm vi mấy trăm dặm quanh động phủ @c1301"],"tabs":{"tienTrinh":[{"chuong":"@c1301","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong tỏa động phủ","text":"Vương Lâm bố trí nhiều tầng cấm chế bên ngoài động phủ, ngăn tu sĩ tiến vào khu vực mấy trăm dặm.","anchor":"Bên ngoài động phủ có nhiều tầng cấm chế, khiến trong trong phạm vi mấy trăm dặm không có bất cứ tu sĩ nào có thể bước vào"}]},"capNhatToi":"@c1301","nguon":["@c1301"]},{"id":"cam-ung-huyet-mach-voi-mau-bon-nguyen","name":"Cảm ứng huyết mạch với máu bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thức/cảm ứng","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm cảm nhận vị trí giọt máu của mình trong hồn đan thông qua liên hệ huyết mạch.","detail":"Dù cách nhau cả tinh vực, Vương Lâm vẫn dựa vào liên hệ giữa máu của mình và máu trong hồn đan để mơ hồ cảm nhận vị trí đại khái của vật mồi.","congNang":["Truy cảm vị trí đại khái của máu qua liên hệ huyết mạch @c1301"],"tabs":{"tienTrinh":[{"chuong":"@c1301","loai":"thi triển","importance":"normal","giaiDoan":"Cảm ứng vật mồi","text":"Vương Lâm dựa vào liên hệ huyết mạch với máu trong hồn đan để cảm nhận vị trí của vật mồi đang được Hỏa Tước tộc mang đi.","anchor":"Cho nên hắn có thể dựa vào sự liên lạc giữa máu huyết mà ở giữa khoảng cách tinh vực vẫn có thể mơ hồ cảm nhận được vị trí đại khái"}]},"capNhatToi":"@c1301","nguon":["@c1301"]},{"id":"hoa-diem-mau-lam-cay-ky-uc","name":"Hỏa diễm màu lam cấy ký ức","cn":"","loai":"than-thong","loaiLabel":"Thần thông hỏa diễm","phamCap":"không rõ","hePhai":"Hỏa diễm","soHuu":["Vương Lâm"],"blurb":"Thần thông hỏa diễm màu lam do Vương Lâm thi triển từ mắt trái để cải tạo ký ức và dựng thân phận giả cho Lưu Kim Bưu.","detail":"Vương Lâm dùng ngọn lửa màu lam từ mắt trái bao lấy Lưu Kim Bưu thành hỏa cầu. Sau hơn một tháng, ký ức và khí thế của Lưu Kim Bưu bị biến đổi thành thân phận Chu Tước đời thứ sáu.","thuocTinh":"Hỏa diễm, ký ức","uyLuc":"Có thể biến đổi ký ức và nhận thức thân phận của mục tiêu trong thời gian dài.","dacDiem":"Được thi triển qua mắt trái của Vương Lâm, kết hợp với kế hoạch lừa gạt Hỏa Tước tộc.","congNang":["Cấy ký ức và cải tạo thân phận giả cho Lưu Kim Bưu @c1302"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1302","tangDatToi":"thi triển được","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1302","loai":"thi triển","importance":"normal","giaiDoan":"Cấy ký ức Chu Tước đời sáu","text":"Vương Lâm thi triển hỏa diễm màu lam để bao lấy Lưu Kim Bưu và biến đổi ký ức của hắn thành thân phận Chu Tước đời thứ sáu.","anchor":"Mắt trái của Vương Lâm lóe lên ngọn lửa màu lam"}]},"capNhatToi":"@c1302","nguon":["@c1302"]},{"id":"thanh-khi-anh-sang-xanh-trong-thuc-hai-ngan-y-nu-tu","name":"Thanh khí / ánh sáng xanh trong thức hải ngân y nữ tử","cn":"","loai":"khac","loaiLabel":"Lực lượng phong tỏa","phamCap":"Chưa rõ","hePhai":"Chưa rõ","soHuu":["Ngân Y Luyện Thi / ngân y nữ tử"],"blurb":"Lực lượng màu xanh bộc phát từ ngân y nữ tử, vừa hóa thành chưởng ấn công kích vừa hiện trong thức hải để ngăn thần thức dò xét.","detail":"Thanh khí này được Vương Lâm nhận định không thuộc linh lực, tiên lực, thiên địa nguyên lực, Cổ Ma khí, Cổ Yêu khí hay Cổ Thần lực; về sau hắn cũng thấy nó không phải hương hỏa hay bổn nguyên, nhưng lại có nét giống bổn nguyên. Trong thức hải ngân y nữ tử, nó hiện thành thanh quang và sương mù xanh, tiêu hao thần thức của Vương Lâm khi hắn thi triển Sưu thần thuật.","nguon":["@c1303"]},{"id":"to-hon-tro-giup","name":"Tổ Hồn trợ giúp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cổ Thần bát tinh","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thần thông bảo mệnh ẩn trong Hộ cốt Thạch Bi, thuộc cấp độ Cổ Thần bát tinh.","detail":"Khi Hộ cốt Thạch Bi hóa thành bảo vệ tay xương trên cánh tay phải Vương Lâm, bên trong lộ ra thần thức Cổ Thần và thần thông Tổ Hồn trợ giúp. Thuật này không có trong trí nhớ Đồ Ti; Vương Lâm nhận định nếu phối hợp với Quang ảnh thuẫn thì sẽ trở thành một thủ đoạn cực mạnh.","nguon":["@c1303"]},{"id":"huyet-luyen","name":"Huyết luyện","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Thuật luyện hóa","phamCap":"Không rõ","hePhai":"Luyện hóa bằng huyết mạch","soHuu":["Vương Lâm"],"blurb":"Thuật luyện hóa bằng máu được Vương Lâm dùng để áp chế và luyện kén ma hồn. Máu có bổn nguyên lực cùng máu Cổ Thần khiến kén ma hồn bị huyết sắc thay thế.","detail":"Khi kén ma hồn sinh phản kháng và truyền ra ý chí Cổ Ma, Vương Lâm phun máu lên kén để huyết luyện. Máu này chứa bổn nguyên lực và máu Cổ Thần, khiến kén phát tiếng kêu thảm, u quang tan rã và dần chuyển thành màu đỏ sẫm.","thuocTinh":"Huyết luyện","uyLuc":"Có thể áp chế phản kháng của kén ma hồn và biến nó thành huyết sắc.","dacDiem":"Dựa vào máu chứa bổn nguyên lực và máu Cổ Thần của Vương Lâm.","congNang":["Lấy máu luyện hóa kén ma hồn và áp chế ý chí phản kháng @c1304"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1304","tangDatToi":"Đã thi triển","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1304","loai":"thi triển","importance":"normal","giaiDoan":"Huyết luyện kén ma hồn","text":"Vương Lâm phun máu có bổn nguyên lực và máu Cổ Thần lên kén ma hồn, khiến kén bị huyết sắc thay thế và giảm phản kháng.","anchor":"Trong máu tươi này ẩn chứ bổn nguyên lực"}]},"trangThai":"Đã thi triển","capNhatToi":"@c1304","nguon":["@c1304"]},{"id":"an-ky-khong-che-ma-hon","name":"Ấn ký khống chế ma hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/ấn quyết","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Ấn ký do Vương Lâm thi triển để truy hồi và trấn áp ma hồn phản nghịch. Chỉ một lần bắt quyết rồi thổi ấn ký đã khiến ma hồn bỏ chạy phải quay về.","detail":"Khi ma hồn nhỏ bé sau khi hút sạch ma khí bỏ chạy, Vương Lâm bắt quyết đánh ra ấn ký và thổi một cái, khiến ma hồn thê thảm tự bay trở lại. Thần thông này thể hiện quyền khống chế sinh sát của hắn đối với vật do mình sáng tạo.","thuocTinh":"Khống chế ma hồn","uyLuc":"Có thể truy hồi và ép ma hồn phản nghịch quay về trước mặt Vương Lâm.","dacDiem":"Dùng ấn ký làm trung tâm để triệu hồi, áp chế đối tượng.","congNang":["Truy hồi và trấn áp ma hồn do Vương Lâm sáng tạo @c1305"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1305","tangDatToi":"Có thể thi triển để truy hồi ma hồn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp ma hồn phản nghịch","text":"Vương Lâm bắt quyết đánh ra ấn ký, thổi một cái để khiến ma hồn bỏ chạy tự quay về.","anchor":"tay phải bắt quyết đánh ra một ấn ký, đặt trước miệng thổi một cái"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"phan-than-ma-hon","name":"Phân thân ma hồn","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Phân thân/ma đạo","phamCap":"Mới có cơ sở","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Phân thân ma hồn là tuyến phân thân ma đạo của Vương Lâm, hình thành từ ma hồn được ép dung nhập Vụ Ma Thương rồi trở về trong cơ thể. Tính đến chương 1305, phân thân này mới chỉ có cơ sở ban đầu và còn cần nhiều lần tế luyện mới có thể thành phân thân chân chính.","detail":"Sau khi ma hồn dung nhập Vụ Ma Thương rồi quay trở lại trong cơ thể Vương Lâm, nó tồn tại cạnh nguyên thần và bị nguyên thần áp chế. Vương Lâm nhận định rằng phân thân ma hồn tuy chưa đại thành nhưng đã mở được nền tảng, và nếu trải qua nhiều lần tế luyện thì có thể trở thành phân thân chân chính. Đây là khởi điểm cho tuyến phân thân ma đạo của Vương Lâm, đánh dấu bước đầu tiên trong quá trình tạo dựng một phân thân riêng biệt từ nguồn ma hồn.","thuocTinh":"Ma đạo, phân thân","uyLuc":"Chưa đại thành nhưng đã mở nền tảng để tế luyện thành phân thân chân chính.","dacDiem":"Ma hồn bị nguyên thần Vương Lâm áp chế trong cơ thể sau khi nhập Vụ Ma Thương.","congNang":["Tạo cơ sở cho phân thân ma hồn của Vương Lâm, có tiềm năng trở thành phân thân chân chính sau nhiều lần tế luyện @c1305"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1305","tangDatToi":"Mới có cơ sở","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1305","loai":"xuất hiện","importance":"major","giaiDoan":"Có cơ sở đầu tiên","text":"Ma hồn trở lại trong cơ thể Vương Lâm và được xác nhận có thể trở thành phân thân chân chính sau nhiều lần tế luyện.","anchor":"Cho dù phân thân ma hồn còn chưa đại thành nhưng đã bắt đầu có cơ sở"}]},"capNhatToi":"@c1305","nguon":["@c1305"]},{"id":"luc-luong-huong-hoa","name":"Lực lượng hương hỏa","cn":"","aliases":[],"loai":"khac","loaiLabel":"Năng lực","phamCap":"đặc trưng tu sĩ bước thứ ba","hePhai":"tu sĩ bước thứ ba","soHuu":["Tư Mặc Tử"],"blurb":"Lực lượng hương hỏa hiện quanh Tư Mặc Tử dưới dạng làn khói hư ảo có nhiều khuôn mặt. Các tu sĩ nhận ra đây là dấu hiệu của tu sĩ bước thứ ba.","detail":"Trong lần Tư Mặc Tử xuất hiện trước Đại đế tinh, quanh hắn có làn khói hương hỏa cùng uy áp khiến tu sĩ bốn phía biến sắc. Biểu hiện này được nhận ra là lực lượng của tu sĩ bước thứ ba.","thuocTinh":"hương hỏa","dacDiem":"Khói hư ảo, bên trong có nhiều khuôn mặt.","nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1307","tangDatToi":"không rõ","trangThai":"đang có"}],"congNang":["Biểu hiện uy áp và thân phận tu sĩ bước thứ ba quanh Tư Mặc Tử @c1307"],"tabs":{"tienTrinh":[{"chuong":"@c1307","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ quanh Tư Mặc Tử","text":"Lực lượng hương hỏa hiện thành làn khói có nhiều khuôn mặt hư ảo quanh Tư Mặc Tử, khiến tu sĩ nhận ra hắn là tu sĩ bước thứ ba.","anchor":"Lực lượng hương hỏa! Tu sĩ bước thứ ba"}]},"capNhatToi":"@c1307","nguon":["@c1307"]},{"id":"luc-luong-giang-xe-va-tu-luc-trong-thong-dao-dai-de-tinh","name":"Lực lượng giằng xé và từ lực trong thông đạo Đại đế tinh","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trường lực","phamCap":"không rõ","hePhai":"Đại đế tinh","soHuu":[],"blurb":"Trường lực trong thông đạo Đại đế tinh gồm lực giằng xé và từ lực có thể hút nguyên lực. Vương Lâm đánh giá lực hút trong thông đạo chưa quá mạnh so với sương mù bên ngoài.","detail":"Khi bước vào thông đạo vào Đại đế tinh, Vương Lâm lập tức cảm nhận lực lượng giằng xé tràn ngập bốn phía cùng từ lực như muốn hút nguyên lực trong cơ thể ra ngoài, khiến nguyên lực tan rã. Đây là lực lượng gắn với thông đạo và vùng sương mù từ lực quanh đó.","thuocTinh":"từ lực, lực giằng xé","dacDiem":"Có thể hút nguyên lực và làm nguyên lực tan rã.","congNang":["Hút nguyên lực trong cơ thể và làm nguyên lực tan rã @c1307"],"tabs":{"tienTrinh":[{"chuong":"@c1307","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm tiến vào thông đạo","text":"Vương Lâm cảm nhận lực giằng xé và từ lực trong thông đạo Đại đế tinh, đồng thời nhận ra lực hút nơi này chưa quá mạnh so với bên ngoài.","anchor":"còn có từ lực như muốn hút nguyên lực trong cơ thể ra ngoài"}]},"capNhatToi":"@c1307","nguon":["@c1307"]},{"id":"danh-khoi-ti-thuat","name":"Danh khôi ti thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Trường Tôn hội","soHuu":["Nữ tử Trường Tôn hội"],"blurb":"Danh khôi ti thuật là thuật pháp của nữ tử Trường Tôn hội, cần dựa vào tên thật do đối phương tự nói ra. Trong chương này, thuật không thể thi triển vì Vương Lâm chỉ dùng tên Hứa Mộc.","detail":"Nữ tử Trường Tôn hội âm thầm niệm Hứa Mộc ba lần nhưng phát hiện đó không phải tên thật do Vương Lâm tự thừa nhận, nên điều kiện thi triển Danh khôi ti thuật không thành.","thuocTinh":"thuật con rối dựa vào tên tuổi","congNang":["Dựa vào tên tuổi để thi triển thuật con rối khi đủ điều kiện tên thật."],"nguoiTu":[{"ten":"Nữ tử Trường Tôn hội","tuChuong":"@c1308","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1308","loai":"thi triển","importance":"normal","giaiDoan":"Thử dùng tên Hứa Mộc","text":"Nữ tử Trường Tôn hội định dùng Danh khôi ti thuật nhưng thất bại vì Vương Lâm không tự nói tên thật.","anchor":"Người này không tự mình nói ra tên thật, không thể thi triển thuật Danh khôi ti thuật"}]},"capNhatToi":"@c1308","nguon":["@c1308"]},{"id":"co-hon-cam","name":"Cổ Hồn cấm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Cấm chế","phamCap":"một trong tứ đại cấm","hePhai":"","soHuu":[],"blurb":"Cổ Hồn cấm là một loại cấm chế cổ xưa đã thất truyền, liên quan tới mãnh thú, lấy hồn phách và thân thể mãnh thú phối hợp thủ đoạn đặc thù để hóa thành. Vương Lâm nhận ra và xác nhận cấm chế này tại trường đấu tuyển chọn trưởng lão Lạc Sinh hội trên Đại đế tinh, khi hắn dùng Lôi đồ ép nó hiện hình thành con rùa xám khổng lồ ngàn dặm mang khí tức tang thương.","detail":"Cổ Hồn cấm xuất hiện với vai trò bảo vệ trường đấu tuyển chọn trưởng lão Lạc Sinh hội trên Đại đế tinh. Khi Vương Lâm chạm vào cấm chế trường đấu, hắn bị phản chấn và cảm nhận được tia hồn phách mang sắc thái tang thương. Hắn sau đó sử dụng Lôi đồ ép buộc cấm chế hiện nguyên hình, lộ ra dạng một con rùa xám khổng lồ ngàn dặm, từ đó xác nhận đây chính là Cổ Hồn cấm — một loại cấm chế đã thất truyền. Bản chất của cấm chế này gắn liền với mãnh thú: lấy hồn phách cùng thân thể mãnh thú, phối hợp thủ đoạn đặc thù mà luyện hóa thành cấm. @c1308","nguonGoc":"Liên quan tới mãnh thú, lấy hồn phách và thân thể mãnh thú biến thành cấm chế.","dacDiem":"Khi bị kích phát, cấm chế hiện hình thành rùa xám khổng lồ ngàn dặm, mang khí tức tang thương. @c1308","congNang":["Dùng hồn phách và thân thể mãnh thú phối hợp thủ đoạn đặc thù để hóa thành cấm chế @c1308","Bảo vệ trường đấu tuyển chọn trưởng lão Lạc Sinh hội trên Đại đế tinh, có khả năng phản chấn khi bị chạm vào @c1308"],"tabs":{"tienTrinh":[{"chuong":"@c1308","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện hình trên Đại đế tinh","text":"Cổ Hồn cấm ở trường đấu bị Vương Lâm dùng Lôi đồ ép hiện hình thành rùa khổng lồ và được xác nhận là một trong tứ đại cấm đã thất truyền.","anchor":"lấy hồn phách của mãnh thú cùng thân thể nó biến thành cấm chế"}]},"capNhatToi":"@c1308","nguon":["@c1308"]},{"id":"tu-dai-cam-che","name":"Tứ đại cấm chế","cn":"","aliases":[],"loai":"khac","loaiLabel":"Hệ cấm chế","phamCap":"không rõ","hePhai":"cấm đạo","soHuu":["Vương Lâm"],"blurb":"Tứ đại cấm chế gồm Phá Diệt cấm, Sinh Tử cấm, Tuế Nguyệt cấm và Cổ Hồn cấm. Việc gom đủ bốn loại được Vương Lâm xem là điều kiện để có cơ hội hiểu bốn nguyên cấm chế.","detail":"Trong lúc phát hiện Cổ Hồn cấm trên Đại đế tinh, Vương Lâm liên hệ nó với hệ tứ đại cấm mà hắn còn thiếu. Nếu học được đủ, hắn có thể tiến tới nhận thức cao hơn về bốn nguyên cấm chế.","thuocTinh":"cấm chế","dacDiem":"Gồm bốn loại cấm là Phá Diệt cấm, Sinh Tử cấm, Tuế Nguyệt cấm và Cổ Hồn cấm.","congNang":["Làm nền tảng để Vương Lâm có cơ hội hiểu bốn nguyên cấm chế khi gom đủ bốn loại cấm."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1309","tangDatToi":"đã có ba loại và phát hiện Cổ Hồn cấm","trangThai":"đang truy tìm"}],"tabs":{"tienTrinh":[{"chuong":"@c1309","loai":"nhắc tới","importance":"normal","giaiDoan":"Được liên hệ khi phát hiện Cổ Hồn cấm","text":"Vương Lâm nêu khả năng học đủ tứ đại cấm để hiểu bốn nguyên cấm chế.","anchor":"Nếu có thể học được toàn bộ tứ đại cấm"}]},"capNhatToi":"@c1309","nguon":["@c1309"]},{"id":"bon-nguyen-cam-che","name":"Bốn nguyên cấm chế","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế liên quan bổn nguyên","phamCap":"không rõ","hePhai":"cấm đạo","soHuu":["Vương Lâm"],"blurb":"Bốn nguyên cấm chế là mục tiêu nhận thức mà Vương Lâm nghĩ có thể chạm tới nếu học đủ và dung hợp tứ đại cấm. Điều này mở khả năng khiến bổn nguyên của hắn tăng thêm một đạo.","detail":"Khái niệm này được đặt ra khi Vương Lâm nhìn thấy Cổ Hồn cấm trên Đại đế tinh. Nó gắn với suy luận rằng việc hiểu sâu tứ đại cấm có thể dẫn tới một tầng bổn nguyên mới.","thuocTinh":"cấm chế, bổn nguyên","dacDiem":"Liên quan tới khả năng sinh thêm bổn nguyên từ cấm đạo.","congNang":["Mở khả năng giúp Vương Lâm tăng thêm một đạo bổn nguyên nếu hiểu ra sau khi gom đủ tứ đại cấm."],"tabs":{"tienTrinh":[{"chuong":"@c1309","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu sau tứ đại cấm","text":"Vương Lâm cho rằng học đủ tứ đại cấm có thể giúp hắn hiểu bốn nguyên cấm chế.","anchor":"có khả năng hiểu được bốn nguyên cấm chế"}]},"capNhatToi":"@c1309","nguon":["@c1309"]},{"id":"hu-hoa-chu-tuoc-cua-lao-gia","name":"Hư hỏa Chu Tước của lão giả","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"hỏa đạo Chu Tước","soHuu":["Chu Tước đời thứ hai"],"blurb":"Thần thông hỏa đạo do Chu Tước đời thứ hai thi triển khi áp chế Viêm long dưới hồ. Hư ảnh Chu Tước khổng lồ hợp vào tay trái như mỏ Chu Tước để xuyên đầu rồng lấy máu.","detail":"Khi Viêm long bị câu lên, Chu Tước đời thứ hai gọi ra hỏa vụ vô hình và hư ảnh Chu Tước cực lớn mang hư hỏa. Thần thông này áp đảo hung thú có uy áp ngang bước thứ ba, giúp lão xuyên vào chỗ nhô trên đầu rồng để lấy máu.","thuocTinh":"hỏa đạo, hư hỏa Chu Tước","uyLuc":"Áp chế Viêm long có uy áp ngang tu sĩ bước thứ ba.","dacDiem":"Hư ảnh Chu Tước có thể ngưng tụ bên ngoài cánh tay trái, hóa thành thế công như mỏ Chu Tước.","congNang":["Áp chế Viêm long và xuyên đầu rồng lấy máu @c1310"],"nguoiTu":[{"ten":"Chu Tước đời thứ hai","tuChuong":"@c1310","tangDatToi":"khong-ro","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1310","loai":"thi triển","importance":"normal","giaiDoan":"Áp chế Viêm long","text":"Chu Tước đời thứ hai thi triển hư ảnh Chu Tước và hỏa vụ để áp chế Viêm long, rồi ngưng lực vào tay trái xuyên vào đầu rồng lấy máu.","anchor":"hư ảnh Chu Tước cực lớn kia bắt đầu khởi động, lao thẳng tới ngưng tụ bên ngoài cánh tay trái"}]},"capNhatToi":"@c1310","nguon":["@c1310"]},{"id":"hoa-bon-nguyen-cua-vuong-lam","name":"Hỏa bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hỏa bổn nguyên của Vương Lâm hiện ra khi Chu Tước đời thứ hai kích phát lực lượng trong thiên linh hắn.","detail":"Đạo bổn nguyên này mang nhiệt độ kinh người và khí tức khiến người ta hít thở không thông. Chu Tước đời thứ hai dường như đã biết trước Vương Lâm có hỏa bổn nguyên, nhưng vẫn dùng nó làm khởi điểm để phát hiện các đạo bổn nguyên còn lại.","congNang":["Hiển hóa hỏa bổn nguyên từ thiên linh khi bị kích phát @c1311"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"đã có hỏa bổn nguyên","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiển hóa trước Chu Tước đời thứ hai","text":"Hỏa bổn nguyên của Vương Lâm hiện ra trong lần Chu Tước đời thứ hai kiểm tra thiên linh hắn.","anchor":"bên trong ẩn chứa hỏa bổn nguyên của Vương Lâm"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"loi-bon-nguyen-cua-vuong-lam","name":"Lôi bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"đại thành","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Lôi bổn nguyên của Vương Lâm hiện thành lôi đồ khi bị Chu Tước đời thứ hai kiểm tra.","detail":"Lôi bổn nguyên hóa thành lôi đồ với một ấn ký và chín tia lôi điện vờn quanh. Chu Tước đời thứ hai đánh giá đạo bổn nguyên này đã đại thành, tới trình độ có thể mở không môn.","congNang":["Hiển hóa lôi đồ bổn nguyên với ấn ký và chín tia lôi điện @c1311","Đạt trình độ có thể mở không môn @c1311"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Được đánh giá đại thành","text":"Lôi bổn nguyên của Vương Lâm hiện ra và được Chu Tước đời thứ hai nhận định đã đạt mức có thể mở không môn.","anchor":"Lôi bổn nguyên này đã đại thành rồi, tới trình độ có thể mở không môn"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"sinh-tu-bon-nguyen-cua-vuong-lam","name":"Sinh tử bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên / ý cảnh","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Sinh tử bổn nguyên của Vương Lâm là đạo bổn nguyên biến hóa từ sinh tử ý cảnh.","detail":"Khi hiển hóa trước Chu Tước đời thứ hai, đạo bổn nguyên này biến thành Hoàng Tuyền hư ảo do sinh tử luân hồi tạo thành, quét ngang trời và bộc phát khí tức sinh tử.","congNang":["Hiển hóa Hoàng Tuyền hư ảo do sinh tử luân hồi tạo thành @c1311"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"đã thành bổn nguyên","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Sinh tử ý cảnh thành bổn nguyên","text":"Sinh tử ý cảnh của Vương Lâm hiển hóa thành sinh tử bổn nguyên dưới dạng Hoàng Tuyền hư ảo.","anchor":"Đây chính là sinh tử ý cảnh của Vương Lâm biến thành bổn nguyên"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"nhan-qua-bon-nguyen-cua-vuong-lam","name":"Nhân quả bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên / ý cảnh","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Nhân quả bổn nguyên của Vương Lâm hiển hóa thành Thái Cực đồ hư ảo.","detail":"Đạo bổn nguyên này ẩn chứa nhân quả, khiến thiên địa hỗn loạn và có thể cuốn tu sĩ khác vào lực lượng nhân quả, dẫn tới tâm ma và tự hủy.","congNang":["Hiển hóa Thái Cực đồ ẩn chứa nhân quả @c1311","Có thể khiến tu sĩ bị lực lượng nhân quả quấn lấy mà sinh tâm ma @c1311"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"đã thành bổn nguyên","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Thái Cực đồ nhân quả","text":"Nhân quả bổn nguyên của Vương Lâm hiển hóa thành Thái Cực đồ hư ảo trước Chu Tước đời thứ hai.","anchor":"Thái Cực đồ này ẩn chứa nhân quả"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"chan-gia-bon-nguyen-cua-vuong-lam","name":"Chân giả bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chân giả bổn nguyên là đạo bổn nguyên thứ năm hiện ra trong lần Chu Tước đời thứ hai kiểm tra Vương Lâm.","detail":"Đạo bổn nguyên này có ánh sáng quỷ dị như tồn tại lại như không, biến đổi giữa thật và giả, khiến hình ảnh đi kèm vừa chân thật vừa hư ảo.","dacDiem":"Biến hóa giữa chân và giả, tồn tại như có như không.","congNang":["Tạo biến hóa chân giả khiến hình ảnh đổi thay giữa thật và hư @c1311"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"đã có chân giả bổn nguyên","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Đạo bổn nguyên thứ năm","text":"Chân giả bổn nguyên của Vương Lâm hiện ra như đạo bổn nguyên thứ năm, biến đổi giữa thật và giả.","anchor":"bị vây trong chân giả, nhanh chóng thay đổi"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"bi-thuat-van-luc-huyen-vu","name":"Bí thuật vận lực Huyền Vũ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Huyền Vũ","soHuu":["Chu Tước đời thứ hai","Vương Lâm"],"blurb":"Bí thuật vận lực Huyền Vũ là phương pháp vận dụng lực lượng mà Chu Tước đời thứ hai chuẩn bị truyền cho Vương Lâm.","detail":"Chu Tước đời thứ hai nói đây không phải thần thông mà là một phương pháp vận dụng lực lượng. Vì Vương Lâm có thân thể Cổ Thần, nếu dùng thuật này thi triển thì uy lực sẽ càng mạnh.","nguonGoc":"Liên quan mạch Huyền Vũ, được Chu Tước đời thứ hai chọn từ hệ bí thuật đoạt được của tam tộc.","congNang":["Vận dụng lực lượng thân thể để tăng uy lực thi triển @c1311"],"nguoiTu":[{"ten":"Chu Tước đời thứ hai","tuChuong":"@c1311","tangDatToi":"nắm giữ và truyền thụ","trangThai":"dang-tu"},{"ten":"Vương Lâm","tuChuong":"@c1311","tangDatToi":"chuẩn bị tiếp nhận","trangThai":"sap-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1311","loai":"xuất hiện","importance":"normal","giaiDoan":"Được chọn truyền cho Vương Lâm","text":"Chu Tước đời thứ hai chọn bí thuật vận lực Huyền Vũ để truyền cho Vương Lâm vì thân thể Cổ Thần của hắn phù hợp với phương pháp này.","anchor":"Đây cũng không phải là thần thông mà là một phương pháp vận dụng lực lượng"}]},"capNhatToi":"@c1311","nguon":["@c1311"]},{"id":"dung-luc-phan-chan-chung-dao","name":"Dùng lực phản chấn chứng đạo","cn":"","aliases":["bí thuật vận dụng lực lượng"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Chu Tước tộc; Cổ Thần","soHuu":["Lão Chu Tước","Vương Lâm"],"blurb":"Bí thuật vận dụng lực lượng do Lão Chu Tước dùng phép thử trên hồ nước để dẫn dắt Vương Lâm tự ngộ. Trọng tâm nằm ở việc mượn phản lực của vật bị công kích để gia tăng uy lực quyền kình, đặc biệt thích hợp với thân Cổ Thần vốn thiên về lực lượng thân thể.","detail":"Lão Chu Tước biểu diễn một chưởng lên mặt hồ nước, khiến Vương Lâm quan sát và nhận ra rằng khi lực đánh xuống càng mạnh thì phản lực từ đối tượng bị đánh cũng càng lớn. Từ nguyên lý đó, Vương Lâm tự suy ra rằng một quyền đánh ra không chỉ dựa vào lực bản thân người tu mà còn có thể mượn chính lực phản chấn của đối tượng để quay ngược lại giết địch, khiến uy lực quyền kình tăng vọt vượt xa sức lực gốc. Phương thức chứng đạo này đặc biệt khế hợp với thân Cổ Thần vì cốt lõi hoàn toàn xoay quanh cách vận dụng lực lượng thân thể thay vì pháp lực hay thần thông.","thuocTinh":"vận lực; phản chấn","nguonGoc":"Do Lão Chu Tước truyền thông qua phép thử trên hồ nước.","uyLuc":"Có thể giúp quyền kình mượn phản lực của đối tượng để tăng mạnh sát thương, khiến uy lực vượt xa sức lực bản thân người xuất quyền.","dacDiem":"Đặc biệt khế hợp với thân Cổ Thần vì trọng tâm nằm hoàn toàn ở cách vận dụng lực lượng thân thể, không dựa vào pháp lực hay thần thông.","congNang":["Mượn lực phản chấn từ vật bị công kích để gia tăng uy lực quyền kình vượt xa sức lực gốc của bản thân @c1312","Giúp người tu nhận ra phản lực của đối tượng bị đánh có thể lợi dụng ngược lại để sát thương đối phương @c1312"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1312","tangDatToi":"mới ngộ nguyên lý","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1312","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm tự ngộ nguyên lý phản chấn","text":"Lão Chu Tước dùng hồ nước dẫn dắt Vương Lâm quan sát lực phản chấn. Vương Lâm tự suy ra cách mượn phản lực để tăng uy lực quyền kình.","anchor":"mượn lực phản chấn mà giết địch, uy lực tăng mạnh"}]},"capNhatToi":"@c1312","nguon":["@c1312"]},{"id":"doc-cong-cua-thai-hoang-cong","name":"Độc công của Thái Hoang Công","cn":"","loai":"cong-phap","loaiLabel":"Công pháp độc thuật","phamCap":"","hePhai":"","soHuu":["Thái Hoang Công"],"blurb":"Độc thuật làm nên hung danh của Thái Hoang Công, được lão Chu Tước nhắc tới khi giới thiệu ông với Vương Lâm.","detail":"Thái Hoang Công nổi danh nhờ một thân độc công. Trong chương này, độc công ấy còn được chứa trong nửa đoạn móng tay mà ông búng tới cho Vương Lâm làm vật phòng thân, được lão Chu Tước xem là lợi khí có thể dùng để đả thương địch thủ.","nguon":["@c1313"]},{"id":"thi-luyen-thieu-de-vung-dat-dien-lac","name":"Thí luyện thiếu đế vùng đất Điên Lạc","cn":"","aliases":[],"loai":"khac","loaiLabel":"Thí luyện huyễn giới","phamCap":"khong-ro","hePhai":"Vùng đất Điên Lạc","soHuu":["Lão Chu Tước"],"blurb":"Thí luyện chọn thiếu đế của vùng đất Điên Lạc, vận hành qua ba cây hương đại biểu Thiên, Địa, Nhân. Người thí luyện đưa hồn vào huyễn giới và phải thoát ra trước khi hương cháy hết.","detail":"Thí luyện gồm ba huyễn giới Thiên, Địa, Nhân, mỗi cửa dùng một cây hương làm vật dẫn. Hồn phách người thí luyện nhập vào trong hương, phải kéo chậm tốc độ cháy và trở về thân thể kịp thời, nếu không hồn phách sẽ bị thiêu đốt mà chết.","thuocTinh":"huyễn giới, khảo nghiệm hồn phách","uyLuc":"Có thể trực tiếp uy hiếp hồn phách người thí luyện nếu không thoát ra trước khi hương tàn.","dacDiem":"Từ trước đến chương này chỉ có rất ít người được nói là từng thành công vượt qua thí luyện.","congNang":["Thử luyện hồn phách qua ba huyễn giới Thiên, Địa, Nhân @c1314","Ép người thí luyện vừa nhập huyễn giới vừa tranh thời gian với tốc độ cháy của hương @c1314"],"trangThai":"đang mở cho Vương Lâm","capNhatToi":"@c1314","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1314","tangDatToi":"cửa thứ nhất Nhân giới","trangThai":"đang thí luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1314","loai":"xuất hiện","importance":"normal","giaiDoan":"Công bố quy tắc","text":"Lão Chu Tước công bố ba cây hương đại biểu Thiên, Địa, Nhân ba huyễn giới và yêu cầu người thí luyện đưa hồn vào từng giới.","anchor":"Ba cây hương đại biểu cho Thiên, Địa, Nhân ba huyễn giới mà người đều phải đưa hồn vào"}]},"nguon":["@c1314"]},{"id":"nhan-gioi-huyen-canh","name":"Nhân giới huyễn cảnh","cn":"","aliases":["Nhân giới trong Thiên, Địa, Nhân"],"loai":"khac","loaiLabel":"Huyễn giới","phamCap":"khong-ro","hePhai":"Thí luyện thiếu đế vùng đất Điên Lạc","soHuu":["Lão Chu Tước"],"blurb":"Cửa thí luyện thứ nhất trong ba huyễn giới Thiên, Địa, Nhân. Huyễn cảnh hiện thành một thành trì phàm nhân như mộng, dùng để khảo nghiệm hồn phách người nhập thí luyện.","detail":"Khi Vương Lâm nhập cây hương thứ nhất, Nhân giới huyễn cảnh hiện ra thành thành trì phàm nhân có cầu, sông, phố xá, thuyền và người qua lại. Phần lớn cảnh vật đều mờ ảo như mộng, nhưng thanh niên trên thuyền lại hiện ra rõ ràng và khiến Vương Lâm chấn động.","thuocTinh":"huyễn cảnh phàm nhân","uyLuc":"Có thể bao phủ hồn phách người thí luyện vào cảnh phàm nhân mơ hồ, nơi thật giả khó phân.","dacDiem":"Cảnh vật xung quanh mờ ảo, riêng thanh niên trên thuyền được ghi nhận là rõ ràng khác thường.","congNang":["Tạo huyễn cảnh phàm nhân để khảo nghiệm hồn phách trong cửa thứ nhất @c1314"],"trangThai":"đang vận hành trong thí luyện của Vương Lâm","capNhatToi":"@c1314","tabs":{"tienTrinh":[{"chuong":"@c1314","loai":"xuất hiện","importance":"normal","giaiDoan":"Cửa thứ nhất","text":"Nhân giới huyễn cảnh được xác định là cửa thí luyện thứ nhất trong Thiên, Địa, Nhân và là nơi hồn phách Vương Lâm tiến vào.","anchor":"cửa thí luyện thứ nhất, chính là Nhân giới trong Thiên , Địa, Nhân"}]},"nguon":["@c1314"]},{"id":"cua-nhan-nhan-luyen","name":"Cửa Nhân / Nhân luyện","cn":"","aliases":["Nhân luyện","Cửa Nhân"],"loai":"bi-thuat","loaiLabel":"Thí luyện huyễn cảnh","phamCap":"Không rõ","hePhai":"Thí luyện ba cây hương Thiên Địa Nhân","soHuu":[],"blurb":"Cửa Nhân là một cửa thí luyện huyễn cảnh trong ba cây hương Thiên Địa Nhân. Chương này lộ rõ bản chất của nó không phải vấn đạo mà là tâm ma, đưa hồn Vương Lâm vào một nhân sinh phàm tục giả định.","detail":"Khi Vương Lâm lấy hồn tiến vào, Cửa Nhân tái hiện Triệu quốc, quê cũ, Hằng Nhạc phái và Lạc Hà môn, đồng thời tạo ra một thanh niên phàm nhân giống hệt hắn như hư hồn nhân sinh. Khảo nghiệm này nhằm lay động đạo tâm bằng tâm ma và những điểm đau sâu nhất trong lòng hắn.","thuocTinh":"huyễn cảnh, tâm ma","uyLuc":"Có thể khiến hồn người thí luyện trải qua hư hồn nhân sinh và kéo theo phản ứng đau buồn lên thân thể ngoài giới.","dacDiem":"Không vận hành như vấn đạo của Thiên Vận Tử mà trực tiếp đánh vào tâm ma và cố nhân trong lòng người thí luyện.","congNang":["Tạo tâm ma và hư hồn nhân sinh để khảo nghiệm người tiến vào @c1315"],"trangThai":"đang được Vương Lâm trải qua","capNhatToi":"@c1315","nguon":["@c1315"],"tabs":{"tienTrinh":[{"chuong":"@c1315","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ bản chất tâm ma","text":"Cửa Nhân đưa hồn Vương Lâm vào một nhân sinh phàm tục giả định và được hắn nhận ra là tâm ma chứ không phải vấn đạo.","anchor":"nơi này không phải là vấn đạo mà là tâm ma"}]}},{"id":"bach-quang-chua-thuong-cua-vuong-lam","name":"Bạch quang chữa thương của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông chữa thương Vương Lâm dùng trong Nhân giới thí luyện để cứu thú nhỏ trước mặt Lý Mộ Uyển.","detail":"Vương Lâm phất tay hoặc vuốt tay tạo bạch quang rơi vào thú nhỏ bị thương, khiến vết thương nhanh chóng khép lại và sinh cơ hồi phục. Thần thông này được dùng hai lần trong chương để cứu thú nhỏ và làm giảm sự cảnh giác của Lý Mộ Uyển.","thuocTinh":"chữa thương, sinh cơ","uyLuc":"Có thể làm vết thương trên thú nhỏ khép lại nhanh chóng.","dacDiem":"Biểu hiện dưới dạng bạch quang rơi vào thân thể mục tiêu.","congNang":["Khép vết thương và rót sinh cơ cho thú nhỏ bị thương @c1316"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1316","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1316","loai":"thi triển","importance":"normal","giaiDoan":"Cứu thú nhỏ trong Nhân giới","text":"Vương Lâm dùng bạch quang chữa thương cho thú nhỏ trước mặt Lý Mộ Uyển, khiến vết thương nhanh chóng khép lại.","anchor":"Vết thương trên người con thú nhanh chóng khép lại"}]},"capNhatToi":"@c1316","nguon":["@c1316"]},{"id":"bat-diet-hon-hoa","name":"Bất diệt hồn hỏa","cn":"","loai":"cong-phap","loaiLabel":"Hồn hỏa tu luyện Chu Tước","phamCap":"không rõ","hePhai":"Chu Tước tộc","soHuu":["Chu Tước tộc"],"blurb":"Bất diệt hồn hỏa là loại hồn hỏa đặc thù sinh ra trong thí luyện của Chu Tước tộc, được tạo thành bằng cách thiêu đốt phàm niệm và thế giới huyễn hóa trong hồn. Ngọn lửa này có tác dụng trợ lực cho lần thức tỉnh Chu Tước thứ tư, được lão Chu Tước đề cập tại thí luyện cây hương thứ nhất nhưng Vương Lâm đã từ chối con đường này.","detail":"Trong thí luyện cây hương thứ nhất của Chu Tước tộc, lão Chu Tước đã giảng giải cơ chế sinh ra Bất diệt hồn hỏa: dùng hỏa diễm trong hồn thiêu cháy thế giới huyễn hóa, đốt sạch phàm niệm ngoài hồn, rồi dung hợp lửa vào hồn để sinh ra một tia hồn hỏa bất diệt. Tia hồn hỏa này chính là điều kiện then chốt thúc đẩy Chu Tước thức tỉnh lần thứ tư. Tuy nhiên, cái giá phải trả là hủy diệt toàn bộ thế giới huyễn hóa trong hồn — nơi có sự tồn tại của Lý Mộ Uyển. Vương Lâm đã từ chối con đường này vì không chấp nhận cái giá ấy.","thuocTinh":"hồn hỏa, hư hỏa Chu Tước","nguonGoc":"Thí luyện Chu Tước tộc","uyLuc":"Có thể trợ lực cho lần thức tỉnh Chu Tước thứ tư.","dacDiem":"Lấy việc đốt phàm niệm và thế giới trong hồn làm điều kiện sinh hỏa.","congNang":["Tạo một tia hồn hỏa bất diệt để thúc đẩy Chu Tước thức tỉnh lần thứ tư @c1316"],"tabs":{"tienTrinh":[{"chuong":"@c1316","loai":"xuất hiện","importance":"major","giaiDoan":"Cơ chế cây hương thứ nhất","text":"Lão Chu Tước nêu cách đốt hương để sinh bất diệt hồn hỏa cho lần thức tỉnh Chu Tước thứ tư, nhưng Vương Lâm không chấp nhận cái giá ấy.","anchor":"giao một tia hồn hỏa bất diệt, khiến cho Chu Tước thức tỉnh lần thứ tư"}]},"capNhatToi":"@c1316","nguon":["@c1316"]},{"id":"nghiep-hoa-nhap-hon","name":"Nghiệp hỏa nhập hồn","aliases":["Chấp nghiệp đốt nghiệp chướng luân hồi"],"cn":"","loai":"cong-phap","loaiLabel":"Hồn hỏa tu luyện Chu Tước","phamCap":"không rõ","hePhai":"Chu Tước tộc","soHuu":["Vương Lâm","Chu Tước đời đầu"],"blurb":"Nghiệp hỏa nhập hồn là con đường hư hỏa của Chu Tước tộc, lấy chấp niệm bản thân hóa thành nghiệp hỏa để thay thế bất diệt hồn hỏa trong lần thức tỉnh Chu Tước thứ tư. Đây là con đường cực kỳ gian nan, từ cổ chí kim chỉ có Chu Tước đời đầu từng thành công.","detail":"Khi đối diện yêu cầu đốt Nhân giới để hoàn thành lần thức tỉnh Chu Tước thứ tư, Vương Lâm đã dứt khoát từ chối và tuyên bố sẽ đi con đường khác: lấy chấp niệm của chính mình hóa thành nghiệp hỏa, dùng chấp nghiệp đốt nghiệp chướng luân hồi thay cho việc mượn bất diệt hồn hỏa. Lão Chu Tước xác nhận đây chính là con đường hư hỏa mà lão tổ Chu Tước đời đầu từng thành công, nhưng cũng là con đường gần như không ai có thể tái hiện. Nếu thành công, địa vị của Vương Lâm trong Chu Tước tộc sẽ vượt trội hơn hẳn con đường thông thường.","thuocTinh":"nghiệp hỏa, hồn hỏa, chấp niệm","nguonGoc":"Con đường hư hỏa Chu Tước được Chu Tước đời đầu từng thành công","yeuCau":"Cần lấy chấp niệm bản thân hóa nghiệp hỏa, không đi theo cách mượn bất diệt hồn hỏa.","uyLuc":"Có thể thay thế bất diệt hồn hỏa trong lần thức tỉnh Chu Tước thứ tư và mở ra con đường vượt trội trong Chu Tước tộc, ngang tầm thành tựu của Chu Tước đời đầu.","dacDiem":"Cực kỳ gian nan, bị xem là con đường từ cổ chí kim gần như không ai thành công ngoài Chu Tước đời đầu; cốt lõi nằm ở việc lấy chấp niệm cá nhân làm nguồn lửa thay vì dựa vào ngoại lực.","congNang":["Thay thế bất diệt hồn hỏa bằng nghiệp hỏa do chấp niệm bản thân sinh ra, hoàn thành lần thức tỉnh Chu Tước thứ tư theo con đường khác @c1316","Đốt nghiệp chướng luân hồi bằng chấp nghiệp thay vì phải hủy diệt một thế giới @c1316"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1316","tangDatToi":"bắt đầu lựa chọn con đường nghiệp hỏa","trangThai":"đang ngộ"},{"ten":"Chu Tước đời đầu","tuChuong":"@c1316","tangDatToi":"từng thành công","trangThai":"được nhắc tới"}],"tabs":{"tienTrinh":[{"chuong":"@c1316","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm chọn nghiệp hỏa","text":"Vương Lâm từ chối hủy diệt Nhân giới và tuyên bố lấy chấp niệm hóa nghiệp hỏa để đốt nghiệp chướng luân hồi.","anchor":"dùng chấp nghiệp đốt lên nghiệp chướng luân hồi"}]},"capNhatToi":"@c1316","nguon":["@c1316"]},{"id":"thi-luyen-dot-cay-huong-thu-nhat","name":"Thí luyện đốt cây hương thứ nhất","cn":"","loai":"bi-thuat","loaiLabel":"Nghi thức thí luyện","phamCap":"không rõ","hePhai":"Chu Tước tộc","soHuu":["Lão Chu Tước","Vương Lâm"],"blurb":"Thí luyện đầu tiên trong ba cây hương Thiên Địa Nhân, yêu cầu dùng hỏa diễm trong hồn thiêu rụi Nhân giới để đốt hương.","detail":"Lão Chu Tước nói muốn đốt cây hương thứ nhất thì phải dùng hỏa diễm trong hồn, trong thời gian ngắn biến toàn bộ thế giới Nhân giới thành biển lửa, không để lại gì. Vương Lâm không chịu dùng cách này vì thế giới ấy có Lý Mộ Uyển.","thuocTinh":"hư hỏa, thí luyện hồn tâm","nguonGoc":"Thí luyện thiếu đế Chu Tước tộc","uyLuc":"Có thể mở điều kiện thông qua cây hương thứ nhất nếu người thí luyện thiêu rụi toàn bộ thế giới huyễn hóa.","dacDiem":"Đòi hỏi người thí luyện tự tay đốt phàm niệm trong hồn.","congNang":["Ma luyện hồn tâm và mở điều kiện vượt qua cây hương thứ nhất @c1316"],"tabs":{"tienTrinh":[{"chuong":"@c1316","loai":"xuất hiện","importance":"normal","giaiDoan":"Lão Chu Tước thúc đốt hương","text":"Lão Chu Tước yêu cầu Vương Lâm dùng hỏa diễm trong hồn biến toàn bộ Nhân giới thành biển lửa để đốt cây hương thứ nhất.","anchor":"trong thời gian ngắn khiến toàn bộ thế giới này thành biển lửa"}]},"capNhatToi":"@c1316","nguon":["@c1316"]},{"id":"phap-bao-huyen-hoa-nhan-gioi-cua-chu-tuoc-doi-dau","name":"Pháp bảo huyễn hóa Nhân giới của Chu Tước đời đầu","cn":"","loai":"khac","loaiLabel":"Pháp bảo/thần thông tạo giới","phamCap":"không rõ","hePhai":"Chu Tước tộc","soHuu":["Chu Tước đời đầu"],"blurb":"Pháp bảo hoặc thần thông do Chu Tước đời đầu để lại, huyễn hóa ra Nhân giới thí luyện trong hồn Vương Lâm.","detail":"Nơi thí luyện được nói là do Chu Tước đời đầu dùng pháp bảo huyễn hóa ra, tạo thành một thế giới trong hồn như thật. Thần thông của pháp bảo này sâu tới mức lão Chu Tước dù ở bên ngoài cũng không thể thật sự can thiệp.","thuocTinh":"huyễn hóa, tạo giới, thí luyện","nguonGoc":"Chu Tước đời đầu","uyLuc":"Tạo thế giới hồn như thực và hạn chế sự can thiệp của người ngoài.","dacDiem":"Gắn trực tiếp với Nhân giới trong thí luyện cây hương thứ nhất.","congNang":["Huyễn hóa Nhân giới thí luyện trong hồn người thí luyện @c1316","Khiến lão Chu Tước ở bên ngoài cũng khó can thiệp vào bên trong @c1316"],"tabs":{"tienTrinh":[{"chuong":"@c1316","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ nguồn gốc Nhân giới","text":"Chương hé lộ Nhân giới thí luyện do Chu Tước đời đầu dùng pháp bảo huyễn hóa ra, nên lão Chu Tước không thể tùy ý can thiệp.","anchor":"do Chu Tước đời đầu dùng pháp bảo huyễn hóa ra"}]},"capNhatToi":"@c1316","nguon":["@c1316"]},{"id":"hu-hoa","name":"Hư hỏa","cn":"","loai":"than-thong","loaiLabel":"Cảnh giới/thần thông hỏa bổn nguyên","phamCap":"Sau thực hỏa","hePhai":"Chu Tước","soHuu":[],"blurb":"Hư hỏa là cảnh giới nằm sau thực hỏa trong đường tu luyện hỏa hệ của Chu Tước, đã vượt khỏi phạm trù hỏa thuộc ngũ hành thông thường. Ở cảnh giới này, người tu có thể lấy dao động tâm tình của sinh linh làm thần thông công kích, đủ khiến tu sĩ bước thứ ba coi trọng. (+) Cảnh giới hỏa pháp đạt được sau khi thức tỉnh Chu Tước lần thứ tư, nghiệp chướng luân hồi cửu sắc đốt lên. Có thể cảm nhận tâm tình trên người khác và biến chúng thành ngọn lửa. [CAN-SOAT-GOP]","detail":"Hư hỏa là cảnh giới tu luyện hỏa đạo kế tiếp sau thực hỏa, được mô tả là đã thoát ra ngoài phạm trù ngũ hành hỏa thông thường. Đặc trưng cốt lõi của hư hỏa nằm ở chỗ biến mọi dao động cảm xúc của sinh linh — bao gồm tưởng niệm, trìu mến, hỉ nộ ái ố — thành điểm phát động thần thông. Cảnh giới này được đánh giá là đáng sợ, đủ nền tảng để giao chiến ở cấp rất cao và khiến tu sĩ bước thứ ba phải coi trọng. Nếu tiến thêm một bước từ hư hỏa sẽ đạt đạo hỏa, khi đó người tu có thể dùng lửa mở Không môn.","thuocTinh":"Hỏa vượt ngũ hành, tác động qua tâm tình","uyLuc":"Có thể khiến tu sĩ bước thứ ba coi trọng và đủ nền tảng để giao chiến ở cấp rất cao.","dacDiem":"Biến dao động cảm xúc như tưởng niệm, trìu mến, hỉ nộ ái ố thành điểm phát động thần thông.","congNang":["Lấy dao động tâm tình của sinh linh làm thần thông công kích @c1317"],"tabs":{"tienTrinh":[{"chuong":"@c1317","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ bản chất","text":"Hư hỏa được giải thích là cảnh giới sau thực hỏa, có thể biến tâm tình của sinh linh thành thần thông giết địch.","anchor":"Người có thể đạt tới cảnh giới hư hỏa thì sự cường đại tuy không bằng tu sĩ bước thứ ba"}]},"capNhatToi":"@c1317","nguon":["@c1317","@c1324"]},{"id":"nghiep-hoa","name":"Nghiệp hỏa","cn":"","loai":"than-thong","loaiLabel":"Ngọn lửa chấp niệm/kiếp hỏa","phamCap":"Kiếp hỏa","hePhai":"Chu Tước","soHuu":["Vương Lâm"],"blurb":"Nghiệp hỏa là ngọn lửa màu đen do chấp niệm hóa thành, lần đầu bùng lên trong hồn phách Vương Lâm tại Nhân phương giới. Ngọn lửa này áp đảo lửa lam thiêu hồn, nhanh chóng lan rộng và bắt đầu hủy diệt cả hồn phách lẫn thân thể hắn, mở ra mốc Cửu chuyển nghiệp kiếp thật sự.","detail":"Nghiệp hỏa xuất hiện dưới hình thức tia lửa màu đen, bùng phát ngay bên trong hồn phách Vương Lâm khi hắn đang chịu ngọn lửa lam thiêu hồn. Ngọn lửa đen này áp đảo lửa lam, lan khắp thân thể và khởi động quá trình hủy diệt đồng thời hồn phách cùng thân thể của Vương Lâm. Đây chính là mốc khiến Cửu chuyển nghiệp kiếp thật sự mở ra.","thuocTinh":"Chấp niệm hóa hỏa","uyLuc":"Có thể nhanh chóng hủy diệt hồn phách và thân thể người chịu kiếp, áp đảo ngọn lửa lam thiêu hồn.","dacDiem":"Tia lửa màu đen bùng lên dưới ngọn lửa lam thiêu hồn, phát sinh từ bên trong hồn phách.","congNang":["Thiêu đốt và hủy diệt hồn phách, thân thể người chịu kiếp @c1317"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1317","tangDatToi":"Nghiệp hỏa vừa bùng lên","trangThai":"đang chịu kiếp"}],"tabs":{"tienTrinh":[{"chuong":"@c1317","loai":"xuất hiện","importance":"major","giaiDoan":"Chấp niệm hóa hỏa","text":"Nghiệp hỏa lần đầu bùng lên thành tia lửa đen trong hồn phách Vương Lâm và bắt đầu hủy diệt hắn.","anchor":"Cũng dưới ngọn lửa này còn có một tia lửa đen đột nhiên bùng lên"}]},"capNhatToi":"@c1317","nguon":["@c1317"]},{"id":"cuu-chuyen-nghiep-kiep","name":"Cửu chuyển nghiệp kiếp","aliases":["Cửu Chuyển Nghiệp Hỏa Kiếp"],"cn":"","loai":"bi-thuat","loaiLabel":"Kiếp nạn nghiệp hỏa","phamCap":"Kiếp nạn Chu Tước thức tỉnh","hePhai":"Chu Tước","soHuu":["Vương Lâm"],"blurb":"Cửu chuyển nghiệp kiếp là kiếp nạn thật sự bắt đầu khi nghiệp hỏa xuất hiện.","detail":"Lão Chu Tước cảnh báo rằng trước khi nghiệp hỏa hiện ra, Vương Lâm mới chỉ bị thiêu hồn. Một khi nghiệp hỏa dấy lên, hồn phách có thể bị hủy diệt, và tiền lệ lão tổ năm xưa cũng cần Tiên Tôn bảo vệ.","yeuCau":"Nghiệp hỏa xuất hiện từ chấp niệm","dacDiem":"Cần hộ pháp hoặc năng lực ngăn cản đặc biệt, nguy cơ hủy hồn cực lớn.","congNang":["Là kiếp nạn nghiệp hỏa mà người thức tỉnh phải vượt qua @c1317"],"tabs":{"tienTrinh":[{"chuong":"@c1317","loai":"xuất hiện","importance":"normal","giaiDoan":"Được cảnh báo","text":"Lão Chu Tước cảnh báo Vương Lâm rằng chỉ khi nghiệp hỏa xuất hiện hắn mới thật sự trải qua Cửu chuyển nghiệp kiếp.","anchor":"Chỉ khi nào nghiệp hỏa xuất hiện ngươi mới trải qua Cửu chuyển nghiệp kiếp"}]},"capNhatToi":"@c1317","nguon":["@c1317"]},{"id":"dao-hoa","name":"Đạo hỏa","cn":"","loai":"than-thong","loaiLabel":"Đại bổn nguyên thuật","phamCap":"Sau hư hỏa","hePhai":"Hỏa bổn nguyên","soHuu":[],"blurb":"Đạo hỏa là bước tiến sau hư hỏa, được mô tả là đại bổn nguyên thuật có thể mở Không môn bằng lửa.","detail":"Chương đặt đạo hỏa như tuyến phát triển tiếp theo của hư hỏa. Khi hình thành đạo hỏa, người tu có thể dùng hỏa mở Không môn và thành tu sĩ bước thứ ba.","thuocTinh":"Hỏa bổn nguyên","congNang":["Dùng lửa mở Không môn để bước vào tầng thứ ba @c1317"],"tabs":{"tienTrinh":[{"chuong":"@c1317","loai":"nhắc tới","importance":"normal","giaiDoan":"Tuyến sau hư hỏa","text":"Đạo hỏa được nêu là bước tiến sau hư hỏa, có thể thành đại bổn nguyên thuật để mở Không môn.","anchor":"nếu tiến thêm một bước nữa, hình thành đạo hỏa thì có thể thành tựu đại bổn nguyên thuật"}]},"capNhatToi":"@c1317","nguon":["@c1317"]},{"id":"chu-tuoc-thuc-tinh-lan-thu-tu","name":"Chu Tước thức tỉnh lần thứ tư","cn":"","loai":"bi-thuat","loaiLabel":"Thức tỉnh huyết mạch/cảnh giới Chu Tước","phamCap":"Lần thứ tư","hePhai":"Chu Tước tộc","soHuu":["Vương Lâm"],"blurb":"Chu Tước thức tỉnh lần thứ tư là mốc đột phá then chốt đưa ngọn lửa Chu Tước từ thực hỏa bước vào cảnh giới hư hỏa. Điều kiện cốt lõi là chấp niệm phải hóa thành nghiệp hỏa trong tình thế cửu tử nhất sinh, đòi hỏi Vương Lâm tự thiêu hồn phách để mưu cầu mầm nghiệp hỏa.","detail":"Lần thức tỉnh thứ tư của Chu Tước được hé lộ tại @c1317 với điều kiện then chốt: từ chấp niệm sinh ra mầm nghiệp hỏa, qua đó chuyển hóa thực hỏa thành hư hỏa. Quá trình này mang nguy cơ hủy diệt hồn phách cực lớn. Tại @c1321, Vương Lâm hấp thu viêm huyết, long huyết cùng hư hỏa trợ lực từ lão Chu Tước và Chu Tước đời thứ tư để thúc đẩy lần thức tỉnh này. Đây là bước ngoặt quan trọng trong tiến trình tu luyện hỏa hệ của Vương Lâm, đánh dấu ngọn lửa Chu Tước vượt qua giới hạn thực hỏa, bước vào tầng thứ cao hơn là hư hỏa — cảnh giới mà chín màu hợp nhất.","yeuCau":"Chấp niệm hóa nghiệp hỏa","congNang":["Chuyển hóa thực hỏa thành hư hỏa sau khi chín màu hợp nhất @c1317","Từ chấp niệm sinh ra mầm nghiệp hỏa làm điều kiện đột phá @c1317","Hấp thu viêm huyết, long huyết và hư hỏa trợ lực từ lão Chu Tước cùng Chu Tước đời thứ tư để hoàn thành thức tỉnh @c1321"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1317","tangDatToi":"Hoàn thành","trangThai":"thanh-cong"}],"tabs":{"tienTrinh":[{"chuong":"@c1317","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Điều kiện thức tỉnh","text":"Điều kiện cốt lõi của lần thức tỉnh thứ tư được hé lộ là từ chấp niệm sinh ra mầm nghiệp hỏa để bước từ thực hỏa vào hư hỏa.","anchor":"vì thế mà có có hội khiến Chu Tước thức tỉnh lần thứ tư"},{"chuong":"@c1321","loai":"thi triển","importance":"major","giaiDoan":"Hoàn thành thức tỉnh lần bốn","text":"Vương Lâm hấp thu viêm huyết, long huyết và hư hỏa trợ lực từ lão Chu Tước và Chu Tước đời thứ tư, sau đó tự dùng đạo thuật hòa tan hai màu trắng đen cuối cùng, chín màu hợp nhất, Chu Tước mang hư hỏa lưu chuyển.","anchor":"Đây là lần thứ tư Chu Tước thức tỉnh, là một sự việc cực kỳ trọng đại trong bộ tộc Chu Tước"}]},"capNhatToi":"@c1317","nguon":["@c1317","@c1321"],"dacDiem":"Điều kiện thức tỉnh đòi hỏi chấp niệm hóa thành nghiệp hỏa trong tình thế cửu tử nhất sinh, mang nguy cơ hủy diệt hồn phách; cần trợ lực từ viêm huyết, long huyết và hư hỏa của lão Chu Tước cùng Chu Tước đời thứ tư."},{"id":"nghiep-hoa-do-chap-niem","name":"Nghiệp hỏa do chấp niệm","cn":"","loai":"than-thong","loaiLabel":"Thần thông / đạo niệm","phamCap":"Gắn với Chu Tước thức tỉnh lần thứ tư","hePhai":"Chu Tước hỏa đạo của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Nghiệp hỏa do chấp niệm là đạo niệm Vương Lâm xác lập trong Nhân phương giới, lấy chấp niệm của bản thân hóa thành nghiệp hỏa để đối kháng tử cục. Sức mạnh này thiêu đốt chính hồn thể hắn, đồng thời dẫn phát biến hóa khiến hồn phách hóa Chu Tước đen và đốt cháy cây hương thứ nhất trên Đại đế tinh.","detail":"Nghiệp hỏa do chấp niệm là căn cơ trực tiếp giúp Vương Lâm biến đổi trong Nhân phương giới. Khi lâm vào cảnh bị nghiệp hỏa thiêu diệt, Vương Lâm công khai xác lập con đường lấy chấp niệm nhập đạo, để niệm hóa nghiệp, biến chấp niệm thành nghiệp hỏa. Sức mạnh này lấy tình chấp với Lý Mộ Uyển làm gốc, đại giá là tự thân cũng bị nghiệp hỏa thiêu đốt, nhưng đổi lại mở đường cho hồn phách hắn hóa thành Chu Tước đen và đốt cháy Nhân phương hương.","thuocTinh":"Nghiệp hỏa, chấp niệm, Chu Tước hỏa đạo","uyLuc":"Có thể thiêu đốt chính hồn thể Vương Lâm, đồng thời dẫn phát biến hóa khiến cây hương thứ nhất trên Đại đế tinh bốc cháy.","dacDiem":"Lấy chấp niệm làm đạo, lấy niệm tạo nghiệp, đại giá là tự thân cũng bị nghiệp hỏa thiêu đốt.","congNang":["Chấp niệm hóa thành nghiệp hỏa để chống lại tử cục trong Nhân phương giới @c1318","Trợ hồn phách Vương Lâm hóa thành Chu Tước đen và đốt Nhân phương hương @c1318"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1318","tangDatToi":"Dùng chấp niệm nhập đạo và dẫn nghiệp hỏa đốt hương","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1318","loai":"xuất hiện","importance":"major","giaiDoan":"Chấp niệm nhập đạo","text":"Vương Lâm tuyên bố nghiệp hỏa do chấp niệm của mình tạo thành, dùng con đường này để hóa nghiệp và trợ Chu Tước thức tỉnh lần thứ tư.","anchor":"Nghiệp hỏa do chấp niệm của ta tạo thành. Ta lấy chấp niệm tu đạo, cả đời vì nàng!"}]},"capNhatToi":"@c1318","nguon":["@c1318"]},{"id":"nghiep-chuong-luan-hoi","name":"Nghiệp chướng luân hồi","cn":"","loai":"than-thong","loaiLabel":"Thần thông / đạo cảnh","phamCap":"Gắn với Chu Tước thức tỉnh lần thứ tư","hePhai":"Chu Tước hỏa đạo của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Nghiệp chướng luân hồi là trạng thái đạo cảnh được Vương Lâm khai mở khi lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp trong lúc thân hồn sắp tiêu tán. Trạng thái này nhóm lên nghiệp hỏa và trực tiếp trợ lực cho lần thức tỉnh thứ tư của Chu Tước tại Nhân phương giới.","detail":"Nghiệp chướng luân hồi xuất hiện tại chương 1318, khi Vương Lâm trong cảnh thân hồn sắp tiêu tán đã lấy chấp niệm nhập đạo, dùng niệm lực tạo thành nghiệp, từ đó hóa nghiệp chướng luân hồi. Từ trạng thái này, hắn nhóm lên nghiệp hỏa, biến chấp niệm thành ngọn lửa nghiệp chướng, hội tụ thành biển lửa và cột lửa xuyên lên thiên không Nhân phương giới. Quá trình này gắn trực tiếp với chấp niệm của Vương Lâm và đóng vai trò then chốt trong việc đẩy mạnh Chu Tước thức tỉnh lần thứ tư.","thuocTinh":"Nghiệp chướng, luân hồi, chấp niệm","uyLuc":"Có thể hội tụ nghiệp hỏa thành biển lửa và cột lửa xuyên lên thiên không Nhân phương giới.","dacDiem":"Gắn trực tiếp với chấp niệm của Vương Lâm và quá trình Chu Tước thức tỉnh lần thứ tư.","congNang":["Nhóm lên nghiệp chướng luân hồi bằng nghiệp hỏa do chấp niệm @c1318","Trợ Chu Tước thức tỉnh lần thứ tư trong Nhân phương giới @c1318"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1318","tangDatToi":"Dùng nghiệp hỏa nhóm nghiệp chướng luân hồi","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1318","loai":"xuất hiện","importance":"major","giaiDoan":"Nghiệp chướng luân hồi","text":"Vương Lâm lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp và hóa thành nghiệp chướng luân hồi để đẩy mạnh Chu Tước thức tỉnh.","anchor":"ta lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp, hóa thành nghiệp chướng luân hồi"}]},"capNhatToi":"@c1318","nguon":["@c1318"]},{"id":"de-nhat-chuyen-nghiep-hoa-kiep","name":"Đệ nhất chuyển nghiệp hỏa kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kiếp hỏa","phamCap":"khong-ro","hePhai":"","soHuu":[],"blurb":"Đệ nhất kiếp trong Cửu Chuyển Nghiệp Hỏa Kiếp, hiện thành ngọn lửa đỏ thiêu đốt Nhân phương giới và hồn phách Vương Lâm.","detail":"Ngọn lửa đỏ của đệ nhất chuyển đại diện cho sát kiếp do chấp niệm của Vương Lâm sinh ra. Nó thiêu đốt trực tiếp hồn phách, khiến Chu Tước màu đen dưới chân hắn bị nhuốm đỏ và có nguy cơ hóa thành một phần của kiếp hỏa.","congNang":["Thiêu đốt hồn phách và làm mục tiêu đứng trước nguy cơ tan vỡ @c1319"],"uyLuc":"Suýt khiến hồn phách vừa ngưng tụ của Vương Lâm tan vỡ.","dacDiem":"Hiện thành biển lửa đỏ tràn ngập Nhân phương giới.","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1319","loai":"xuất hiện","importance":"normal","giaiDoan":"Đệ nhất chuyển","text":"Đệ nhất chuyển nghiệp hỏa kiếp giáng xuống dưới dạng lửa đỏ và thiêu đốt hồn phách Vương Lâm trong Nhân phương giới.","anchor":"ngọn lửa màu đỏ này là đệ nhất kiếp"}]},"nguon":["@c1319"]},{"id":"chanh-hoang-luc-tam-kiep","name":"Chanh, Hoàng, Lục tam kiếp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Kiếp hỏa","phamCap":"khong-ro","hePhai":"","soHuu":[],"blurb":"Ba chuyển nghiệp hỏa màu cam, vàng và lục đồng thời giáng xuống khi đệ nhất kiếp chưa qua.","detail":"Chanh, Hoàng, Lục tam kiếp cho thấy Cửu Chuyển Nghiệp Hỏa Kiếp không chừa khoảng thở như Thiên Kiếp. Ba loại nghiệp hỏa cùng xuất hiện, tiếp tục bị Vương Lâm hút vào hồn phách khiến bốn ngọn lửa cùng thiêu đốt trong cơ thể hắn.","congNang":["Liên tiếp thiêu đốt và hủy diệt hồn phách sau đệ nhất chuyển @c1319"],"dacDiem":"Ba màu cam, vàng, lục đồng thời giáng xuống khi đệ nhất kiếp chưa được vượt qua.","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1319","loai":"xuất hiện","importance":"normal","giaiDoan":"Tam kiếp đồng giáng","text":"Ba chuyển nghiệp hỏa màu cam, vàng và lục đồng thời giáng xuống, buộc Vương Lâm phải đối mặt bốn tầng kiếp hỏa trong hồn phách.","anchor":"Chanh, Hoàng, Lục tam kiếp đồng thời giáng xuống"}]},"nguon":["@c1319"]},{"id":"ngon-lua-nghiep-chuong-luan-hoi","name":"Ngọn lửa nghiệp chướng luân hồi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hỏa đạo","soHuu":["Vương Lâm"],"blurb":"Ngọn lửa nghiệp chướng luân hồi là phép thuật Vương Lâm thi triển bằng cách đốt nghiệp chướng luân hồi của bản thân, ngưng chín màu kiếp hỏa thành bông sen lửa chín cánh tại mi tâm, từ đó mở ra lần thức tỉnh Chu Tước thứ tư.","detail":"Sau khi chín màu kiếp hỏa hội tụ tại mi tâm — kết quả của quá trình Thiên Nghịch hấp thu, ngưng luyện hư ảnh cùng hai kiếp đen trắng cuối cùng giáng xuống — Vương Lâm mở mắt tuyên bố đốt nghiệp chướng luân hồi. Chín ngọn lửa dung hợp thành một bông sen lửa chín cánh mang chín màu khác nhau ngay tại mi tâm hắn. Từ bông sen lửa ấy, Chu Tước chín màu bay ra, đánh dấu lần tỉnh giấc thứ tư của Chu Tước.","congNang":["Ngưng chín màu kiếp hỏa thành sen lửa chín cánh tại mi tâm @c1320","Mở ra lần thức tỉnh Chu Tước thứ tư @c1320"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1320","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1320","loai":"thi triển","importance":"major","giaiDoan":"Lần thi triển đầu tiên","text":"Vương Lâm mở mắt đốt lên nghiệp chướng luân hồi, chín màu lửa dung hợp thành sen lửa chín cánh tại mi tâm, Chu Tước chín màu bay ra tỉnh giấc lần thứ tư.","anchor":"Đốt lên ngọn lửa nghiệp chướng luân hồi của ta"}]},"nguon":["@c1320"]},{"id":"an-ky-chu-tuoc-nam-tu-trung-nien","name":"Ấn ký Chu Tước của nam tử trung niên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chu Tước","soHuu":["Nam tử trung niên trong Địa Phương giới"],"blurb":"Ấn ký Chu Tước từ mi tâm nam tử trung niên trong Địa Phương giới, phóng ra với tốc độ cực nhanh phá không mà đi để cứu viện Vương Lâm, nhưng bị sức mạnh Thiên Nghịch đánh bật.","detail":"Nam tử trung niên mặc văn bào ngồi trên ngọn núi trọc tận cùng Địa Phương giới phóng ấn ký Chu Tước từ mi tâm lao tới ngọn lửa bảy màu bao quanh Vương Lâm. Tuy nhiên ấn ký vừa chạm sức mạnh kỳ dị của Thiên Nghịch đã bị đánh bật ngược ra xa.","nguon":["@c1320"]},{"id":"dao-thuat-dung-hoa-van-vat","name":"Đạo thuật dung hòa vạn vật","cn":"","loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"","hePhai":"Đạo thuật","soHuu":["Vương Lâm"],"blurb":"Đạo thuật có sức mạnh dung hòa vạn vật trong trời đất, được Vương Lâm dùng để hòa tan hai màu trắng đen cuối cùng trong quá trình thức tỉnh Chu Tước lần bốn.","detail":"Khi hỏa lực đạt cực điểm và bảy màu đã tan, Vương Lâm không tiếp tục nuốt hỏa mà phóng sức mạnh đạo thuật từ cơ thể để hòa tan hai màu trắng đen còn lại trong cơn bão lửa, hoàn tất chín màu hợp nhất.","congNang":["Dung hòa hai màu trắng đen cuối cùng trong quá trình thức tỉnh Chu Tước"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1321","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1321","loai":"thi triển","importance":"normal","giaiDoan":"Dùng hòa tan hai màu trắng đen","text":"Vương Lâm tự dùng đạo thuật dung hòa vạn vật từ cơ thể để hòa tan hai màu trắng đen cuối cùng, không cần thêm trợ lực từ bên ngoài.","anchor":"sức mạnh này có thể dung hòa vạn vật trong trời đất"}]},"nguon":["@c1321"]},{"id":"la-ban-khong-lo-kim-la-ban-dai-de-tinh","name":"La bàn khổng lồ Đại đế tinh","cn":"","loai":"khac","loaiLabel":"Dị tượng tinh không","phamCap":"Không rõ","hePhai":"Thiên đạo","soHuu":[],"blurb":"Dị tượng tinh không xuất hiện khi Thiên Nghịch bộc phát. Đại đế tinh hóa kim la bàn xoay tròn, chỉ hướng Tây Nam và phóng u quang tới Phong Giới Đại Trận.","detail":"Vương Lâm thấy trong hồn phách hình ảnh la bàn khổng lồ ngang tinh không, tâm la bàn là hạt châu Thiên Nghịch. Bên ngoài, Đại đế tinh chấn động rồi hiện la bàn hư ảo bao quanh, trở thành kim la bàn xoay điên cuồng rồi dừng lại chỉ hướng Tây Nam, phát ra u quang xóa sạch mọi vật cản trên đường, lao tới Phong Giới Đại Trận.","congNang":["Hóa Đại đế tinh thành kim la bàn xoay, chỉ định phương hướng @c1322","Phóng u quang phá hủy mọi vật cản trên đường đi","Liên hệ với Thiên Nghịch ở trung tâm — tâm la bàn chính là hạt châu Thiên Nghịch"],"tabs":{"tienTrinh":[{"chuong":"@c1322","loai":"xuat-hien","importance":"major","giaiDoan":"Thiên Nghịch bộc phát, la bàn hiện hình","text":"Đại đế tinh chấn động rồi xoay như kim la bàn, bên ngoài xuất hiện la bàn hư ảo. Kim la bàn chỉ hướng Tây Nam và bắn u quang xóa sạch vật cản, lao tới Phong Giới Đại Trận. Trong hồn Vương Lâm cũng hiện la bàn khổng lồ ngang tinh không có Thiên Nghịch ở trung tâm.","anchor":"Đại đế tinh nằm giữa vật ấy ở bên ngoài nhìn lại trông giống như là một cây kim la bàn"}]},"nguon":["@c1322"],"dacDiem":"La bàn hư ảo xuất hiện bao quanh Đại đế tinh, quy mô ngang tinh không; kim la bàn xoay điên cuồng rồi dừng lại chỉ cố định một phương hướng."},{"id":"hu-hoa-chu-tuoc-bien-di","name":"Hư hỏa Chu Tước biến dị","cn":"","loai":"than-thong","loaiLabel":"Hỏa đạo thần thông","phamCap":"Không rõ","hePhai":"Hỏa đạo","soHuu":["Vương Lâm"],"blurb":"Hư hỏa của Chu Tước phát sinh biến dị sau khi bị từ lực Thiên Nghịch quét qua trong quá trình chuyển hóa từ thực hỏa sang hư hỏa ở lần thức tỉnh thứ tư. Hư hỏa này mang biến hóa quỷ dị khác thường, khiến ngay cả lão tổ Chu Tước đời đầu chứng kiến cũng phải rung động.","detail":"Trong lần thức tỉnh thứ tư của Chu Tước, toàn bộ thực hỏa tiến hành chuyển hóa sang hư hỏa — vốn là quá trình tự nhiên trong tiến hóa của linh thú Chu Tước. Tuy nhiên, đúng thời điểm chuyển hóa, sương mù từ lực do Thiên Nghịch phun ra quét qua, khiến thực hỏa tan nát và hóa thành hư hỏa mang biến hóa cực kỳ quỷ dị, hoàn toàn khác biệt so với hư hỏa Chu Tước thông thường. Mức độ dị biến nghiêm trọng đến nỗi lão tổ Chu Tước đời đầu — tồn tại có bề dày kiến thức lâu đời nhất về chủng tộc Chu Tước — khi chứng kiến cũng phải rung động.","tabs":{"tienTrinh":[{"chuong":"@c1322","loai":"xuat-hien","importance":"major","giaiDoan":"Hư hỏa phát sinh biến dị do từ lực Thiên Nghịch","text":"Thực hỏa của Chu Tước tan nát hóa hư hỏa, nhưng do bị từ lực Thiên Nghịch quét qua nên hư hỏa xuất hiện biến hóa quỷ dị khác thường.","anchor":"Chỉ là hư hỏa này vì bị từ lực quét qua nên bên trong cũng xuất hiện biến hóa"}]},"nguon":["@c1322"],"dacDiem":"Hư hỏa phát sinh biến hóa quỷ dị khác thường so với hư hỏa Chu Tước thông thường, là kết quả của sự giao thoa giữa quá trình chuyển hóa thực hỏa sang hư hỏa và từ lực Thiên Nghịch.","congNang":["Thực hỏa Chu Tước tan nát chuyển hóa thành hư hỏa mang biến dị quỷ dị do tác động của từ lực Thiên Nghịch @c1322"]},{"id":"hu-hoa-chu-tuoc-toc","name":"Hư hỏa của Chu Tước tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết mạch","phamCap":"Không rõ","hePhai":"Chu Tước tộc","soHuu":["Chu Tước tộc"],"blurb":"Hư hỏa là ngọn lửa diệt thế bẩm sinh của Chu Tước tộc, vô hình, số lượng cố định từ khi sinh ra và không thể tinh luyện thêm trong cơ thể tu sĩ. Trường hợp Vương Lâm là ngoại lệ duy nhất từ cổ chí kim khi có khả năng hấp thu thêm hư hỏa nhờ lực thiên đạo.","detail":"Hư hỏa bắt nguồn từ huyết mạch bẩm sinh của Chu Tước tộc, là ngọn lửa mang lực lượng diệt thế. Khác với hỏa diễm thông thường, hư hỏa hoàn toàn vô hình và có khả năng thiêu đốt tâm tình của đối phương thay vì tác động lên thể xác đơn thuần. Mỗi tu sĩ Chu Tước tộc sở hữu một số lượng hư hỏa cố định ngay từ khi sinh ra, không có cách nào tự tinh luyện hay gia tăng thêm trong cơ thể. Quy luật này tồn tại bất biến cho đến khi xuất hiện ngoại lệ duy nhất là Vương Lâm — do từng hấp thu lực thiên đạo nên hắn có thể tiếp tục hấp thu thêm hư hỏa, phá vỡ giới hạn cố hữu của tộc nhân. Bản chất và quy luật này được hé lộ rõ ràng tại @c1323.","thuocTinh":"Hỏa","nguonGoc":"Huyết mạch bẩm sinh Chu Tước tộc","dacDiem":"Vô hình, số lượng cố định từ khi sinh ra không thể tinh luyện thêm, thiêu đốt tâm tình thay vì thể xác; trường hợp Vương Lâm là ngoại lệ duy nhất từ cổ chí kim có thể hấp thu thêm hư hỏa nhờ lực thiên đạo.","congNang":["Thiêu đốt tâm tình của đối phương @c1323","Sát thương ngoại tộc","Mang lực lượng diệt thế @c1323"],"tabs":{"tienTrinh":[{"chuong":"@c1323","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ bản chất","text":"Chương lộ bản chất hư hỏa là ngọn lửa diệt thế số lượng cố định, đồng thời hư hỏa của Vương Lâm phá quy luật này nhờ hấp thu từ lực thiên đạo.","anchor":"Hư hỏa chính là ngọn lửa diệt thế của Chu Tước tộc"}]},"nguon":["@c1323"]},{"id":"hu-hoa-bien-di-vuong-lam","name":"Hư hỏa biến dị của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông cá nhân","phamCap":"Không rõ","hePhai":"Chu Tước tộc / Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Hư hỏa biến dị của Vương Lâm là dạng hư hỏa đặc biệt hình thành sau khi Chu Tước hư huyễn nhập vào mắt phải hắn, mang lực lượng diệt thế và có đặc tính vô hình vô sắc. Do chứa từ lực thiên đạo với lực hút vĩnh hằng, hư hỏa này phá vỡ quy luật cố định của Chu Tước tộc, cho phép Vương Lâm tiếp tục hấp thu thêm hư hỏa — ngoại lệ chưa từng có từ cổ chí kim.","detail":"Tại thời điểm Vương Lâm thu Chu Tước hư huyễn vào mắt phải (@c1323), cơ thể hắn bùng phát hư hỏa vô hình vô sắc mang lực lượng diệt thế. Hư hỏa này khác biệt căn bản so với hư hỏa thông thường của Chu Tước tộc: bên trong nó chứa từ lực thiên đạo tạo ra lực hút vĩnh hằng, nhờ đó Vương Lâm có thể tiếp tục hấp thu thêm hư hỏa thay vì bị giới hạn như mọi thành viên Chu Tước tộc khác. Đây là hiện tượng ngoại lệ mà ngay cả lão tổ đời thứ nhất của Chu Tước tộc cũng không thể lý giải, khiến Vương Lâm trở thành người đầu tiên từ cổ chí kim sở hữu khả năng này.","thuocTinh":"Hỏa / Từ lực thiên đạo","dacDiem":"Vô hình vô sắc, chứa từ lực thiên đạo với lực hút vĩnh hằng, cho phép hấp thu thêm hư hỏa không giới hạn — ngoại lệ chưa từng có trong lịch sử Chu Tước tộc.","congNang":["Mang lực lượng diệt thế (@c1323)","Có thể tiếp tục hấp thu thêm hư hỏa nhờ từ lực thiên đạo chứa lực hút vĩnh hằng (@c1323)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1323","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1323","loai":"xuat-hien","importance":"major","giaiDoan":"Hình thành","text":"Vương Lâm thu Chu Tước hư huyễn vào mắt phải, cơ thể bùng hư hỏa vô hình vô sắc mang lực lượng diệt thế, trở thành ngoại lệ từ cổ chí kim.","anchor":"Cũng trong nháy mắt này, cơ thể Vương Lâm ầm ầm tràn ngập hư hỏa"}]},"nguon":["@c1323"],"uyLuc":"Mang lực lượng diệt thế, phá vỡ quy luật cố định của Chu Tước tộc từ cổ chí kim."}]};
